"use client"

import * as React from 'react'
import { useState, useEffect } from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table"
import {
    MessageSquare,
    Plus,
    Edit,
    Trash2,
    ArrowLeft,
    Search,
    Filter,
    BookOpen
} from 'lucide-react'
import Link from 'next/link'

interface KnowledgeEntry {
    id: string
    domain: string
    topic: string
    content: string
    answer?: string
    difficulty: 'BEGINNER' | 'INTERMEDIATE' | 'ADVANCED'
    type?: 'TECHNICAL' | 'BEHAVIORAL' | 'HR' | 'CODING'
    codeSnippet?: string
    tags?: any
    createdAt: string
}

const SAMPLE_ENTRIES: KnowledgeEntry[] = [
    {
        id: '1',
        domain: 'IT',
        topic: 'JavaScript Closures',
        content: 'Explain what closures are in JavaScript and provide an example of their practical use.',
        answer: 'A closure is the combination of a function bundled together (enclosed) with references to its surrounding state (the lexical environment).',
        difficulty: 'INTERMEDIATE',
        type: 'TECHNICAL',
        createdAt: new Date().toISOString()
    }
]

export default function QuestionsPage() {
    const [entries, setEntries] = useState<KnowledgeEntry[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [isDialogOpen, setIsDialogOpen] = useState(false)
    const [editingEntry, setEditingEntry] = useState<KnowledgeEntry | null>(null)
    const [searchQuery, setSearchQuery] = useState('')
    const [filterDomain, setFilterDomain] = useState<string>('all')
    const [filterDifficulty, setFilterDifficulty] = useState<string>('all')

    const [formData, setFormData] = useState<{
        domain: string
        topic: string
        content: string
        answer: string
        difficulty: 'BEGINNER' | 'INTERMEDIATE' | 'ADVANCED'
        type: 'TECHNICAL' | 'BEHAVIORAL' | 'HR' | 'CODING'
        codeSnippet: string
        tags: string
    }>({
        domain: 'IT',
        topic: '',
        content: '',
        answer: '',
        difficulty: 'INTERMEDIATE',
        type: 'TECHNICAL',
        codeSnippet: '',
        tags: ''
    })

    useEffect(() => {
        fetchEntries()
    }, [filterDomain, filterDifficulty, searchQuery]) // Re-fetch when filters change (or use client-side filtering)

    const fetchEntries = async () => {
        try {
            setIsLoading(true)
            const { knowledgeBaseApi } = await import('@/lib/api')
            const res = await knowledgeBaseApi.getAll({
                domain: filterDomain !== 'all' ? filterDomain : undefined,
                difficulty: filterDifficulty !== 'all' ? filterDifficulty : undefined,
                search: searchQuery || undefined
            })
            setEntries(res.data.entries)
        } catch (error) {
            console.error('Failed to fetch entries:', error)
        } finally {
            setIsLoading(false)
        }
    }

    const [isGenerating, setIsGenerating] = useState(false)
    const [generatedQuestions, setGeneratedQuestions] = useState<any[]>([])
    const [isAiDialogOpen, setIsAiDialogOpen] = useState(false)
    const [aiParams, setAiParams] = useState({
        domain: 'IT',
        role: 'Frontend Developer',
        difficulty: 'INTERMEDIATE',
        count: 5,
        company: ''
    })

    const handleGenerate = async () => {
        setIsGenerating(true)
        try {
            const { knowledgeBaseApi } = await import('@/lib/api')
            const res = await knowledgeBaseApi.generate(aiParams)
            setGeneratedQuestions(res.data.questions)
        } catch (error) {
            console.error('Generation failed:', error)
            alert('Failed to generate questions')
        } finally {
            setIsGenerating(false)
        }
    }

    const saveGeneratedQuestion = async (q: any, index: number) => {
        try {
            const { knowledgeBaseApi } = await import('@/lib/api')
            await knowledgeBaseApi.create({
                domain: aiParams.domain,
                topic: q.topic,
                content: q.content,
                difficulty: aiParams.difficulty,
                answer: q.answer
            })
            // Remove from list
            setGeneratedQuestions(prev => prev.filter((_, i) => i !== index))
            fetchEntries()
        } catch (error) {
            console.error('Failed to save generated question:', error)
        }
    }

    const handleSubmit = async () => {
        try {
            const { knowledgeBaseApi } = await import('@/lib/api')
            if (editingEntry) {
                await knowledgeBaseApi.update(editingEntry.id, formData)
            } else {
                await knowledgeBaseApi.create(formData)
            }
            fetchEntries() // Refresh list
            setIsDialogOpen(false)
            setEditingEntry(null)
            setFormData({
                domain: 'IT',
                topic: '',
                content: '',
                answer: '',
                difficulty: 'INTERMEDIATE',
                type: 'TECHNICAL',
                codeSnippet: '',
                tags: ''
            })
        } catch (error) {
            console.error('Failed to save entry:', error)
            alert('Failed to save entry')
        }
    }

    const handleEdit = (entry: KnowledgeEntry) => {
        setEditingEntry(entry)
        setFormData({
            domain: entry.domain,
            topic: entry.topic,
            content: entry.content,
            answer: entry.answer || '',
            difficulty: entry.difficulty,
            type: entry.type || 'TECHNICAL',
            codeSnippet: entry.codeSnippet || '',
            tags: Array.isArray(entry.tags) ? entry.tags.join(', ') : ''
        })
        setIsDialogOpen(true)
    }

    const handleDelete = async (id: string) => {
        if (confirm('Are you sure you want to delete this Q&A entry?')) {
            try {
                const { knowledgeBaseApi } = await import('@/lib/api')
                await knowledgeBaseApi.delete(id)
                fetchEntries()
            } catch (error) {
                console.error('Failed to delete entry:', error)
            }
        }
    }

    // Client-side filtering is redundant if API handles it, but kept for speed if small dataset
    // We already fetch filtered data, so we can just use 'entries'
    const filteredEntries = entries;

    const getDifficultyColor = (difficulty: string) => {
        switch (difficulty) {
            case 'BEGINNER': return 'bg-green-100 text-green-800'
            case 'INTERMEDIATE': return 'bg-yellow-100 text-yellow-800'
            case 'ADVANCED': return 'bg-red-100 text-red-800'
            default: return 'bg-gray-100 text-gray-800'
        }
    }

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <Link href="/admin/ai-interviews">
                        <Button variant="ghost" size="icon">
                            <ArrowLeft className="h-4 w-4" />
                        </Button>
                    </Link>
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight">Q&A Training</h1>
                        <p className="text-muted-foreground">Train AI with domain-specific questions and knowledge.</p>
                    </div>
                </div>
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                        <Button onClick={() => {
                            setEditingEntry(null);
                            setFormData({
                                domain: 'IT',
                                topic: '',
                                content: '',
                                answer: '',
                                difficulty: 'INTERMEDIATE',
                                type: 'TECHNICAL',
                                codeSnippet: '',
                                tags: ''
                            })
                        }}>
                            <Plus className="mr-2 h-4 w-4" />
                            Add Q&A Entry
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-[525px]">
                        <DialogHeader>
                            <DialogTitle>{editingEntry ? 'Edit Q&A Entry' : 'Add New Q&A Entry'}</DialogTitle>
                            <DialogDescription>
                                Add knowledge to train the AI interviewer.
                            </DialogDescription>
                        </DialogHeader>
                        <div className="grid gap-4 py-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="grid gap-2">
                                    <Label htmlFor="domain">Domain</Label>
                                    <Select
                                        value={formData.domain}
                                        onValueChange={(value) => setFormData(f => ({ ...f, domain: value }))}
                                    >
                                        <SelectTrigger>
                                            <SelectValue placeholder="Select domain" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="IT">IT / Software</SelectItem>
                                            <SelectItem value="Finance">Finance</SelectItem>
                                            <SelectItem value="Marketing">Marketing</SelectItem>
                                            <SelectItem value="HR">HR / Behavioral</SelectItem>
                                            <SelectItem value="General">General</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="grid gap-2">
                                    <Label htmlFor="type">Question Type</Label>
                                    <Select
                                        value={formData.type}
                                        onValueChange={(value: any) => setFormData(f => ({ ...f, type: value }))}
                                    >
                                        <SelectTrigger>
                                            <SelectValue placeholder="Select type" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="TECHNICAL">Technical</SelectItem>
                                            <SelectItem value="BEHAVIORAL">Behavioral</SelectItem>
                                            <SelectItem value="HR">HR</SelectItem>
                                            <SelectItem value="CODING">Coding Challenge</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="grid gap-2">
                                    <Label htmlFor="difficulty">Difficulty</Label>
                                    <Select
                                        value={formData.difficulty}
                                        onValueChange={(value: 'BEGINNER' | 'INTERMEDIATE' | 'ADVANCED') => setFormData(f => ({ ...f, difficulty: value }))}
                                    >
                                        <SelectTrigger>
                                            <SelectValue placeholder="Select difficulty" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="BEGINNER">Beginner</SelectItem>
                                            <SelectItem value="INTERMEDIATE">Intermediate</SelectItem>
                                            <SelectItem value="ADVANCED">Advanced</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="grid gap-2">
                                    <Label htmlFor="topic">Topic</Label>
                                    <Input
                                        id="topic"
                                        value={formData.topic}
                                        onChange={(e) => setFormData(f => ({ ...f, topic: e.target.value }))}
                                        placeholder="e.g., JavaScript Closures"
                                    />
                                </div>
                            </div>

                            <div className="grid gap-2">
                                <Label htmlFor="content">Question / Content</Label>
                                <Textarea
                                    id="content"
                                    value={formData.content}
                                    onChange={(e) => setFormData(f => ({ ...f, content: e.target.value }))}
                                    placeholder="Enter the interview question..."
                                    rows={3}
                                />
                            </div>

                            {formData.type === 'CODING' && (
                                <div className="grid gap-2">
                                    <Label htmlFor="codeSnippet">Starting Code / Snippet</Label>
                                    <Textarea
                                        id="codeSnippet"
                                        value={formData.codeSnippet}
                                        onChange={(e) => setFormData(f => ({ ...f, codeSnippet: e.target.value }))}
                                        placeholder="function example() { ... }"
                                        className="font-mono text-sm"
                                        rows={4}
                                    />
                                </div>
                            )}

                            <div className="grid gap-2">
                                <Label htmlFor="answer">Ideal Answer / Key Points</Label>
                                <Textarea
                                    id="answer"
                                    value={formData.answer}
                                    onChange={(e) => setFormData(f => ({ ...f, answer: e.target.value }))}
                                    placeholder="Key points or full answer used for scoring..."
                                    rows={4}
                                />
                            </div>

                            <div className="grid gap-2">
                                <Label htmlFor="tags">Tags (Comma separated)</Label>
                                <Input
                                    id="tags"
                                    value={formData.tags}
                                    onChange={(e) => setFormData(f => ({ ...f, tags: e.target.value }))}
                                    placeholder="react, hooks, basics"
                                />
                            </div>
                        </div>
                        <DialogFooter>
                            <Button variant="outline" onClick={() => setIsDialogOpen(false)}>Cancel</Button>
                            <Button onClick={handleSubmit} disabled={!formData.topic || !formData.content}>
                                {editingEntry ? 'Update' : 'Add to Knowledge Base'}
                            </Button>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>

                {/* AI Generator Modal */}
                <Dialog open={isAiDialogOpen} onOpenChange={setIsAiDialogOpen}>
                    <DialogTrigger asChild>
                        <Button variant="outline" className="ml-2 gap-2 border-primary/20 bg-primary/5 hover:bg-primary/10">
                            <BookOpen className="h-4 w-4 text-purple-600" />
                            Generate with AI
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-[700px] max-h-[80vh] overflow-y-auto">
                        <DialogHeader>
                            <DialogTitle>AI Question Generator</DialogTitle>
                            <DialogDescription>
                                Auto-generate interview questions based on your criteria.
                            </DialogDescription>
                        </DialogHeader>

                        {!generatedQuestions.length ? (
                            <div className="grid gap-4 py-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label>Domain</Label>
                                        <Select value={aiParams.domain} onValueChange={v => setAiParams(p => ({ ...p, domain: v }))}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="IT">IT / Software</SelectItem>
                                                <SelectItem value="Finance">Finance</SelectItem>
                                                <SelectItem value="Marketing">Marketing</SelectItem>
                                                <SelectItem value="HR">HR</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Difficulty</Label>
                                        <Select value={aiParams.difficulty} onValueChange={v => setAiParams(p => ({ ...p, difficulty: v }))}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="BEGINNER">Beginner</SelectItem>
                                                <SelectItem value="INTERMEDIATE">Intermediate</SelectItem>
                                                <SelectItem value="ADVANCED">Advanced</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label>Role / Job Title</Label>
                                        <Input
                                            value={aiParams.role}
                                            onChange={e => setAiParams(p => ({ ...p, role: e.target.value }))}
                                            placeholder="e.g. Senior React Dev"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Company Context (Optional)</Label>
                                        <Input
                                            value={aiParams.company}
                                            onChange={e => setAiParams(p => ({ ...p, company: e.target.value }))}
                                            placeholder="e.g. Google, Startup"
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <Label>Number of Questions</Label>
                                    <Select value={String(aiParams.count)} onValueChange={v => setAiParams(p => ({ ...p, count: Number(v) }))}>
                                        <SelectTrigger><SelectValue /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="3">3 Questions</SelectItem>
                                            <SelectItem value="5">5 Questions</SelectItem>
                                            <SelectItem value="10">10 Questions</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <Button onClick={handleGenerate} disabled={isGenerating} className="w-full mt-4">
                                    {isGenerating ? <div className="animate-spin mr-2 h-4 w-4 border-2 border-white border-t-transparent rounded-full" /> : <BookOpen className="mr-2 h-4 w-4" />}
                                    Generate Questions
                                </Button>
                            </div>
                        ) : (
                            <div className="space-y-4">
                                <div className="flex justify-between items-center">
                                    <h3 className="font-semibold text-lg">{generatedQuestions.length} Questions Generated</h3>
                                    <Button variant="ghost" size="sm" onClick={() => setGeneratedQuestions([])}>Reset</Button>
                                </div>
                                <div className="space-y-4">
                                    {generatedQuestions.map((q, i) => (
                                        <Card key={i} className="bg-muted/30">
                                            <CardHeader className="pb-2">
                                                <div className="flex justify-between items-start">
                                                    <div>
                                                        <CardTitle className="text-base font-medium">{q.topic}</CardTitle>
                                                        <CardDescription className="text-xs mt-1">{aiParams.difficulty}</CardDescription>
                                                    </div>
                                                    <Button size="sm" onClick={() => saveGeneratedQuestion(q, i)}>Save</Button>
                                                </div>
                                            </CardHeader>
                                            <CardContent className="text-sm space-y-2">
                                                <p className="font-medium">{q.content}</p>
                                                <div className="bg-background p-2 rounded text-muted-foreground text-xs">
                                                    <span className="font-semibold text-primary">Ideal Answer: </span>
                                                    {q.answer}
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}
                                </div>
                            </div>
                        )}
                    </DialogContent>
                </Dialog>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium">Total Entries</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{entries.length}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium">Beginner</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-600">
                            {entries.filter(e => e.difficulty === 'BEGINNER').length}
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium">Intermediate</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-yellow-600">
                            {entries.filter(e => e.difficulty === 'INTERMEDIATE').length}
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium">Advanced</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-red-600">
                            {entries.filter(e => e.difficulty === 'ADVANCED').length}
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Filters */}
            <Card>
                <CardHeader className="pb-4">
                    <div className="flex flex-col md:flex-row gap-4">
                        <div className="relative flex-1">
                            <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Search topics or content..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="pl-10"
                            />
                        </div>
                        <Select value={filterDomain} onValueChange={setFilterDomain}>
                            <SelectTrigger className="w-[150px]">
                                <SelectValue placeholder="Domain" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">All Domains</SelectItem>
                                <SelectItem value="IT">IT / Software</SelectItem>
                                <SelectItem value="Finance">Finance</SelectItem>
                                <SelectItem value="Marketing">Marketing</SelectItem>
                                <SelectItem value="HR">HR</SelectItem>
                            </SelectContent>
                        </Select>
                        <Select value={filterDifficulty} onValueChange={setFilterDifficulty}>
                            <SelectTrigger className="w-[150px]">
                                <SelectValue placeholder="Difficulty" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">All Levels</SelectItem>
                                <SelectItem value="BEGINNER">Beginner</SelectItem>
                                <SelectItem value="INTERMEDIATE">Intermediate</SelectItem>
                                <SelectItem value="ADVANCED">Advanced</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                </CardHeader>
                <CardContent>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Topic</TableHead>
                                <TableHead>Domain</TableHead>
                                <TableHead>Difficulty</TableHead>
                                <TableHead className="max-w-[300px]">Content</TableHead>
                                <TableHead className="text-right">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {filteredEntries.map((entry) => (
                                <TableRow key={entry.id}>
                                    <TableCell className="font-medium">{entry.topic}</TableCell>
                                    <TableCell>{entry.domain}</TableCell>
                                    <TableCell>
                                        <span className={`px-2 py-1 rounded-full text-xs font-medium ${getDifficultyColor(entry.difficulty)}`}>
                                            {entry.difficulty}
                                        </span>
                                    </TableCell>
                                    <TableCell className="max-w-[300px] truncate">{entry.content}</TableCell>
                                    <TableCell className="text-right">
                                        <Button variant="ghost" size="icon" onClick={() => handleEdit(entry)}>
                                            <Edit className="h-4 w-4" />
                                        </Button>
                                        <Button variant="ghost" size="icon" onClick={() => handleDelete(entry.id)}>
                                            <Trash2 className="h-4 w-4 text-destructive" />
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))}
                            {filteredEntries.length === 0 && (
                                <TableRow>
                                    <TableCell colSpan={5} className="text-center py-8 text-muted-foreground">
                                        <BookOpen className="h-8 w-8 mx-auto mb-2 opacity-50" />
                                        No entries found. Add some Q&A to train the AI.
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useRouter } from 'next/navigation'
import api from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { GraduationCap, Loader2, Plus, BookOpen, Clock } from 'lucide-react'

interface Course {
    id: string
    title: string
    category: string
    isPublished: boolean
    difficulty: string
    price: number
    _count?: { enrollments: number; modules: number }
}

export default function AdminCoursesPage() {
    const router = useRouter()
    const [courses, setCourses] = React.useState<Course[]>([])
    const [isLoading, setIsLoading] = React.useState(true)

    React.useEffect(() => {
        const fetchCourses = async () => {
            try {
                const res = await api.get('/courses')
                setCourses(res.data.courses || [])
            } catch (error) {
                console.error(error)
            } finally {
                setIsLoading(false)
            }
        }
        fetchCourses()
    }, [])

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Courses</h1>
                    <p className="text-muted-foreground">Manage your curriculum and content.</p>
                </div>
                <Button onClick={() => router.push('/admin/courses/new')}>
                    <Plus className="h-4 w-4 mr-2" />
                    Create New Course
                </Button>
            </div>

            {isLoading ? (
                <div className="flex justify-center py-12">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {courses.map((course) => (
                        <Card key={course.id} className="hover:shadow-lg transition-all group overflow-hidden">
                            <div className="h-2 bg-primary/10 group-hover:bg-primary transition-colors" />
                            <CardContent className="p-6">
                                <div className="flex justify-between items-start mb-4">
                                    <Badge variant="outline" className="mb-2">
                                        {course.category}
                                    </Badge>
                                    <Badge className={course.isPublished ? "bg-green-100 text-green-700 hover:bg-green-100" : "bg-yellow-100 text-yellow-700 hover:bg-yellow-100"}>
                                        {course.isPublished ? 'Published' : 'Draft'}
                                    </Badge>
                                </div>
                                <h3 className="font-bold text-lg mb-2 line-clamp-2 min-h-[56px]">
                                    {course.title}
                                </h3>

                                <div className="grid grid-cols-2 gap-4 text-sm text-muted-foreground mb-6">
                                    <div className="flex items-center gap-1">
                                        <BookOpen className="h-3.5 w-3.5" />
                                        {course._count?.modules || 0} Modules
                                    </div>
                                    <div className="flex items-center gap-1">
                                        <Clock className="h-3.5 w-3.5" />
                                        {course.difficulty}
                                    </div>
                                </div>

                                <div className="flex items-center justify-between pt-4 border-t">
                                    <span className="font-bold text-lg">
                                        {course.price === 0 ? 'Free' : `₹${course.price}`}
                                    </span>
                                    <Button variant="secondary" size="sm" onClick={() => router.push(`/admin/courses/${course.id}/edit`)}>
                                        Manage
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}
        </div>
    )
}

"use client"

import * as React from 'react'
import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog"
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table"
import {
    Eye,
    CheckCircle,
    XCircle,
    Clock,
    Archive,
    Loader2,
    BookOpen,
    Video,
    Users
} from 'lucide-react'
import api from '@/lib/api'

interface PendingCourse {
    id: string
    title: string
    description: string
    category: string
    courseType: 'RECORDED' | 'LIVE' | 'HYBRID'
    difficulty: string
    publishStatus: 'DRAFT' | 'IN_REVIEW' | 'PUBLISHED' | 'ARCHIVED'
    submittedForReviewAt?: string
    instructorId: string
    price: number
    _count?: {
        modules: number
        enrollments: number
    }
}

export default function CourseReviewPage() {
    const router = useRouter()
    const [courses, setCourses] = useState<PendingCourse[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [selectedCourse, setSelectedCourse] = useState<PendingCourse | null>(null)
    const [isDialogOpen, setIsDialogOpen] = useState(false)
    const [reviewNotes, setReviewNotes] = useState('')
    const [isProcessing, setIsProcessing] = useState(false)
    const [filter, setFilter] = useState<'ALL' | 'IN_REVIEW' | 'DRAFT'>('IN_REVIEW')

    useEffect(() => {
        fetchCourses()
    }, [filter])

    const fetchCourses = async () => {
        setIsLoading(true)
        try {
            const res = await api.get('/admin/courses/pending', {
                params: { status: filter }
            })
            setCourses(res.data.courses || [])
        } catch (error) {
            console.error('Failed to fetch pending courses:', error)
            // Mock data for demo
            setCourses([
                {
                    id: '1',
                    title: 'Advanced React Patterns',
                    description: 'Learn advanced React patterns including compound components...',
                    category: 'Development',
                    courseType: 'RECORDED',
                    difficulty: 'ADVANCED',
                    publishStatus: 'IN_REVIEW',
                    submittedForReviewAt: new Date().toISOString(),
                    instructorId: 'inst1',
                    price: 2999,
                    _count: { modules: 8, enrollments: 0 }
                },
                {
                    id: '2',
                    title: 'Live Python Bootcamp',
                    description: 'Comprehensive Python course with live sessions...',
                    category: 'Development',
                    courseType: 'LIVE',
                    difficulty: 'BEGINNER',
                    publishStatus: 'IN_REVIEW',
                    submittedForReviewAt: new Date().toISOString(),
                    instructorId: 'inst2',
                    price: 4999,
                    _count: { modules: 12, enrollments: 0 }
                }
            ])
        } finally {
            setIsLoading(false)
        }
    }

    const handleApprove = async (course: PendingCourse) => {
        setIsProcessing(true)
        try {
            await api.patch(`/admin/courses/${course.id}/approve`, { notes: reviewNotes })
            setCourses(courses.filter(c => c.id !== course.id))
            setIsDialogOpen(false)
            setSelectedCourse(null)
            setReviewNotes('')
        } catch (error) {
            console.error('Failed to approve course:', error)
            alert('Failed to approve course')
        } finally {
            setIsProcessing(false)
        }
    }

    const handleReject = async (course: PendingCourse) => {
        if (!reviewNotes.trim()) {
            alert('Please provide rejection notes')
            return
        }
        setIsProcessing(true)
        try {
            await api.patch(`/admin/courses/${course.id}/reject`, { notes: reviewNotes })
            setCourses(courses.filter(c => c.id !== course.id))
            setIsDialogOpen(false)
            setSelectedCourse(null)
            setReviewNotes('')
        } catch (error) {
            console.error('Failed to reject course:', error)
            alert('Failed to reject course')
        } finally {
            setIsProcessing(false)
        }
    }

    const handleArchive = async (courseId: string) => {
        if (!confirm('Are you sure you want to archive this course?')) return
        try {
            await api.patch(`/admin/courses/${courseId}/archive`)
            fetchCourses()
        } catch (error) {
            console.error('Failed to archive course:', error)
        }
    }

    const getCourseTypeIcon = (type: string) => {
        switch (type) {
            case 'LIVE': return <Users className="h-4 w-4 text-green-600" />
            case 'HYBRID': return <Video className="h-4 w-4 text-orange-600" />
            default: return <BookOpen className="h-4 w-4 text-blue-600" />
        }
    }

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'IN_REVIEW':
                return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 border-yellow-300"><Clock className="h-3 w-3 mr-1" />In Review</Badge>
            case 'PUBLISHED':
                return <Badge variant="outline" className="bg-green-50 text-green-700 border-green-300"><CheckCircle className="h-3 w-3 mr-1" />Published</Badge>
            case 'ARCHIVED':
                return <Badge variant="outline" className="bg-gray-50 text-gray-700 border-gray-300"><Archive className="h-3 w-3 mr-1" />Archived</Badge>
            default:
                return <Badge variant="secondary">Draft</Badge>
        }
    }

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Course Review</h1>
                    <p className="text-muted-foreground">Review and approve courses submitted by instructors.</p>
                </div>
            </div>

            {/* Filters */}
            <div className="flex gap-2">
                {(['IN_REVIEW', 'DRAFT', 'ALL'] as const).map(status => (
                    <Button
                        key={status}
                        variant={filter === status ? 'default' : 'outline'}
                        size="sm"
                        onClick={() => setFilter(status)}
                    >
                        {status === 'IN_REVIEW' ? 'Pending Review' : status === 'ALL' ? 'All Courses' : 'Drafts'}
                    </Button>
                ))}
            </div>

            {/* Courses Table */}
            <Card>
                <CardContent className="pt-6">
                    {isLoading ? (
                        <div className="flex justify-center py-12">
                            <Loader2 className="h-8 w-8 animate-spin text-primary" />
                        </div>
                    ) : courses.length > 0 ? (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Course</TableHead>
                                    <TableHead>Type</TableHead>
                                    <TableHead>Category</TableHead>
                                    <TableHead>Modules</TableHead>
                                    <TableHead>Price</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead className="text-right">Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {courses.map(course => (
                                    <TableRow key={course.id}>
                                        <TableCell>
                                            <div>
                                                <div className="font-medium">{course.title}</div>
                                                <div className="text-xs text-muted-foreground max-w-xs truncate">{course.description}</div>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <div className="flex items-center gap-1">
                                                {getCourseTypeIcon(course.courseType)}
                                                <span className="text-sm">{course.courseType}</span>
                                            </div>
                                        </TableCell>
                                        <TableCell>{course.category}</TableCell>
                                        <TableCell>{course._count?.modules || 0}</TableCell>
                                        <TableCell>₹{course.price}</TableCell>
                                        <TableCell>{getStatusBadge(course.publishStatus)}</TableCell>
                                        <TableCell className="text-right">
                                            <div className="flex justify-end gap-2">
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    onClick={() => router.push(`/courses/${course.id}`)}
                                                >
                                                    <Eye className="h-4 w-4" />
                                                </Button>
                                                {course.publishStatus === 'IN_REVIEW' && (
                                                    <Button
                                                        size="sm"
                                                        onClick={() => {
                                                            setSelectedCourse(course)
                                                            setIsDialogOpen(true)
                                                        }}
                                                    >
                                                        Review
                                                    </Button>
                                                )}
                                                {course.publishStatus === 'PUBLISHED' && (
                                                    <Button
                                                        variant="outline"
                                                        size="sm"
                                                        onClick={() => handleArchive(course.id)}
                                                    >
                                                        <Archive className="h-4 w-4" />
                                                    </Button>
                                                )}
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    ) : (
                        <div className="text-center py-12 text-muted-foreground">
                            <CheckCircle className="h-12 w-12 mx-auto mb-4 opacity-20" />
                            <h3 className="text-lg font-medium">No courses pending review</h3>
                            <p>All courses have been reviewed.</p>
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Review Dialog */}
            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="sm:max-w-lg">
                    <DialogHeader>
                        <DialogTitle>Review Course</DialogTitle>
                        <DialogDescription>{selectedCourse?.title}</DialogDescription>
                    </DialogHeader>
                    {selectedCourse && (
                        <div className="space-y-4 py-4">
                            <div className="grid grid-cols-2 gap-4 text-sm">
                                <div>
                                    <span className="text-muted-foreground">Type:</span>
                                    <p className="font-medium">{selectedCourse.courseType}</p>
                                </div>
                                <div>
                                    <span className="text-muted-foreground">Difficulty:</span>
                                    <p className="font-medium">{selectedCourse.difficulty}</p>
                                </div>
                                <div>
                                    <span className="text-muted-foreground">Modules:</span>
                                    <p className="font-medium">{selectedCourse._count?.modules || 0}</p>
                                </div>
                                <div>
                                    <span className="text-muted-foreground">Price:</span>
                                    <p className="font-medium">₹{selectedCourse.price}</p>
                                </div>
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Review Notes</label>
                                <Textarea
                                    value={reviewNotes}
                                    onChange={e => setReviewNotes(e.target.value)}
                                    placeholder="Add notes for the instructor (required for rejection)"
                                    className="min-h-[100px]"
                                />
                            </div>
                        </div>
                    )}
                    <DialogFooter className="gap-2">
                        <Button
                            variant="destructive"
                            onClick={() => selectedCourse && handleReject(selectedCourse)}
                            disabled={isProcessing}
                        >
                            {isProcessing ? <Loader2 className="h-4 w-4 animate-spin" /> : <XCircle className="h-4 w-4 mr-2" />}
                            Reject
                        </Button>
                        <Button
                            onClick={() => selectedCourse && handleApprove(selectedCourse)}
                            disabled={isProcessing}
                        >
                            {isProcessing ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle className="h-4 w-4 mr-2" />}
                            Approve & Publish
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import * as React from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'

import {
    Mail,
    Server,
    Plus
} from 'lucide-react'
import api from '@/lib/api'

interface EmailConfig {
    id: string
    provider: string
    name: string
    isActive: boolean
    host?: string
    port?: number
    user?: string
    fromEmail?: string
    serviceId?: string
    templateId?: string
    publicKey?: string
}

export default function EmailSettingsPage() {
    const [configs, setConfigs] = React.useState<EmailConfig[]>([])
    const [isLoading, setIsLoading] = React.useState(true)
    const [showAddForm, setShowAddForm] = React.useState(false)
    const [testEmail, setTestEmail] = React.useState('')

    // Form State
    const [formData, setFormData] = React.useState({
        provider: 'EMAILJS',
        name: '',
        host: '',
        port: 587,
        user: '',
        pass: '',
        fromEmail: '',
        serviceId: '',
        templateId: '',
        publicKey: '',
        privateKey: ''
    })

    React.useEffect(() => {
        fetchConfigs()
    }, [])

    const fetchConfigs = async () => {
        try {
            const res = await api.get('/email-settings/config')
            setConfigs(res.data)
        } catch {
            // Error logged if needed
        } finally {
            setIsLoading(false)
        }
    }

    const handleSave = async () => {
        try {
            await api.post('/email-settings/config', formData)
            setShowAddForm(false)
            fetchConfigs()
            resetForm()
        } catch (error) {
            alert('Failed to save configuration')
        }
    }

    const handleActivate = async (id: string) => {
        try {
            await api.put(`/email-settings/config/${id}/activate`)
            fetchConfigs()
        } catch (error) {
            alert('Failed to activate')
        }
    }

    const handleTest = async (id: string) => {
        if (!testEmail) return alert('Please enter a test email address')
        try {
            const res = await api.post('/email-settings/test', { id, toEmail: testEmail })
            alert(res.data.message || 'Test email sent!')
        } catch (error) {
            const err = error as { response?: { data?: { details?: string } }, message: string }
            alert('Test Failed: ' + (err.response?.data?.details || err.message))
        }
    }

    const resetForm = () => {
        setFormData({
            provider: 'EMAILJS',
            name: '',
            host: '',
            port: 587,
            user: '',
            pass: '',
            fromEmail: '',
            serviceId: '',
            templateId: '',
            publicKey: '',
            privateKey: ''
        })
    }

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold flex items-center gap-2">
                    <Mail className="h-8 w-8 text-primary" />
                    Email Services
                </h1>
                <p className="text-muted-foreground">Configure transactional and marketing email providers.</p>
            </div>

            <div className="flex gap-4 items-center p-4 bg-muted/30 rounded-lg border">
                <Input
                    placeholder="Enter email to test..."
                    value={testEmail}
                    onChange={e => setTestEmail(e.target.value)}
                    className="max-w-xs bg-background"
                />
                <span className="text-sm text-muted-foreground">Use this email for &quot;Test Connection&quot; buttons below.</span>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* List of Configs */}
                <div className="space-y-4">
                    <div className="flex justify-between items-center">
                        <h2 className="text-xl font-semibold">Providers</h2>
                        <Button onClick={() => setShowAddForm(true)} size="sm">
                            <Plus className="h-4 w-4 mr-2" />
                            Add New
                        </Button>
                    </div>

                    {configs.map(config => (
                        <Card key={config.id} className={config.isActive ? 'border-primary shadow-sm' : ''}>
                            <CardHeader className="pb-2">
                                <CardTitle className="flex justify-between items-center text-lg">
                                    <span className="flex items-center gap-2">
                                        {config.provider === 'SMTP' ? <Server className="h-4 w-4" /> : <Mail className="h-4 w-4" />}
                                        {config.name || config.provider}
                                    </span>
                                    {config.isActive && <Badge>Active</Badge>}
                                </CardTitle>
                                <CardDescription>
                                    {config.provider === 'SMTP' ? `${config.host}:${config.port}` : `Service ID: ${config.serviceId}`}
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="flex gap-2 justify-end pt-0">
                                <Button variant="outline" size="sm" onClick={() => handleTest(config.id)}>Test</Button>
                                {!config.isActive && (
                                    <Button size="sm" onClick={() => handleActivate(config.id)}>Activate</Button>
                                )}
                            </CardContent>
                        </Card>
                    ))}

                    {configs.length === 0 && !showAddForm && (
                        <div className="text-center py-8 text-muted-foreground border-2 border-dashed rounded-lg">
                            No email providers configured.
                        </div>
                    )}
                </div>

                {/* Add/Edit Form */}
                {showAddForm && (
                    <Card className="border-t-4 border-t-primary">
                        <CardHeader>
                            <CardTitle>Add Email Provider</CardTitle>
                            <CardDescription>Configure SMTP or EmailJS Settings</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-2">
                                <Label>Provider Type</Label>
                                <select
                                    className="w-full h-10 px-3 rounded-md border bg-background"
                                    value={formData.provider}
                                    onChange={e => setFormData({ ...formData, provider: e.target.value })}
                                >
                                    <option value="EMAILJS">EmailJS (Frontend/API)</option>
                                    <option value="SMTP">SMTP (Standard)</option>
                                    <option value="SENDGRID">SendGrid</option>
                                </select>
                            </div>

                            <div className="space-y-2">
                                <Label>Display Name</Label>
                                <Input
                                    placeholder="e.g. Marketing EmailJS"
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                />
                            </div>

                            {formData.provider === 'SMTP' ? (
                                <>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label>Host</Label>
                                            <Input placeholder="smtp.gmail.com" value={formData.host} onChange={e => setFormData({ ...formData, host: e.target.value })} />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Port</Label>
                                            <Input type="number" placeholder="587" value={formData.port} onChange={e => setFormData({ ...formData, port: parseInt(e.target.value) })} />
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Username</Label>
                                        <Input value={formData.user} onChange={e => setFormData({ ...formData, user: e.target.value })} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Password</Label>
                                        <Input type="password" value={formData.pass} onChange={e => setFormData({ ...formData, pass: e.target.value })} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>From Email</Label>
                                        <Input placeholder="noreply@techwell.com" value={formData.fromEmail} onChange={e => setFormData({ ...formData, fromEmail: e.target.value })} />
                                    </div>
                                </>
                            ) : formData.provider === 'EMAILJS' ? (
                                <>
                                    <div className="space-y-2">
                                        <Label>Service ID</Label>
                                        <Input placeholder="service_xyz" value={formData.serviceId} onChange={e => setFormData({ ...formData, serviceId: e.target.value })} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Template ID</Label>
                                        <Input placeholder="template_abc" value={formData.templateId} onChange={e => setFormData({ ...formData, templateId: e.target.value })} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Public Key (User ID)</Label>
                                        <Input placeholder="user_123" value={formData.publicKey} onChange={e => setFormData({ ...formData, publicKey: e.target.value })} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Private Key</Label>
                                        <Input type="password" placeholder="Access Token for API" value={formData.privateKey} onChange={e => setFormData({ ...formData, privateKey: e.target.value })} />
                                        <p className="text-xs text-muted-foreground">Required for backend sending. Found in Account &gt; Security.</p>
                                    </div>
                                </>
                            ) : (
                                <div className="p-4 bg-muted text-center">Provider not fully supported in UI yet</div>
                            )}

                            <div className="flex gap-2 justify-end pt-4">
                                <Button variant="ghost" onClick={() => setShowAddForm(false)}>Cancel</Button>
                                <Button onClick={handleSave}>Save Configuration</Button>
                            </div>
                        </CardContent>
                    </Card>
                )}
            </div>
        </div>
    )
}

"use client"

import * as React from "react"
import { useState, useEffect } from "react"
import api from "@/lib/api"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Loader2, Check, X, Building2 } from "lucide-react"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"

interface EmployerRequest {
    id: string
    companyName: string
    status: string
    createdAt: string
    user: {
        name: string
        email: string
        phone: string
    }
}

export default function AdminEmployersPage() {
    const [requests, setRequests] = useState<EmployerRequest[]>([])
    const [isLoading, setIsLoading] = useState(true)

    useEffect(() => {
        fetchRequests()
    }, [])

    const fetchRequests = async () => {
        try {
            const res = await api.get('/employers/pending')
            setRequests(res.data)
        } catch {
            // Error handling
        } finally {
            setIsLoading(false)
        }
    }

    const handleStatusUpdate = async (id: string, status: 'APPROVED' | 'REJECTED') => {
        try {
            await api.put(`/employers/${id}/status`, { status })
            setRequests(prev => prev.filter(r => r.id !== id))
            alert(`Employer ${status.toLowerCase()} successfully`)
        } catch {
            alert('Failed to update status')
        }
    }

    if (isLoading) return <div className="flex justify-center p-8"><Loader2 className="animate-spin" /></div>

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">Employer Requests</h1>
                <p className="text-muted-foreground">Approve or reject company registration requests.</p>
            </div>

            {requests.length === 0 ? (
                <Card className="p-8 text-center text-muted-foreground">
                    <Building2 className="mx-auto h-12 w-12 mb-4 opacity-50" />
                    <p>No pending employer requests.</p>
                </Card>
            ) : (
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {requests.map((req) => (
                        <Card key={req.id}>
                            <CardHeader className="pb-3">
                                <div className="flex justify-between items-start">
                                    <Avatar className="h-10 w-10 border">
                                        <AvatarFallback><Building2 className="h-5 w-5" /></AvatarFallback>
                                    </Avatar>
                                    <Badge variant="outline">{req.status}</Badge>
                                </div>
                                <CardTitle className="mt-4">{req.companyName}</CardTitle>
                                <CardDescription>Registered {new Date(req.createdAt).toLocaleDateString()}</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="text-sm space-y-1">
                                    <p><span className="font-medium">User:</span> {req.user.name}</p>
                                    <p><span className="font-medium">Email:</span> {req.user.email}</p>
                                    <p><span className="font-medium">Phone:</span> {req.user.phone || 'N/A'}</p>
                                </div>
                                <div className="flex gap-2 pt-2">
                                    <Button
                                        className="w-full bg-green-600 hover:bg-green-700"
                                        size="sm"
                                        onClick={() => handleStatusUpdate(req.id, 'APPROVED')}
                                    >
                                        <Check className="mr-2 h-4 w-4" /> Approve
                                    </Button>
                                    <Button
                                        className="w-full"
                                        variant="destructive"
                                        size="sm"
                                        onClick={() => handleStatusUpdate(req.id, 'REJECTED')}
                                    >
                                        <X className="mr-2 h-4 w-4" /> Reject
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}
        </div>
    )
}

"use client"

import * as React from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
