"use client"

import * as React from 'react'
import { useRouter, useParams } from 'next/navigation'
import { courseApi, paymentApi } from '@/lib/api'
import { useAuth } from '@/lib/auth-context'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import {
    GraduationCap,
    Clock,
    Users,
    Star,
    CheckCircle2,
    PlayCircle,
    BookOpen,
    Loader2,
    ArrowLeft,
    CreditCard
} from 'lucide-react'

interface RazorpayResponse {
    razorpay_payment_id: string
    razorpay_order_id: string
    razorpay_signature: string
}

interface RazorpayOptions {
    key: string
    amount: number
    currency: string
    name: string
    description: string
    order_id: string
    handler: (response: RazorpayResponse) => Promise<void>
    prefill: {
        name?: string
        email?: string
    }
    theme: {
        color: string
    }
    modal: {
        ondismiss: () => void
    }
}

declare global {
    interface Window {
        Razorpay: new (options: RazorpayOptions) => {
            open: () => void
            on: (event: string, handler: (response: { error?: Record<string, unknown> } & Record<string, unknown>) => void) => void
        }
    }
}

interface Module {
    id: string
    title: string
    description: string
    orderIndex: number
    lessons: { id: string; title: string; duration: number }[]
}

interface Course {
    id: string
    title: string
    description: string
    category: string
    difficulty: string
    duration: number
    price: number
    thumbnail?: string
    instructor?: { name: string; email: string }
    modules: Module[]
    start?: string
    bundlePrice?: number
    hasInterviewPrep?: boolean
    _count?: { enrollments: number }
    isEnrolled?: boolean
    discountPrice?: number
    courseCode?: string
    jobRoles?: string[]
    bannerUrl?: string
}

const loadRazorpay = () => {
    return new Promise<boolean>((resolve) => {
        const script = document.createElement('script');
        script.src = 'https://checkout.razorpay.com/v1/checkout.js';
        script.onload = () => resolve(true);
        script.onerror = () => resolve(false);
        document.body.appendChild(script);
    });
};

export default function CourseDetailClient() {
    const router = useRouter()
    const params = useParams()
    const { isAuthenticated, user } = useAuth()

    const [course, setCourse] = React.useState<Course | null>(null)
    const [isLoading, setIsLoading] = React.useState(true)
    const [isEnrolling, setIsEnrolling] = React.useState(false)
    const [expandedModules, setExpandedModules] = React.useState<string[]>([])
    const [purchaseType, setPurchaseType] = React.useState<'COURSE_ONLY' | 'BUNDLE'>('COURSE_ONLY');

    React.useEffect(() => {
        const fetchCourse = async () => {
            try {
                const response = await courseApi.getById(params.id as string)
                setCourse(response.data.course)
            } catch (error) {
                console.error('Failed to fetch course:', error)
            } finally {
                setIsLoading(false)
            }
        }

        if (params.id) {
            fetchCourse()
        }
    }, [params.id])

    const handleBuy = async () => {
        if (!isAuthenticated) {
            router.push('/login')
            return
        }

        setIsEnrolling(true)
        try {
            // 1. Create Order with Type
            const { data: order } = await paymentApi.createOrder(course!.id, purchaseType)

            // Simulating "Dummy Payment" flow explicitly for User Request
            if (process.env.NODE_ENV === 'development' || order.status === 'created') {
                // In a real app, 'created' is standard. 
            }

            // Load Script
            const res = await loadRazorpay();
            if (!res) throw new Error('Razorpay SDK failed to load');

            const options = {
                key: 'rzp_test_dummy12345', // This should match backend key if real
                amount: order.amount,
                currency: order.currency,
                name: 'TechWell',
                description: purchaseType === 'BUNDLE' ? `Course + Interview Bundle` : `Enrollment for ${course!.title}`,
                order_id: order.id,
                handler: async function (response: RazorpayResponse) {
                    try {
                        await paymentApi.verifyPayment({
                            orderId: order.id,
                            paymentId: response.razorpay_payment_id,
                            signature: response.razorpay_signature
                        })
                        alert('Payment Successful! You are now enrolled.')
                        setCourse({ ...course!, isEnrolled: true })
                    } catch (err) {
                        alert('Payment verification failed')
                    }
                },
                prefill: {
                    name: user?.name,
                    email: user?.email,
                },
                theme: {
                    color: '#0f172a'
                },
                // Handle modal close
                modal: {
                    ondismiss: function () {
                        setIsEnrolling(false)
                    }
                }
            };

            try {
                const rzp = new window.Razorpay(options);
                rzp.open();

                rzp.on('payment.failed', function (_response: { error?: Record<string, unknown> } & Record<string, unknown>) {
                    alert("Payment Failed");
                    setIsEnrolling(false);
                });
            } catch (e) {
                // Determine if we should mock success
                console.warn("Razorpay SDK Error (likely dummy key). Simulating success...");
                await paymentApi.verifyPayment({
                    orderId: order.id,
                    paymentId: 'pay_mock_bypass',
                    signature: 'dummy_sig'
                });
                alert('Mock Payment Successful! (Dummy Mode)');
                setCourse({ ...course!, isEnrolled: true });
                setIsEnrolling(false);
            }

        } catch (error) {
            console.error('Failed to enroll:', error)
            // Fallback for mock environment if strictly needed
            if (error instanceof Error && error.message.includes('SDK')) {
                alert('SDK Error');
            }
            setIsEnrolling(false)
        }
    }

    const toggleModule = (moduleId: string) => {
        setExpandedModules(prev =>
            prev.includes(moduleId)
                ? prev.filter(id => id !== moduleId)
                : [...prev, moduleId]
        )
    }

    const getDifficultyColor = (diff: string) => {
        switch (diff) {
            case 'BEGINNER': return 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400'
            case 'INTERMEDIATE': return 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400'
            case 'ADVANCED': return 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
            default: return 'bg-gray-100 text-gray-700'
        }
    }

    if (isLoading) {
        return (
            <div className="min-h-[calc(100vh-4rem)] flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    if (!course) {
        return (
            <div className="container py-8 text-center">
                <h1 className="text-2xl font-bold mb-4">Course not found</h1>
                <Button onClick={() => router.push('/courses')}>
                    <ArrowLeft className="mr-2 h-4 w-4" />
                    Back to Courses
                </Button>
            </div>
        )
    }

    const currentPrice = purchaseType === 'BUNDLE'

        ? Number(course.bundlePrice || course.price * 1.2)
        : course.price;

    return (
        <div className="container py-8">
            {/* Back Button */}
            <Button variant="ghost" className="mb-6" onClick={() => router.push('/courses')}>
                <ArrowLeft className="mr-2 h-4 w-4" />
                Back to Courses
            </Button>

            {/* Banner Image */}
            {course.bannerUrl && (
                <div className="mb-8 rounded-xl overflow-hidden h-[300px] relative">
                    <img src={course.bannerUrl} alt={course.title} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Main Content */}
                <div className="lg:col-span-2">
                    {/* Header */}
                    <div className="mb-8">
                        <div className="flex items-center gap-3 mb-4 flex-wrap">
                            {course.courseCode && (
                                <span className="bg-primary/10 text-primary px-2 py-1 rounded text-xs font-mono border border-primary/20">
                                    {course.courseCode}
                                </span>
                            )}
                            <span className={`text-xs px-3 py-1 rounded-full ${getDifficultyColor(course.difficulty)}`}>
                                {course.difficulty}
                            </span>
                            <span className="text-sm text-muted-foreground">{course.category}</span>

                            {course.hasInterviewPrep && (
                                <span className="text-xs px-3 py-1 rounded-full bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400 flex items-center gap-1">
                                    <Star className="h-3 w-3" />
                                    Interview Prep Available
                                </span>
                            )}
                        </div>
                        <h1 className="text-3xl font-bold mb-4">{course.title}</h1>
                        <p className="text-lg text-muted-foreground mb-6">{course.description}</p>

                        <div className="flex items-center gap-6 text-sm text-muted-foreground">
                            <div className="flex items-center gap-2">
                                <Clock className="h-4 w-4" />
                                {course.duration} hours
                            </div>
                            <div className="flex items-center gap-2">
                                <Users className="h-4 w-4" />
                                {course._count?.enrollments || 0} students
                            </div>
                            <div className="flex items-center gap-2">
                                <Star className="h-4 w-4 text-yellow-500" />
                                4.8 rating
                            </div>
                            <div className="flex items-center gap-2">
                                <BookOpen className="h-4 w-4" />
                                {course.modules?.length || 0} modules
                            </div>
                        </div>
                        {course.jobRoles && course.jobRoles.length > 0 && (
                            <div className="mt-6 p-4 bg-muted/30 rounded-lg">
                                <h4 className="font-semibold text-sm mb-2">Target Job Roles:</h4>
                                <div className="flex flex-wrap gap-2">
                                    {course.jobRoles.map((role, i) => (
                                        <div key={i} className="flex items-center gap-1.5 bg-background border px-3 py-1.5 rounded-full text-xs font-medium">
                                            <CheckCircle2 className="h-3.5 w-3.5 text-green-500" />
                                            {role}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Course Curriculum */}
                    <Card>
                        <CardHeader>
                            <CardTitle>Course Curriculum</CardTitle>
                            <CardDescription>
                                {course.modules?.reduce((acc, m) => acc + (m.lessons?.length || 0), 0) || 0} lessons
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            {course.modules && course.modules.length > 0 ? (
                                <div className="space-y-4">
                                    {course.modules.map((module) => (
                                        <div key={module.id} className="border rounded-lg">
                                            <button
                                                onClick={() => toggleModule(module.id)}
                                                className="w-full flex items-center justify-between p-4 hover:bg-muted/50 transition-colors"
                                            >
                                                <div className="flex items-center gap-3">
                                                    <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center text-sm font-medium">
                                                        {module.orderIndex + 1}
                                                    </div>
                                                    <div className="text-left">
                                                        <h4 className="font-medium">{module.title}</h4>
                                                        <p className="text-sm text-muted-foreground">
                                                            {module.lessons?.length || 0} lessons
                                                        </p>
                                                    </div>
                                                </div>
                                                <span className="text-muted-foreground">
                                                    {expandedModules.includes(module.id) ? '−' : '+'}
                                                </span>
                                            </button>
                                            {expandedModules.includes(module.id) && module.lessons && (
                                                <div className="border-t px-4 py-2">
                                                    {module.lessons.map((lesson, idx) => (
                                                        <div key={lesson.id} className="flex items-center justify-between py-2 text-sm">
                                                            <div className="flex items-center gap-3">
                                                                <PlayCircle className="h-4 w-4 text-muted-foreground" />
                                                                <span>{lesson.title}</span>
                                                            </div>
                                                            <span className="text-muted-foreground">{lesson.duration}m</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p className="text-muted-foreground text-center py-8">
                                    Curriculum coming soon
                                </p>
                            )}
                        </CardContent>
                    </Card>
                </div>

                {/* Sidebar */}
                <div className="lg:col-span-1">
                    <Card className="sticky top-24">
                        <div className="h-40 bg-gradient-to-br from-primary/20 to-purple-500/20 rounded-t-lg flex items-center justify-center">
                            <GraduationCap className="h-16 w-16 text-primary/50" />
                        </div>
                        <CardContent className="pt-4">
                            {/* Pricing Toggle */}

                            {course.hasInterviewPrep && !course.isEnrolled && (
                                <div className="mb-6 p-4 bg-muted/50 rounded-lg space-y-3">
                                    <div
                                        className={`flex items-center justify-between p-3 rounded border cursor-pointer ${purchaseType === 'COURSE_ONLY' ? 'border-primary bg-primary/5' : 'border-border'}`}
                                        onClick={() => setPurchaseType('COURSE_ONLY')}
                                    >
                                        <div className="flex items-center gap-2">
                                            <div className={`h-4 w-4 rounded-full border flex items-center justify-center ${purchaseType === 'COURSE_ONLY' ? 'border-primary' : 'border-muted-foreground'}`}>
                                                {purchaseType === 'COURSE_ONLY' && <div className="h-2 w-2 rounded-full bg-primary" />}
                                            </div>
                                            <span className="font-medium">Course Only</span>
                                        </div>
                                        <span className="font-bold">₹{course.price}</span>
                                    </div>

                                    <div
                                        className={`flex items-center justify-between p-3 rounded border cursor-pointer ${purchaseType === 'BUNDLE' ? 'border-purple-500 bg-purple-50' : 'border-border'}`}
                                        onClick={() => setPurchaseType('BUNDLE')}
                                    >
                                        <div className="flex items-center gap-2">
                                            <div className={`h-4 w-4 rounded-full border flex items-center justify-center ${purchaseType === 'BUNDLE' ? 'border-purple-500' : 'border-muted-foreground'}`}>
                                                {purchaseType === 'BUNDLE' && <div className="h-2 w-2 rounded-full bg-purple-500" />}
                                            </div>
                                            <div>
                                                <span className="font-medium block">Complete Bundle</span>
                                                <span className="text-xs text-green-600 font-medium">Includes AI Interview Prep</span>
                                            </div>
                                        </div>

                                        <span className="font-bold text-purple-700">₹{course.bundlePrice || course.price * 1.2}</span>
                                    </div>
                                </div>
                            )}

                            <div className="text-3xl font-bold mb-4">
                                {course.discountPrice && course.discountPrice > 0 ? (
                                    <>
                                        ₹{purchaseType === 'BUNDLE' ? Number(course.bundlePrice || course.price * 1.2) : course.discountPrice}
                                        <span className="text-sm font-normal text-muted-foreground ml-2 line-through">
                                            ₹{purchaseType === 'BUNDLE' ? Number(course.price) * 1.5 : course.price}
                                        </span>
                                    </>
                                ) : (
                                    <>
                                        {currentPrice === 0 ? 'Free' : `₹${currentPrice}`}
                                        {purchaseType === 'BUNDLE' && <span className="text-sm font-normal text-muted-foreground ml-2 line-through">₹{Number(course.price) * 1.5}</span>}
                                    </>
                                )}
                            </div>

                            {course.isEnrolled ? (
                                <Button
                                    className="w-full mb-4 shadow-lg shadow-primary/25"
                                    size="lg"
                                    onClick={() => router.push(`/courses/${course.id}/learn`)}
                                >
                                    <PlayCircle className="mr-2 h-5 w-5" />
                                    Start Learning
                                </Button>
                            ) : (
                                <Button
                                    className={`w-full mb-4 ${purchaseType === 'BUNDLE' ? 'bg-purple-600 hover:bg-purple-700' : ''}`}
                                    size="lg"
                                    onClick={handleBuy}
                                    disabled={isEnrolling}
                                >
                                    {isEnrolling ? (
                                        <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                                    ) : (
                                        <CreditCard className="mr-2 h-5 w-5" />
                                    )}
                                    {isEnrolling ? 'Processing...' : (currentPrice === 0 ? 'Enroll for Free' : `Buy ${purchaseType === 'BUNDLE' ? 'Bundle' : 'Now'}`)}
                                </Button>
                            )}

                            <div className="space-y-3 text-sm">
                                <div className="flex items-center gap-2">
                                    <CheckCircle2 className="h-4 w-4 text-green-500" />
                                    <span>Full lifetime access</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    <CheckCircle2 className="h-4 w-4 text-green-500" />
                                    <span>Certificate of completion</span>
                                </div>
                                {purchaseType === 'BUNDLE' && (
                                    <div className="flex items-center gap-2 font-medium text-purple-700">
                                        <Star className="h-4 w-4" />
                                        <span>Unlimited AI Mock Interviews</span>
                                    </div>
                                )}
                            </div>


                            {course.instructor && (
                                <div className="mt-6 pt-6 border-t">
                                    <h4 className="font-medium mb-2">Instructor</h4>
                                    <div className="flex items-center gap-3">
                                        <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center">
                                            <Users className="h-5 w-5 text-primary" />
                                        </div>
                                        <div>
                                            <p className="font-medium">{course.instructor.name}</p>
                                            <p className="text-xs text-muted-foreground">{course.instructor.email}</p>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useRouter, useParams } from 'next/navigation'
import api from '@/lib/api'
import { Button } from '@/components/ui/button'
import { Progress } from '@/components/ui/progress'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Badge } from '@/components/ui/badge'
import {
    Loader2,
    PlayCircle,
    CheckCircle2,
    Lock,
    Menu,
    ChevronLeft,
    FileText,
    Award
} from 'lucide-react'
import { cn } from '@/lib/utils'

interface Lesson {
    id: string
    title: string
    duration: number
    content?: string
    videoUrl?: string
    order: number
    progress: { isCompleted: boolean }[]
}

interface Module {
    id: string
    title: string
    orderIndex: number
    lessons: Lesson[]
}

interface Course {
    id: string
    title: string
    modules: Module[]
}

export default function CourseLearnPage() {
    const params = useParams()
    const router = useRouter()

    // Expanded Interfaces
    interface QuizOption {
        optionText: string
        isCorrect: boolean
    }
    interface QuizQuestion {
        id: string
        question: string
        options: string[] | any // Simplified for now
        correctAnswer: string
    }
    interface Lesson {
        id: string
        title: string
        type: 'VIDEO' | 'TEXT' | 'QUIZ' | 'ASSIGNMENT' | 'PDF'
        duration: number
        content?: string
        videoUrl?: string
        order: number
        isLocked: boolean
        isCompleted: boolean
        lastScore?: number
        quizzes?: QuizQuestion[]
        settings?: any
    }
    interface Module {
        id: string
        title: string
        description: string
        orderIndex: number
        lessons: Lesson[]
    }
    interface Course {
        id: string
        title: string
        modules: Module[]
        userProgress: number
    }

    const [course, setCourse] = React.useState<Course | null>(null)
    const [activeLesson, setActiveLesson] = React.useState<Lesson | null>(null)
    const [isLoading, setIsLoading] = React.useState(true)
    const [sidebarOpen, setSidebarOpen] = React.useState(true)

    // Quiz State
    const [quizAnswers, setQuizAnswers] = React.useState<Record<string, string>>({})
    const [quizSubmitted, setQuizSubmitted] = React.useState(false)
    const [quizScore, setQuizScore] = React.useState(0)

    React.useEffect(() => {
        const fetchContent = async () => {
            try {
                // Use the new LMS route
                // @ts-ignore
                const res = await api.get(`/courses/${params.id}/learn`)
                if (res.data.course) {
                    setCourse(res.data.course)

                    // Intelligent Resume: Find first unlocked and incomplete lesson
                    const modules = res.data.course.modules as Module[]
                    let resumeLesson = null

                    for (const mod of modules) {
                        for (const lesson of mod.lessons) {
                            if (!lesson.isCompleted && !lesson.isLocked) {
                                resumeLesson = lesson
                                break
                            }
                        }
                        if (resumeLesson) break
                    }

                    // Fallback to first lesson
                    if (!resumeLesson && modules.length > 0 && modules[0].lessons.length > 0) {
                        resumeLesson = modules[0].lessons[0]
                    }

                    setActiveLesson(resumeLesson)
                }
            } catch (error) {
                console.error("Failed to load course content", error)
            } finally {
                setIsLoading(false)
            }
        }
        fetchContent()
    }, [params.id, router])

    const handleLessonComplete = async (lessonId: string, score?: number) => {
        try {
            // Optimistic Update
            setCourse(prev => {
                if (!prev) return null
                const newModules = prev.modules.map(m => ({
                    ...m,
                    lessons: m.lessons.map(l => l.id === lessonId ? { ...l, isCompleted: true } : l)
                }))
                // Re-calculate locks locally (simplified) or fetch
                return { ...prev, modules: newModules }
            })

            // Call API
            await api.post(`/courses/${course?.id}/lessons/${lessonId}/complete`, {
                timeSpent: 100, // Mock time
                score
            })

            // Re-fetch to sync locks and progress
            const res = await api.get(`/courses/${params.id}/learn`)
            if (res.data.course) {
                setCourse(res.data.course)
                // Auto-advance logic could go here
            }

        } catch (error) {
            console.error("Failed to mark complete", error)
        }
    }

    const handleQuizSubmit = () => {
        if (!activeLesson || !activeLesson.quizzes) return

        let correct = 0
        activeLesson.quizzes.forEach(q => {
            if (quizAnswers[q.id] === q.correctAnswer) correct++
        })

        const score = Math.round((correct / activeLesson.quizzes.length) * 100)
        setQuizScore(score)
        setQuizSubmitted(true)

        // Pass if score > passing (default 60)
        const passing = activeLesson.settings?.passingScore || 60
        if (score >= passing) {
            handleLessonComplete(activeLesson.id, score)
        }
    }

    if (isLoading) {
        return (
            <div className="h-screen flex items-center justify-center bg-background">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    if (!course) return null

    return (
        <div className="flex h-screen bg-background overflow-hidden font-sans">
            {/* Sidebar */}
            <div className={cn(
                "w-80 border-r bg-card flex flex-col transition-all duration-300 absolute inset-y-0 left-0 z-20 md:relative",
                !sidebarOpen && "-translate-x-full md:w-0 md:translate-x-0 md:overflow-hidden md:border-none"
            )}>
                <div className="p-4 border-b flex items-center justify-between h-14">
                    <h2 className="font-bold truncate text-sm">{course.title}</h2>
                    <Button variant="ghost" size="icon" onClick={() => setSidebarOpen(false)} className="md:hidden">
                        <ChevronLeft className="h-4 w-4" />
                    </Button>
                </div>

                <div className="p-4 border-b bg-muted/20">
                    <div className="flex justify-between text-xs mb-2">
                        <span>Course Progress</span>
                        <span className="font-medium">{course.userProgress}%</span>
                    </div>
                    <Progress value={course.userProgress} className="h-1.5" />
                </div>

                <ScrollArea className="flex-1">
                    <div className="p-4 space-y-6">
                        {course.modules.map((module) => (
                            <div key={module.id}>
                                <h3 className="text-[11px] font-bold text-muted-foreground uppercase tracking-wider mb-3 pl-1">
                                    {module.title}
                                </h3>
                                <div className="space-y-1">
                                    {module.lessons.map((lesson) => {
                                        const isActive = activeLesson?.id === lesson.id
                                        const isLocked = lesson.isLocked

                                        return (
                                            <button
                                                key={lesson.id}
                                                disabled={isLocked}
                                                onClick={() => {
                                                    setActiveLesson(lesson)
                                                    // Reset quiz state on change
                                                    setQuizAnswers({})
                                                    setQuizSubmitted(false)
                                                }}
                                                className={cn(
                                                    "w-full flex items-center gap-3 p-2.5 rounded-md text-sm transition-all text-left group relative",
                                                    isActive ? "bg-primary/10 text-primary font-medium" : "hover:bg-muted text-foreground/80",
                                                    isLocked && "opacity-50 cursor-not-allowed hover:bg-transparent"
                                                )}
                                            >
                                                {/* Status Icon */}
                                                <div className="shrink-0">
                                                    {lesson.isCompleted ? (
                                                        <CheckCircle2 className="h-4 w-4 text-green-600" />
                                                    ) : isLocked ? (
                                                        <Lock className="h-3.5 w-3.5 text-muted-foreground" />
                                                    ) : (
                                                        <div className={cn(
                                                            "h-4 w-4 rounded-full border-2 flex items-center justify-center",
                                                            isActive ? "border-primary" : "border-muted-foreground/30"
                                                        )}>
                                                            {isActive && <div className="h-1.5 w-1.5 rounded-full bg-primary" />}
                                                        </div>
                                                    )}
                                                </div>

                                                <div className="flex-1 min-w-0">
                                                    <div className="truncate text-xs md:text-sm">{lesson.title}</div>
                                                    <div className="flex items-center gap-2 text-[10px] text-muted-foreground mt-0.5">
                                                        <span>{Math.round(lesson.duration / 60)}m</span>
                                                        <span className="uppercase border px-1 rounded">{lesson.type}</span>
                                                    </div>
                                                </div>
                                            </button>
                                        )
                                    })}
                                </div>
                            </div>
                        ))}
                    </div>
                </ScrollArea>
            </div>

            {/* Main Content */}
            <div className="flex-1 flex flex-col min-w-0 bg-secondary/10">
                <header className="h-14 border-b flex items-center px-4 gap-4 bg-background sticky top-0 z-10 w-full justify-between">
                    <div className="flex items-center gap-4">
                        <Button variant="ghost" size="icon" onClick={() => setSidebarOpen(!sidebarOpen)}>
                            <Menu className="h-4 w-4" />
                        </Button>
                        <h1 className="text-sm font-semibold hidden md:block">{activeLesson?.title}</h1>
                    </div>

                    <Button variant="outline" size="sm" onClick={() => router.push('/dashboard')}>
                        Exit Class
                    </Button>
                </header>

                <ScrollArea className="flex-1">
                    <div className="max-w-4xl mx-auto p-4 md:p-8 pb-20">
                        {activeLesson ? (
                            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                {/* Type-Based Content Rendering */}
                                {activeLesson.type === 'VIDEO' && (
                                    <div className="aspect-video bg-black rounded-lg overflow-hidden shadow-2xl ring-1 ring-border">
                                        {activeLesson.videoUrl ? (
                                            <iframe
                                                title={activeLesson.title}
                                                src={activeLesson.videoUrl.replace('watch?v=', 'embed/')} // Simple generic replace
                                                className="w-full h-full"
                                                allowFullScreen
                                                allow="accelerometer; autoplay; encrypted-media; gyroscope; picture-in-picture"
                                            />
                                        ) : (
                                            <div className="h-full flex items-center justify-center text-muted-foreground">
                                                No Video Source
                                            </div>
                                        )}
                                    </div>
                                )}

                                {activeLesson.type === 'QUIZ' && (
                                    <div className="border rounded-xl bg-card p-6 shadow-sm">
                                        <div className="flex items-center justify-between mb-6">
                                            <h2 className="text-xl font-bold">Concept Check Quiz</h2>
                                            <Badge
                                                variant={quizSubmitted ? (quizScore >= 60 ? "default" : "destructive") : "secondary"}
                                                className={quizSubmitted && quizScore >= 60 ? "bg-green-600 hover:bg-green-700" : ""}
                                            >
                                                {quizSubmitted ? `Score: ${quizScore}%` : `${activeLesson.quizzes?.length || 0} Questions`}
                                            </Badge>
                                        </div>

                                        {!quizSubmitted ? (
                                            <div className="space-y-6">
                                                {activeLesson.quizzes?.map((q, idx) => (
                                                    <div key={q.id} className="space-y-3">
                                                        <p className="font-medium text-sm">{idx + 1}. {q.question}</p>
                                                        <div className="space-y-2 pl-4">
                                                            {/* Assuming options is an array of strings for V1 */}
                                                            {Array.isArray(q.options) && q.options.map((opt: string, oIdx: number) => (
                                                                <label key={oIdx} className="flex items-center gap-3 p-3 border rounded-lg cursor-pointer hover:bg-muted/50 transition-colors">
                                                                    <input
                                                                        type="radio"
                                                                        name={q.id}
                                                                        value={opt}
                                                                        checked={quizAnswers[q.id] === opt}
                                                                        onChange={() => setQuizAnswers(prev => ({ ...prev, [q.id]: opt }))}
                                                                        className="w-4 h-4 accent-primary"
                                                                    />
                                                                    <span className="text-sm">{opt}</span>
                                                                </label>
                                                            ))}
                                                        </div>
                                                    </div>
                                                ))}
                                                <Button onClick={handleQuizSubmit} className="w-full mt-4">
                                                    Submit Quiz
                                                </Button>
                                            </div>
                                        ) : (
                                            <div className="text-center py-8 space-y-4">
                                                {quizScore >= 60 ? (
                                                    <CheckCircle2 className="h-16 w-16 text-green-500 mx-auto" />
                                                ) : (
                                                    <div className="h-16 w-16 rounded-full bg-red-100 flex items-center justify-center mx-auto text-red-600 font-bold text-2xl">
                                                        !
                                                    </div>
                                                )}
                                                <div>
                                                    <h3 className="text-lg font-bold">
                                                        {quizScore >= 60 ? 'Quiz Passed!' : 'Try Again'}
                                                    </h3>
                                                    <p className="text-muted-foreground text-sm mt-1">
                                                        You scored {quizScore}%. Passing score is 60%.
                                                    </p>
                                                </div>
                                                {quizScore < 60 && (
                                                    <Button onClick={() => { setQuizSubmitted(false); setQuizAnswers({}); }}>
                                                        Retry Quiz
                                                    </Button>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                )}

                                {/* Generic Content (Text/Instructions) */}
                                {(activeLesson.type === 'TEXT' || activeLesson.type === 'ASSIGNMENT' || activeLesson.type === 'PDF') && (
                                    <div className="prose dark:prose-invert max-w-none bg-card p-6 rounded-xl border shadow-sm">
                                        <h2 className="text-xl font-bold mb-4 not-prose border-b pb-2">{activeLesson.title}</h2>
                                        <div dangerouslySetInnerHTML={{ __html: activeLesson.content || '' }} />

                                        {activeLesson.type === 'ASSIGNMENT' && (
                                            <div className="mt-8 p-6 bg-muted/30 rounded-lg border-2 border-dashed text-center">
                                                <FileText className="h-10 w-10 mx-auto opacity-50 mb-2" />
                                                <h3 className="font-semibold mb-1">Upload Submission</h3>
                                                <p className="text-xs text-muted-foreground mb-4">Upload your assignment file (PDF, Zip) for review.</p>
                                                <Button size="sm">Select File</Button>
                                            </div>
                                        )}
                                    </div>
                                )}

                                {/* Navigation / completion controls */}
                                <div className="flex items-center justify-between pt-8 border-t mt-8">
                                    <Button variant="ghost" disabled>Previous</Button>

                                    {/* Video triggers completion via button manually for now, usually via event */}
                                    {activeLesson.type !== 'QUIZ' && (
                                        <Button
                                            onClick={() => handleLessonComplete(activeLesson.id)}
                                            disabled={activeLesson.isCompleted}
                                            className={cn("min-w-[150px]", activeLesson.isCompleted && "bg-green-600 hover:bg-green-700")}
                                        >
                                            {activeLesson.isCompleted ? (
                                                <>
                                                    <CheckCircle2 className="mr-2 h-4 w-4" /> Completed
                                                </>
                                            ) : "Mark as Complete"}
                                        </Button>
                                    )}

                                    <Button variant="secondary" disabled>Next Lesson</Button>
                                </div>
                            </div>
                        ) : (
                            <div className="text-center py-20 animate-pulse">
                                <p className="text-muted-foreground">Select a lesson from the sidebar to start</p>
                            </div>
                        )}

                        {/* Course Completion Banner */}
                        {course.userProgress === 100 && (
                            <div className="mt-12 mb-12 p-8 bg-gradient-to-r from-emerald-500/10 to-blue-500/10 rounded-2xl border border-emerald-500/20 text-center animate-bounce-in">
                                <div className="inline-flex p-4 bg-emerald-100 dark:bg-emerald-900/30 rounded-full mb-4 shadow-sm">
                                    <Award className="h-10 w-10 text-emerald-600 dark:text-emerald-400" />
                                </div>
                                <h2 className="text-2xl font-bold mb-2">Detailed Course Completed!</h2>
                                <p className="text-muted-foreground mb-6 max-w-md mx-auto">
                                    Congratulations! You have successfully completed all modules and assessments.
                                </p>
                                <Button size="lg" className="bg-emerald-600 hover:bg-emerald-700 text-white shadow-lg shadow-emerald-500/20" onClick={() => router.push(`/certificate/${course.id}`)}>
                                    View Certificate
                                </Button>
                            </div>
                        )}
                    </div>
                </ScrollArea>
            </div>
        </div>
    )
}

import type { Metadata, ResolvingMetadata } from 'next'
import CourseDetailClient from './client'

type Props = {
    params: { id: string }
    searchParams: { [key: string]: string | string[] | undefined }
}

// Function to fetch data for metadata
// In a real app, use `fetch` with caching or a direct DB call if using Server Actions/RSC
async function getCourse(id: string) {
    try {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/courses/${id}`, {
            // Revalidate every hour
            next: { revalidate: 3600 }
        })
        if (!res.ok) return null
        // Assuming API structure: { course: ... } or { data: { course: ... } }
        // Based on previous code: response.data.course
        const data = await res.json()
        return data.course
    } catch (error) {
        return null
    }
}

export async function generateMetadata(
    { params, searchParams }: Props,
    parent: ResolvingMetadata
): Promise<Metadata> {
    const { id } = await params
    const course = await getCourse(id)

    if (!course) {
        return {
            title: 'Course Not Found',
        }
    }

    const previousImages = (await parent).openGraph?.images || []

    return {
        title: course.title,
        description: course.description?.slice(0, 160) || "Learn with TechWell",
        openGraph: {
            title: course.title,
            description: course.description?.slice(0, 160),
            images: course.thumbnail ? [course.thumbnail, ...previousImages] : previousImages,
            type: 'article',
            publishedTime: course.createdAt,
            authors: [course.instructor?.name || 'TechWell'],
        },
        twitter: {
            card: "summary_large_image",
            title: course.title,
            description: course.description?.slice(0, 160),
            images: course.thumbnail ? [course.thumbnail] : [],
        }
    }
}

export default async function CoursePage({ params }: Props) {
    const { id } = await params
    const course = await getCourse(id)

    // Handle course not found case gracefully (or let client handle loading if we returned null but client fetches too? 
    // Actually client generally re-fetches or we could pass initial data. 
    // For now we just render client component which handles its own fetching, 
    // but the JSON-LD script will only be present if we successfully fetched here.)

    if (!course) {
        return <CourseDetailClient />
    }

    // JSON-LD Structured Data
    const jsonLd = {
        '@context': 'https://schema.org',
        '@type': 'Course',
        name: course.title,
        description: course.description,
        provider: {
            '@type': 'Organization',
            name: 'TechWell',
            sameAs: 'https://techwell.co.in'
        },
        hasCourseInstance: {
            '@type': 'CourseInstance',
            courseMode: 'online',
            instructor: course.instructor ? {
                '@type': 'Person',
                name: course.instructor.name
            } : undefined
        },
        offers: {
            '@type': 'Offer',
            category: 'Paid',
            price: course.price,
            priceCurrency: 'INR'
        }
    }

    return (
        <>
            <script
                type="application/ld+json"
                dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
            />
            <CourseDetailClient />
        </>
    )
}

