                                    <div className="flex items-center gap-3 md:flex-shrink-0">
                                        {getStatusBadge(app.status)}
                                        <Button variant="ghost" size="sm" onClick={() => router.push(`/jobs/${app.job.id}`)}>
                                            <ExternalLink className="h-4 w-4" />
