export default function DashboardPage() {
    const router = useRouter()
    const { user, isLoading: authLoading, logout } = useAuth()

    const [activeTab, setActiveTab] = React.useState<'overview' | 'learning' | 'interviews' | 'applications' | 'certificates'>('overview')
    const [stats, setStats] = React.useState<{
        enrollments: number;
        interviews: { total: number; completed: number; averageScore: number };
    } | null>(null)

    const [enrollments, setEnrollments] = React.useState<Enrollment[]>([])
    const [interviews, setInterviews] = React.useState<Interview[]>([])
    const [jobInterviews, setJobInterviews] = React.useState<JobInterview[]>([])
    const [certificates, setCertificates] = React.useState<Certificate[]>([])
    const [applications, setApplications] = React.useState<Application[]>([])
    const [isLoading, setIsLoading] = React.useState(true)
    const [appFilter, setAppFilter] = React.useState<string>('ALL')

    React.useEffect(() => {
        if (!authLoading) {
            if (!user) {
                router.push('/login')
            } else if (user.role === 'EMPLOYER') {
                router.push('/employer/dashboard')
            } else if (user.role === 'SUPER_ADMIN' || user.role === 'ADMIN') {
                router.push('/admin')
            } else if (user.role === 'INSTRUCTOR') {
                router.push('/instructor')
            }
        }
    }, [authLoading, user, router])

    React.useEffect(() => {
        const fetchData = async () => {
            if (!user) return

            try {
                const [enrollmentsRes, interviewStatsRes, interviewsRes, jobInterviewsRes] = await Promise.all([
                    courseApi.getMyEnrollments(),
                    interviewApi.getStats(),
                    interviewApi.getAll({ page: 1 }),
                    interviewApi.getJobInterviews ? interviewApi.getJobInterviews() : Promise.resolve({ data: { interviews: [] } })
                ])

                setEnrollments(enrollmentsRes.data.enrollments || [])
                setInterviews(interviewsRes.data.interviews || [])
                setJobInterviews(jobInterviewsRes.data.interviews || [])

                setStats({
                    enrollments: enrollmentsRes.data.enrollments?.length || 0,
                    interviews: interviewStatsRes.data.stats || { total: 0, completed: 0, averageScore: 0 },
                })

                // Fetch certificates and applications in background (non-blocking)
                try {
                    const certsRes = await certificateApi.getAll()
                    setCertificates(certsRes.data.certificates || certsRes.data || [])
                } catch {
                    // Certificate endpoint might fail - graceful fallback
                }

                try {
                    const appsRes = await api.get('/jobs/applications/me')
                    setApplications(appsRes.data || [])
                } catch {
                    // Applications endpoint might fail - graceful fallback
                }
            } catch {
                // Error handling
            } finally {
                setIsLoading(false)
            }
        }

        if (user) {
            fetchData()
        }
    }, [user])

    const getStatusBadge = (status: string) => {
        const statusMap: Record<string, { label: string; className: string }> = {
            APPLIED: { label: 'Applied', className: 'bg-blue-50 text-blue-700 border-blue-200' },
            UNDER_REVIEW: { label: 'Under Review', className: 'bg-yellow-50 text-yellow-700 border-yellow-200' },
            SHORTLISTED: { label: 'Shortlisted', className: 'bg-emerald-50 text-emerald-700 border-emerald-200' },
            INTERVIEW: { label: 'Interview', className: 'bg-purple-50 text-purple-700 border-purple-200' },
            OFFERED: { label: 'Offered', className: 'bg-green-50 text-green-700 border-green-200' },
            HIRED: { label: 'Hired', className: 'bg-green-50 text-green-800 border-green-300' },
            REJECTED: { label: 'Rejected', className: 'bg-red-50 text-red-700 border-red-200' },
            WITHDRAWN: { label: 'Withdrawn', className: 'bg-gray-50 text-gray-600 border-gray-200' },
        }
        const s = statusMap[status] || { label: status, className: 'bg-gray-50 text-gray-700 border-gray-200' }
        return <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${s.className}`}>{s.label}</span>
    }

    const filteredApplications = appFilter === 'ALL'
        ? applications
        : applications.filter(app => app.status === appFilter)

    if (authLoading || !user) {
        return (
            <div className="min-h-[calc(100vh-4rem)] flex items-center justify-center bg-background relative overflow-hidden">
                <div className="absolute inset-0 z-0">
                    <div className="absolute top-[-20%] left-[-10%] w-[800px] h-[800px] bg-primary/5 rounded-full blur-[100px] opacity-40 animate-pulse" />
                    <div className="absolute bottom-[-20%] right-[-10%] w-[600px] h-[600px] bg-purple-500/5 rounded-full blur-[100px] opacity-40" />
                </div>
                <Loader2 className="h-8 w-8 animate-spin text-primary relative z-10" />
            </div>
        )
    }

    return (
        <div className="relative min-h-screen bg-background overflow-hidden">
            {/* Background Decor */}
            <div className="absolute inset-0 z-0 pointer-events-none">
                <div className="absolute top-[-10%] left-[-10%] w-[600px] h-[600px] bg-primary/5 rounded-full blur-[100px]" />
                <div className="absolute bottom-[20%] right-[-5%] w-[500px] h-[500px] bg-teal-500/5 rounded-full blur-[100px]" />
            </div>

            <div className="container py-8 relative z-10">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                    <div>
                        <h1 className="text-3xl font-extrabold tracking-tight">
                            Welcome, <span className="text-gradient">{user.name}</span>!
                        </h1>
                        <p className="text-muted-foreground mt-1 text-lg">Track your progress and manage your learning journey.</p>
                    </div>
                    <div className="flex gap-3">
                        <Button variant="outline" className="hover:bg-muted/80" onClick={() => router.push('/profile')}>
                            Profile Settings
                        </Button>
                        <Button variant="ghost" className="text-red-500 hover:text-red-600 hover:bg-red-50/50" onClick={logout}>
                            <LogOut className="mr-2 h-4 w-4" />
                            Logout
                        </Button>
                    </div>
                </div>

                {/* Tab Navigation */}
                <div className="flex gap-1 mb-8 p-1.5 bg-muted/50 border border-border/50 rounded-xl overflow-x-auto">
                    {[
                        { id: 'overview', label: 'Overview', icon: TrendingUp },
                        { id: 'learning', label: 'My Learning', icon: BookOpen },
                        { id: 'interviews', label: 'Interviews', icon: Video },
                        { id: 'applications', label: 'Applications', icon: Briefcase, count: applications.length },
                        { id: 'certificates', label: 'Certificates', icon: Award, count: certificates.length },
                    ].map((tab) => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id as typeof activeTab)}
                            className={`px-5 py-2.5 rounded-lg font-medium transition-all duration-300 flex items-center gap-2 whitespace-nowrap text-sm ${activeTab === tab.id
                                ? 'bg-primary text-white shadow-lg shadow-primary/25'
                                : 'text-muted-foreground hover:bg-background hover:text-foreground'
                                }`}
                        >
                            <tab.icon className="h-4 w-4" />
                            {tab.label}
                            {tab.count !== undefined && tab.count > 0 && (
                                <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-bold ${activeTab === tab.id
                                    ? 'bg-white/20 text-white'
                                    : 'bg-primary/10 text-primary'
                                    }`}>
                                    {tab.count}
                                </span>
                            )}
                        </button>
                    ))}
                </div>

                {/* PROMINENT UPCOMING INTERVIEWS BANNER */}
                {jobInterviews.length > 0 && (
                    <div className="mb-8 bg-card border border-border rounded-2xl p-6 border-l-4 border-l-primary relative overflow-hidden animate-in fade-in slide-in-from-top-2 duration-500">
                        <div className="absolute top-0 right-0 w-40 h-40 bg-primary/5 rounded-full blur-3xl" />

                        <div className="flex items-center gap-3 mb-4 relative z-10">
                            <div className="p-2 bg-primary/10 rounded-xl">
                                <Calendar className="h-6 w-6 text-primary animate-pulse" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-foreground">Upcoming Interviews</h2>
                                <p className="text-sm text-muted-foreground">You have {jobInterviews.length} scheduled interview{jobInterviews.length > 1 ? 's' : ''}</p>
                            </div>
                        </div>

                        <div className="space-y-3 relative z-10">
                            {jobInterviews.slice(0, 3).map((interview) => {
                                const interviewDate = new Date(interview.scheduledAt);
                                const isToday = interviewDate.toDateString() === new Date().toDateString();
                                const isTomorrow = interviewDate.toDateString() === new Date(Date.now() + 86400000).toDateString();
                                const isPast = interviewDate < new Date();
                                const isWithinHour = !isPast && (interviewDate.getTime() - Date.now()) < 3600000;

                                return (
                                    <div
                                        key={interview.id}
                                        className={`flex flex-col md:flex-row md:items-center justify-between gap-4 p-4 rounded-xl bg-background border ${isWithinHour ? 'border-green-500 shadow-lg shadow-green-500/10' :
                                            isToday ? 'border-primary/50' : 'border-border'
                                            }`}
                                    >
                                        <div className="flex items-start gap-4">
                                            <div className={`flex flex-col items-center justify-center p-3 rounded-xl min-w-[70px] ${isWithinHour ? 'bg-green-50 text-green-700' :
                                                isToday ? 'bg-primary/10 text-primary' :
                                                    isTomorrow ? 'bg-blue-50 text-blue-700' :
                                                        'bg-muted text-muted-foreground'
                                                }`}>
                                                <span className="text-xs font-medium uppercase">
                                                    {isToday ? 'Today' : isTomorrow ? 'Tomorrow' : interviewDate.toLocaleDateString('en-US', { weekday: 'short' })}
                                                </span>
                                                <span className="text-2xl font-bold">{interviewDate.getDate()}</span>
                                                <span className="text-xs">{interviewDate.toLocaleDateString('en-US', { month: 'short' })}</span>
                                            </div>
                                            <div>
                                                <h3 className="font-bold text-lg text-foreground">{interview.application?.job?.title || interview.roundName}</h3>
                                                <p className="text-sm text-muted-foreground">
                                                    {interview.application?.job?.employer?.employerProfile?.companyName || 'Company'} • {interview.roundName}
                                                </p>
                                                <div className="flex items-center gap-2 mt-1">
                                                    <Clock className="h-3 w-3 text-muted-foreground" />
                                                    <span className="text-sm font-medium text-foreground">
                                                        {interviewDate.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })} ({interview.duration} min)
                                                    </span>
                                                    {isWithinHour && (
                                                        <span className="text-xs px-2 py-0.5 bg-green-100 text-green-700 rounded-full font-medium animate-pulse">
                                                            Starting Soon!
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>

                                        <div className="flex gap-2 md:flex-shrink-0">
                                            {interview.meetingLink ? (
                                                <Button
                                                    size="lg"
                                                    className={`gap-2 font-semibold ${isWithinHour
                                                        ? 'bg-green-600 hover:bg-green-700 shadow-lg shadow-green-500/20'
                                                        : 'bg-primary hover:bg-primary/90'
                                                        }`}
                                                    onClick={() => window.open(interview.meetingLink, '_blank')}
                                                >
                                                    <Video className="h-4 w-4" />
                                                    {isWithinHour ? 'Join Now' : 'Join Meeting'}
                                                </Button>
                                            ) : (
                                                <Button size="lg" variant="outline" className="gap-2" disabled>
                                                    <Video className="h-4 w-4" />
                                                    Link pending...
                                                </Button>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}

                            {jobInterviews.length > 3 && (
                                <Button variant="link" className="w-full text-primary" onClick={() => setActiveTab('interviews')}>
                                    View all {jobInterviews.length} interviews →
                                </Button>
                            )}
                        </div>
                    </div>
                )}

                {isLoading ? (
                    <div className="flex justify-center py-20">
                        <Loader2 className="h-10 w-10 animate-spin text-primary" />
                    </div>
                ) : (
                    <>
                        {/* OVERVIEW TAB */}
                        {activeTab === 'overview' && (
                            <div className="space-y-8">
                                {/* Stats Grid */}
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                                    {[
                                        { label: 'Enrolled Courses', value: stats?.enrollments || 0, icon: GraduationCap, color: 'blue' },
                                        { label: 'Total Interviews', value: stats?.interviews.total || 0, icon: Video, color: 'purple' },
                                        { label: 'Completed', value: stats?.interviews.completed || 0, icon: CheckCircle2, color: 'teal' },
                                        { label: 'Avg Score', value: `${Math.round(stats?.interviews.averageScore || 0)}%`, icon: TrendingUp, color: 'green' },
                                    ].map((stat) => (
                                        <div key={stat.label} className="bg-card border border-border p-6 rounded-2xl relative overflow-hidden group hover:-translate-y-1 transition-all duration-300 hover:shadow-md">
                                            <div className="flex justify-between items-start mb-4">
                                                <div>
                                                    <p className="text-sm font-medium text-muted-foreground">{stat.label}</p>
                                                    <h3 className="text-3xl font-bold mt-2 text-foreground">{stat.value}</h3>
                                                </div>
                                                <div className={`p-3 bg-${stat.color}-500/10 rounded-xl text-${stat.color}-600`}>
                                                    <stat.icon className="h-6 w-6" />
                                                </div>
                                            </div>
                                            <div className={`absolute inset-x-0 bottom-0 h-1 bg-gradient-to-r from-transparent via-${stat.color}-500 to-transparent opacity-0 group-hover:opacity-100 transition-opacity`} />
                                        </div>
                                    ))}
                                </div>

                                {/* Recent Activity / Quick Actions */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="bg-card border border-border p-6 rounded-2xl">
                                        <div className="flex flex-col gap-1 mb-6">
                                            <h3 className="text-xl font-bold text-foreground">Continue Learning</h3>
                                            <p className="text-sm text-muted-foreground">Pick up where you left off</p>
                                        </div>

                                        <div className="space-y-3">
                                            {enrollments.length > 0 ? (
                                                <>
                                                    {enrollments.slice(0, 3).map((enrollment) => (
                                                        <div key={enrollment.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-muted/50 transition-colors border border-transparent hover:border-border">
                                                            <div className="flex items-center gap-3 flex-1 min-w-0">
                                                                <div className="h-10 w-10 bg-primary/10 rounded-lg flex items-center justify-center flex-shrink-0">
                                                                    <BookOpen className="h-5 w-5 text-primary" />
                                                                </div>
                                                                <div className="min-w-0">
                                                                    <h4 className="font-medium line-clamp-1 text-foreground">{enrollment.course.title}</h4>
                                                                    <p className="text-xs text-muted-foreground">{enrollment.course.category} • {enrollment.progress || 0}% complete</p>
                                                                </div>
                                                            </div>
                                                            <Button size="sm" variant="ghost" className="h-8 w-8 p-0 rounded-full flex-shrink-0" onClick={() => router.push(`/courses/${enrollment.course.id}/learn`)}>
                                                                <PlayCircle className="h-4 w-4" />
                                                            </Button>
                                                        </div>
                                                    ))}
                                                    <Button variant="link" className="px-0 w-full text-primary" onClick={() => setActiveTab('learning')}>
                                                        View All Courses
                                                    </Button>
                                                </>
                                            ) : (
                                                <div className="text-center py-6">
                                                    <p className="text-muted-foreground mb-4">No courses enrolled yet.</p>
                                                    <Button onClick={() => router.push('/courses')}>Browse Courses</Button>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    <div className="bg-card border border-border p-6 rounded-2xl">
                                        <div className="flex flex-col gap-1 mb-6">
                                            <h3 className="text-xl font-bold text-foreground">Interview Practice</h3>
                                            <p className="text-sm text-muted-foreground">Recent mock interviews</p>
                                        </div>

                                        <div className="space-y-3">
                                            {interviews.length > 0 ? (
                                                <>
                                                    {interviews.slice(0, 3).map((interview) => (
                                                        <div key={interview.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-muted/50 transition-colors border border-transparent hover:border-border">
                                                            <div>
                                                                <h4 className="font-medium text-foreground">{interview.role}</h4>
                                                                <p className="text-xs text-muted-foreground">{interview.domain} • {new Date(interview.createdAt).toLocaleDateString()}</p>
                                                            </div>
                                                            <span className={`text-xs px-2.5 py-1 rounded-full font-medium border ${interview.status === 'COMPLETED' ? 'bg-green-50 text-green-700 border-green-200' : 'bg-yellow-50 text-yellow-700 border-yellow-200'
                                                                }`}>
                                                                {interview.status === 'COMPLETED' ? `${interview.score || 0}%` : interview.status}
                                                            </span>
                                                        </div>
                                                    ))}
                                                    <Button variant="link" className="px-0 w-full text-primary" onClick={() => setActiveTab('interviews')}>
                                                        View All Interviews
                                                    </Button>
                                                </>
                                            ) : (
                                                <div className="text-center py-6">
                                                    <p className="text-muted-foreground mb-4">No interviews taken yet.</p>
                                                    <NewInterviewDialog trigger={<Button variant="outline">Start Interview</Button>} />
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* MY LEARNING TAB */}
                        {activeTab === 'learning' && (
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                {enrollments.map((enrollment) => {
                                    const progress = enrollment.progress || 0
                                    return (
                                        <div key={enrollment.id} className="bg-card border border-border p-0 rounded-2xl overflow-hidden hover:shadow-lg transition-all duration-300 hover:-translate-y-1">
                                            <div className="p-6 pb-2">
                                                <div className="flex justify-between items-start">
                                                    <div className="h-10 w-10 bg-primary/10 rounded-lg flex items-center justify-center mb-4">
                                                        <GraduationCap className="h-5 w-5 text-primary" />
                                                    </div>
                                                    <span className="text-xs px-2 py-1 bg-muted rounded-full border border-border font-medium text-muted-foreground">
                                                        {enrollment.course.difficulty}
                                                    </span>
                                                </div>
                                                <h3 className="text-lg font-bold line-clamp-1 mb-1 text-foreground">{enrollment.course.title}</h3>
                                                <p className="text-sm text-muted-foreground">{enrollment.course.category}</p>
                                            </div>
                                            <div className="p-6 pt-2">
                                                <div className="w-full bg-muted h-2 rounded-full mb-4 overflow-hidden">
                                                    <div
                                                        className={`h-2 rounded-full transition-all duration-500 ${progress === 100 ? 'bg-green-500' : 'bg-primary'}`}
                                                        style={{ width: `${progress}%` }}
                                                    />
                                                </div>
                                                <div className="flex justify-between items-center text-sm mb-4">
                                                    <span className="text-muted-foreground">Progress</span>
                                                    <span className={`font-bold ${progress === 100 ? 'text-green-600' : 'text-foreground'}`}>{progress}%</span>
                                                </div>

                                                {enrollment.hasInterviewAccess && (
                                                    <div className="mb-4 pt-4 border-t border-border">
                                                        <div className="flex justify-between items-center text-sm mb-2">
                                                            <span className="text-muted-foreground flex items-center gap-1">
                                                                <Video className="h-3 w-3" /> Interview Prep
                                                            </span>
                                                        </div>
                                                        <Button variant="secondary" size="sm" className="w-full text-xs h-8" onClick={() => router.push('/interviews')}>
                                                            Practice Now
                                                        </Button>
                                                    </div>
                                                )}
                                                <Button
                                                    className="w-full shadow-sm"
                                                    onClick={() => router.push(`/courses/${enrollment.course.id}/learn`)}
                                                >
                                                    <PlayCircle className="mr-2 h-4 w-4" />
                                                    {progress === 100 ? 'Review Course' : progress > 0 ? 'Continue' : 'Start Learning'}
                                                </Button>
                                            </div>
                                        </div>
                                    )
                                })}
                                {enrollments.length === 0 && (
                                    <div className="col-span-full text-center py-20">
                                        <GraduationCap className="h-16 w-16 text-muted-foreground/30 mx-auto mb-4" />
                                        <h3 className="text-xl font-medium mb-2 text-foreground">No Courses Yet</h3>
                                        <p className="text-muted-foreground mb-6">Start your learning journey today.</p>
                                        <Button size="lg" onClick={() => router.push('/courses')}>Browse Catalog</Button>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* INTERVIEWS TAB */}
                        {activeTab === 'interviews' && (
                            <div className="space-y-6">
                                <div className="flex justify-between items-center">
                                    <h2 className="text-2xl font-bold text-foreground">Interview History</h2>
                                    <NewInterviewDialog />
                                </div>

                                {/* Scheduled Job Interviews Section */}
                                {jobInterviews.length > 0 && (
                                    <div className="bg-card border border-border rounded-xl p-6 border-l-4 border-l-blue-500 mb-6 relative overflow-hidden">
                                        <div className="absolute top-0 right-0 p-4 opacity-5">
                                            <Calendar className="w-24 h-24" />
                                        </div>
                                        <h3 className="text-lg font-bold mb-4 flex items-center gap-2 text-foreground">
                                            <Calendar className="h-5 w-5 text-blue-500" />
                                            Upcoming Scheduled Interviews
                                        </h3>
                                        <div className="grid gap-4">
                                            {jobInterviews.map((interview) => (
                                                <div key={interview.id} className="bg-muted/30 p-4 rounded-lg border border-border flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                                                    <div>
                                                        <h4 className="font-bold text-lg text-foreground">{interview.roundName}</h4>
                                                        <p className="text-muted-foreground">{interview.application.job.title} at <span className="text-foreground font-medium">{interview.application.job.employer.employerProfile?.companyName || 'Company'}</span></p>
                                                        <div className="flex flex-wrap gap-4 mt-2 text-sm">
                                                            <div className="flex items-center gap-1 text-foreground">
                                                                <Calendar className="h-4 w-4 text-blue-500" />
                                                                {new Date(interview.scheduledAt).toLocaleDateString()}
                                                            </div>
                                                            <div className="flex items-center gap-1 text-foreground">
                                                                <Clock className="h-4 w-4 text-blue-500" />
                                                                {new Date(interview.scheduledAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} ({interview.duration} mins)
                                                            </div>
                                                            {interview.location && (
                                                                <div className="flex items-center gap-1 text-muted-foreground">
                                                                    <MapPin className="h-4 w-4" /> {interview.location}
                                                                </div>
                                                            )}
                                                        </div>
                                                    </div>
                                                    <div className="flex flex-col items-end gap-2">
                                                        <span className="px-3 py-1 bg-blue-50 text-blue-700 rounded-full text-xs font-medium border border-blue-200">
                                                            {interview.roundType}
                                                        </span>
                                                        {interview.meetingLink && (
                                                            <Button size="sm" onClick={() => window.open(interview.meetingLink, '_blank')}>
                                                                <Video className="mr-1 h-3 w-3" /> Join Meeting
                                                            </Button>
                                                        )}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                <div className="bg-card border border-border rounded-2xl p-6">
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                        {interviews.map(interview => (
                                            <div key={interview.id} className="p-4 rounded-xl border border-border bg-background hover:bg-muted/30 transition-colors">
                                                <div className="flex justify-between mb-2">
                                                    <span className="text-xs text-muted-foreground">{new Date(interview.createdAt).toLocaleDateString()}</span>
                                                    <span className={`text-xs px-2 py-1 rounded-full font-medium border ${interview.status === 'COMPLETED' ? 'bg-green-50 text-green-700 border-green-200' : 'bg-blue-50 text-blue-700 border-blue-200'
                                                        }`}>
                                                        {interview.status}
                                                    </span>
                                                </div>
                                                <h3 className="font-bold text-base mb-1 text-foreground">{interview.role}</h3>
                                                <p className="text-xs text-muted-foreground mb-3">{interview.domain}</p>

                                                {interview.status === 'COMPLETED' && (
                                                    <div className="mb-4 flex items-baseline gap-1">
                                                        <span className="text-2xl font-bold text-primary">{interview.score || 0}%</span>
                                                        <span className="text-xs text-muted-foreground">Score</span>
                                                    </div>
                                                )}
                                                <Button variant="outline" className="w-full" size="sm" onClick={() => router.push(`/interviews/${interview.id}${interview.status === 'COMPLETED' ? '/report' : ''}`)}>
                                                    {interview.status === 'COMPLETED' ? 'View Report' : 'Resume'}
                                                </Button>
                                            </div>
                                        ))}
                                        {interviews.length === 0 && (
                                            <div className="col-span-full py-12 text-center">
                                                <Video className="h-12 w-12 text-muted-foreground/30 mx-auto mb-4" />
                                                <h3 className="text-lg font-medium mb-2 text-foreground">No Interviews Yet</h3>
                                                <p className="text-muted-foreground mb-4">Practice with AI-powered mock interviews.</p>
                                                <NewInterviewDialog trigger={<Button>Start Your First Interview</Button>} />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* APPLICATIONS TAB */}
                        {activeTab === 'applications' && (
                            <div className="space-y-6">
                                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                                    <div>
                                        <h2 className="text-2xl font-bold text-foreground">My Applications</h2>
                                        <p className="text-muted-foreground text-sm">{applications.length} total application{applications.length !== 1 ? 's' : ''}</p>
                                    </div>
                                    <Button onClick={() => router.push('/jobs')} variant="outline">
                                        <Briefcase className="mr-2 h-4 w-4" /> Find Jobs
                                    </Button>
                                </div>

                                {/* Status Filter */}
                                {applications.length > 0 && (
                                    <div className="flex gap-2 overflow-x-auto pb-1">
                                        {['ALL', 'APPLIED', 'UNDER_REVIEW', 'SHORTLISTED', 'INTERVIEW', 'OFFERED', 'REJECTED'].map((status) => {
                                            const count = status === 'ALL' ? applications.length : applications.filter(a => a.status === status).length
                                            if (count === 0 && status !== 'ALL') return null
                                            return (
                                                <button
                                                    key={status}
                                                    onClick={() => setAppFilter(status)}
                                                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors whitespace-nowrap border ${appFilter === status
                                                        ? 'bg-primary text-white border-primary'
                                                        : 'bg-background text-muted-foreground border-border hover:bg-muted/50'
                                                        }`}
                                                >
                                                    {status === 'ALL' ? 'All' : status.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())} ({count})
                                                </button>
                                            )
                                        })}
                                    </div>
                                )}

                                {/* Applications List */}
                                <div className="space-y-3">
                                    {filteredApplications.map((app) => (
                                        <div key={app.id} className="bg-card border border-border rounded-xl p-5 hover:shadow-md transition-all duration-200">
                                            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                                <div className="flex items-start gap-4">
                                                    <div className="h-12 w-12 bg-primary/10 rounded-xl flex items-center justify-center flex-shrink-0">
                                                        <Building2 className="h-6 w-6 text-primary" />
                                                    </div>
                                                    <div>
                                                        <h3 className="font-bold text-foreground text-lg">{app.job.title}</h3>
                                                        <p className="text-sm text-muted-foreground">
                                                            {app.job.employer?.employerProfile?.companyName || 'Company'}
                                                        </p>
                                                        <div className="flex items-center gap-3 mt-1.5 text-xs text-muted-foreground">
                                                            {app.job.location && (
                                                                <span className="flex items-center gap-1">
                                                                    <MapPin className="h-3 w-3" /> {app.job.location}
                                                                </span>
                                                            )}
                                                            <span className="flex items-center gap-1">
                                                                <Briefcase className="h-3 w-3" /> {app.job.type}
                                                            </span>
                                                            <span className="flex items-center gap-1">
                                                                <Clock className="h-3 w-3" /> Applied {new Date(app.createdAt).toLocaleDateString()}
                                                            </span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <div className="flex items-center gap-3 md:flex-shrink-0">
                                                    {getStatusBadge(app.status)}
                                                    <Button variant="ghost" size="sm" onClick={() => router.push(`/jobs/${app.job.id}`)}>
                                                        <ExternalLink className="h-4 w-4" />
                                                    </Button>
                                                </div>
                                            </div>
                                        </div>
                                    ))}

                                    {applications.length === 0 && (
                                        <div className="text-center py-20 bg-card border border-border rounded-2xl">
                                            <Briefcase className="h-16 w-16 text-muted-foreground/30 mx-auto mb-4" />
                                            <h3 className="text-xl font-medium mb-2 text-foreground">No Applications Yet</h3>
                                            <p className="text-muted-foreground mb-6 max-w-sm mx-auto">Start applying to jobs and track your applications here.</p>
                                            <Button size="lg" onClick={() => router.push('/jobs')}>
                                                <Briefcase className="mr-2 h-4 w-4" /> Browse Jobs
                                            </Button>
                                        </div>
                                    )}

                                    {applications.length > 0 && filteredApplications.length === 0 && (
                                        <div className="text-center py-12 bg-card border border-border rounded-2xl">
                                            <FileText className="h-12 w-12 text-muted-foreground/30 mx-auto mb-4" />
                                            <p className="text-muted-foreground">No applications with this status.</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* CERTIFICATES TAB */}
                        {activeTab === 'certificates' && (
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                {certificates.map((cert) => (
                                    <div key={cert.id} className="bg-card border border-border p-6 rounded-2xl border-l-[6px] border-l-yellow-500 relative overflow-hidden group hover:shadow-md transition-all">
                                        <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                                            <Award className="w-24 h-24" />
                                        </div>
                                        <div className="h-12 w-12 bg-yellow-50 rounded-full flex items-center justify-center mb-4">
                                            <Award className="h-6 w-6 text-yellow-600" />
                                        </div>
                                        <h3 className="text-lg font-bold mb-1 text-foreground">{cert.courseName}</h3>
                                        <p className="text-sm text-muted-foreground mb-4">Certificate of Completion</p>

                                        <div className="flex items-center gap-2 text-xs text-muted-foreground mb-2 bg-muted/50 p-2 rounded border border-border">
                                            <Clock className="h-3 w-3" />
                                            Issued: {new Date(cert.issueDate).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
                                        </div>
                                        <div className="flex items-center gap-2 text-xs text-muted-foreground mb-4 bg-muted/50 p-2 rounded border border-border font-mono">
                                            ID: {cert.uniqueId}
                                        </div>

                                        {cert.score && (
                                            <div className="mb-4 text-sm">
                                                <span className="text-muted-foreground">Score: </span>
                                                <span className="font-bold text-foreground">{cert.score}%</span>
                                            </div>
                                        )}

                                        <Button size="sm" variant="outline" className="w-full" onClick={() => router.push(`/certificate/${cert.id}`)}>
                                            <Download className="h-4 w-4 mr-2" />
                                            View Certificate
                                        </Button>
                                    </div>
                                ))}
                                {certificates.length === 0 && (
                                    <div className="col-span-full text-center py-20 bg-card border border-border rounded-2xl">
                                        <Award className="h-16 w-16 text-muted-foreground/30 mx-auto mb-4" />
                                        <h3 className="text-lg font-medium mb-2 text-foreground">No Certificates Yet</h3>
                                        <p className="text-muted-foreground mb-6">Complete courses to earn your certificates.</p>
                                        <Button onClick={() => setActiveTab('learning')}>
                                            <BookOpen className="mr-2 h-4 w-4" /> Go to My Learning
                                        </Button>
                                    </div>
                                )}
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { useParams, useRouter } from "next/navigation"
import api from "@/lib/api"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Textarea } from "@/components/ui/textarea"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
    Loader2, Mail, Phone, Calendar, Download, Send, Star, MessageSquare,
    Tag, Clock, Zap, CheckCircle2, XCircle, AlertTriangle, ArrowLeft,
    BookOpen, Award
} from "lucide-react"

interface HistoryEntry {
    type?: string
    status?: string
    content?: string
    rating?: number
    tags?: string[]
    timestamp: string
    notes?: string
    addedBy?: string
}

interface ApplicationDetail {
    id: string
    status: string
    source: string
    atsScore: number
    createdAt: string
    externalName?: string
    externalEmail?: string
    externalPhone?: string
    coverLetter?: string
    resumeUrl?: string
    applicant?: {
        id: string
        name: string
        email: string
        phone?: string
        avatar?: string
    }
    statusHistory?: HistoryEntry[]
    job?: {
        title: string
        skills?: string
    }
}

function AIInterviewList({ userId }: { userId: string }) {
    const [interviews, setInterviews] = useState<any[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchInterviews = async () => {
            try {
                const res = await api.get(`/interviews/user/${userId}`)
                setInterviews(res.data.interviews || [])
            } catch (error) {
                console.error("Failed to fetch interviews", error)
            } finally {
                setLoading(false)
            }
        }
        fetchInterviews()
    }, [userId])

    if (loading) return <div className="text-center py-4"><Loader2 className="animate-spin h-5 w-5 mx-auto text-primary" /></div>
    if (interviews.length === 0) return <div className="text-center py-8 text-muted-foreground">No practice interviews found.</div>

    return (
        <div className="space-y-3">
            {interviews.map((interview) => (
                <div key={interview.id} className="flex items-center justify-between p-3 bg-white/50 border rounded-lg hover:bg-white transition-colors">
                    <div>
                        <div className="font-medium text-sm">{interview.role} ({interview.domain})</div>
                        <div className="text-xs text-muted-foreground gap-2 flex items-center">
                            <Badge variant="outline" className="text-[10px] h-4">{interview.difficulty}</Badge>
                            <span>{new Date(interview.createdAt).toLocaleDateString()}</span>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        {interview.evaluation ? (
                            <Badge variant={interview.evaluation.overallScore >= 70 ? 'default' : 'secondary'} className={interview.evaluation.overallScore >= 70 ? 'bg-green-600' : 'bg-amber-500'}>
                                {interview.evaluation.overallScore}%
                            </Badge>
                        ) : (
                            <span className="text-xs text-muted-foreground">In Progress</span>
                        )}
                        <Button size="sm" variant="ghost" onClick={() => window.open(`/interviews/${interview.id}/report`, '_blank')}>
                            View Report
                        </Button>
                    </div>
                </div>
            ))}
        </div>
    )
}

export default function CandidateProfilePage() {
    const { id } = useParams()
    const router = useRouter()

    const [application, setApplication] = useState<ApplicationDetail | null>(null)
    const [isLoading, setIsLoading] = useState(true)
    const [score, setScore] = useState<number | null>(null)

    // Notes
    const [noteContent, setNoteContent] = useState("")
    const [noteTags, setNoteTags] = useState("")
    const [submittingNote, setSubmittingNote] = useState(false)

    // Rating
    const [hoverRating, setHoverRating] = useState(0)
    const [selectedRating, setSelectedRating] = useState(0)

    const fetchData = useCallback(async () => {
        try {
            const res = await api.get(`/ats/applications/detail/${id}`)
            setApplication(res.data)
            setScore(res.data.atsScore)

            // Auto-mark as VIEWED if status is APPLIED
            if (res.data.status === 'APPLIED') {
                await api.patch(`/ats/status/${id}`, { status: 'VIEWED' })
                setApplication((prev) => prev ? ({ ...prev, status: 'VIEWED' }) : null)
            }

            // Extract most recent rating
            const ratings = (res.data.statusHistory || []).filter((h: HistoryEntry) => h.type === 'RATING')
            if (ratings.length > 0) {
                setSelectedRating(ratings[ratings.length - 1].rating || 0)
            }
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoading(false)
        }
    }, [id])

    useEffect(() => {
        fetchData()
    }, [fetchData])

    const handleScore = async () => {
        const res = await api.post(`/ats/score/${id}`)
        setScore(res.data.atsScore)
        fetchData()
    }

    const handleStatusUpdate = async (newStatus: string) => {
        await api.patch(`/ats/status/${id}`, { status: newStatus })
        setApplication((prev) => prev ? ({ ...prev, status: newStatus }) : null)
    }

    const handleAddNote = async () => {
        if (!noteContent.trim()) return
        setSubmittingNote(true)
        try {
            const tags = noteTags.split(',').map(t => t.trim()).filter(Boolean)
            await api.post(`/ats/notes/${id}`, {
                content: noteContent,
                tags,
                rating: selectedRating || undefined
            })
            setNoteContent("")
            setNoteTags("")
            fetchData()
        } catch (error) {
            console.error('Failed to add note:', error)
        } finally {
            setSubmittingNote(false)
        }
    }

    const handleRate = async (rating: number) => {
        setSelectedRating(rating)
        try {
            await api.patch(`/ats/rate/${id}`, { rating })
        } catch (error) {
            console.error('Failed to rate:', error)
        }
    }

    if (isLoading) return (
        <div className="flex justify-center items-center h-[60vh]">
            <Loader2 className="animate-spin h-8 w-8 text-primary" />
        </div>
    )

    if (!application) return (
        <div className="text-center py-20 text-muted-foreground">
            <XCircle className="mx-auto h-12 w-12 mb-3 opacity-30" />
            Candidate not found
        </div>
    )

    const { applicant, externalName, externalEmail, externalPhone, source, status, coverLetter, resumeUrl } = application
    const name = applicant?.name || externalName || 'Unknown Candidate'
    const email = applicant?.email || externalEmail
    const phone = applicant?.phone || externalPhone || "N/A"

    // Separate notes vs status changes from history
    const notes = (application.statusHistory || []).filter(h => h.type === 'NOTE')
    const statusHistory = (application.statusHistory || []).filter(h => !h.type || h.type === 'STATUS')
    const ratings = (application.statusHistory || []).filter(h => h.type === 'RATING')

    const getStatusColor = (s: string) => {
        switch (s) {
            case 'APPLIED': case 'VIEWED': return 'bg-gray-400'
            case 'SCREENED': return 'bg-blue-500'
            case 'SHORTLISTED': return 'bg-purple-500'
            case 'INTERVIEW_SCHEDULED': case 'INTERVIEW_PENDING': return 'bg-violet-500'
            case 'SELECTED': case 'APPOINTED': case 'HIRED': return 'bg-green-500'
            case 'REJECTED': return 'bg-red-500'
            default: return 'bg-primary'
        }
    }

    return (
        <div className="max-w-5xl mx-auto py-6 px-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <Button variant="ghost" onClick={() => router.back()} className="mb-4 gap-2">
                <ArrowLeft className="h-4 w-4" /> Back to Pipeline
            </Button>

            <div className="grid gap-6 md:grid-cols-3">
                {/* Sidebar Profile */}
                <Card className="md:col-span-1 glass-card">
                    <CardContent className="pt-6 flex flex-col items-center text-center">
                        <Avatar className="h-24 w-24 mb-4 ring-4 ring-primary/10">
                            <AvatarImage src={applicant?.avatar} />
                            <AvatarFallback className="text-xl bg-primary/10 text-primary font-bold">{name[0]}</AvatarFallback>
                        </Avatar>
                        <h2 className="text-xl font-bold">{name}</h2>
                        <p className="text-sm text-muted-foreground mb-2">{email}</p>

                        {/* Star Rating */}
                        <div className="flex items-center gap-1 mb-4">
                            {[1, 2, 3, 4, 5].map((star) => (
                                <button
                                    key={star}
                                    onClick={() => handleRate(star)}
                                    onMouseEnter={() => setHoverRating(star)}
                                    onMouseLeave={() => setHoverRating(0)}
                                    className="p-0.5 transition-transform hover:scale-125"
                                    aria-label={`Rate ${star} stars`}
                                >
                                    <Star
                                        className={`h-5 w-5 transition-colors ${(hoverRating || selectedRating) >= star
                                            ? 'fill-amber-400 text-amber-400'
                                            : 'text-gray-300'
                                            }`}
                                    />
                                </button>
                            ))}
                        </div>

                        <div className="flex flex-wrap gap-2 justify-center mb-6">
                            {source === 'INTERNAL' ? (
                                <Badge className="bg-blue-600 hover:bg-blue-700">TechWell Student</Badge>
                            ) : (
                                <Badge variant="secondary">External</Badge>
                            )}
                            <Badge variant="outline" className={`${status === 'HIRED' || status === 'APPOINTED' ? 'border-green-300 text-green-700' :
                                status === 'REJECTED' ? 'border-red-300 text-red-700' : ''
                                }`}>{status}</Badge>
                        </div>

                        <div className="w-full space-y-2 text-left text-sm">
                            <div className="flex items-center gap-2">
                                <Phone className="w-4 h-4 text-muted-foreground" /> {phone}
                            </div>
                            <div className="flex items-center gap-2">
                                <Mail className="w-4 h-4 text-muted-foreground" /> {email}
                            </div>
                            <div className="flex items-center gap-2">
                                <Calendar className="w-4 h-4 text-muted-foreground" />
                                Applied {new Date(application.createdAt).toLocaleDateString()}
                            </div>
                        </div>

                        <div className="mt-6 w-full space-y-2">
                            {resumeUrl && (
                                <Button className="w-full" variant="outline" onClick={() => window.open(resumeUrl, '_blank')}>
                                    <Download className="mr-2 h-4 w-4" /> Resume
                                </Button>
                            )}
                            <Button className="w-full">
                                <Mail className="mr-2 h-4 w-4" /> Send Email
                            </Button>
                            <Button className="w-full" variant="secondary" onClick={() => router.push(`/employer/schedule-interview?appId=${application.id}`)}>
                                <Calendar className="mr-2 h-4 w-4" /> Schedule Interview
                            </Button>
                        </div>
                    </CardContent>
                </Card>

                {/* Main Content */}
                <div className="md:col-span-2 space-y-6">
                    {/* ATS Score Card */}
                    <Card className="glass-card overflow-hidden">
                        <CardHeader className="pb-2">
                            <CardTitle className="text-lg flex justify-between items-center">
                                <span className="flex items-center gap-2">
                                    <Zap className="h-5 w-5 text-primary" /> ATS Analysis
                                </span>
                                {score ? (
                                    <Badge variant={score >= 80 ? 'default' : 'secondary'} className={`text-base px-3 py-1 ${score >= 80 ? 'bg-green-600' : score >= 60 ? 'bg-amber-500' : 'bg-red-500'}`}>
                                        {score}% Match
                                    </Badge>
                                ) : (
                                    <Button size="sm" onClick={handleScore}>
                                        <Zap className="mr-1 h-3 w-3" /> Calculate Score
                                    </Button>
                                )}
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            {score && (
                                <div className="mb-3">
                                    <div className="h-3 bg-muted rounded-full overflow-hidden">
                                        <div
                                            className={`h-full rounded-full transition-all duration-1000 ${score >= 80 ? 'bg-green-500' : score >= 60 ? 'bg-amber-500' : 'bg-red-500'}`}
                                            style={{ width: `${score}%` }}
                                        />
                                    </div>
                                </div>
                            )}
                            <p className="text-sm text-muted-foreground flex items-center gap-2">
                                {score && score >= 80 ? (
                                    <><CheckCircle2 className="h-4 w-4 text-green-500" /> Strong match! Recommended for interview.</>
                                ) : score && score >= 60 ? (
                                    <><AlertTriangle className="h-4 w-4 text-amber-500" /> Good match. Review experience details.</>
                                ) : score ? (
                                    <><XCircle className="h-4 w-4 text-red-500" /> Low match. Check resume manually.</>
                                ) : (
                                    <>Click calculate to run AI-powered analysis.</>
                                )}
                            </p>
                        </CardContent>
                    </Card>

                    <Tabs defaultValue="details">
                        <TabsList className="w-full grid grid-cols-4">
                            <TabsTrigger value="details">Details</TabsTrigger>
                            <TabsTrigger value="notes">Notes ({notes.length})</TabsTrigger>
                            <TabsTrigger value="resume">Resume</TabsTrigger>
                            <TabsTrigger value="history">History</TabsTrigger>
                        </TabsList>

                        <TabsContent value="details" className="space-y-4">
                            <Card className="glass-card">
                                <CardHeader>
                                    <CardTitle className="text-base">Cover Letter</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <div className="bg-muted/50 p-4 rounded-lg text-sm whitespace-pre-wrap leading-relaxed">
                                        {coverLetter || "No cover letter provided."}
                                    </div>
                                </CardContent>
                            </Card>

                            {/* Job info */}
                            {application.job && (
                                <Card className="glass-card">
                                    <CardHeader>
                                        <CardTitle className="text-base flex items-center gap-2">
                                            <BookOpen className="h-4 w-4" /> Applied For
                                        </CardTitle>
                                    </CardHeader>
                                    <CardContent>
                                        <h3 className="font-semibold text-lg">{application.job.title}</h3>
                                        {application.job.skills && (
                                            <div className="flex flex-wrap gap-1.5 mt-2">
                                                {application.job.skills.split(',').map((s, i) => (
                                                    <Badge key={i} variant="outline" className="text-[10px]">{s.trim()}</Badge>
                                                ))}
                                            </div>
                                        )}
                                    </CardContent>
                                </Card>
                            )}
                        </TabsContent>

                        {/* Notes Tab */}
                        <TabsContent value="notes" className="space-y-4">
                            {/* Add Note */}
                            <Card className="glass-card">
                                <CardHeader className="pb-3">
                                    <CardTitle className="text-base flex items-center gap-2">
                                        <MessageSquare className="h-4 w-4" /> Add Note
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-3">
                                    <Textarea
                                        placeholder="Add your assessment, observations, or reminders about this candidate..."
                                        value={noteContent}
                                        onChange={(e) => setNoteContent(e.target.value)}
                                        rows={3}
                                    />
                                    <div className="flex items-center gap-3">
                                        <div className="flex-1">
                                            <Input
                                                placeholder="Tags (comma-separated): e.g. strong-communicator, culture-fit"
                                                value={noteTags}
                                                onChange={(e) => setNoteTags(e.target.value)}
                                                className="text-sm"
                                            />
                                        </div>
                                        <Button onClick={handleAddNote} disabled={submittingNote || !noteContent.trim()}>
                                            {submittingNote ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>

                            {/* Existing Notes */}
                            {notes.length === 0 ? (
                                <Card className="glass-card">
                                    <CardContent className="py-8 text-center text-muted-foreground">
                                        <MessageSquare className="h-10 w-10 mx-auto mb-2 opacity-30" />
                                        <p>No notes yet. Add your first note above.</p>
                                    </CardContent>
                                </Card>
                            ) : (
                                <div className="space-y-3">
                                    {notes.slice().reverse().map((note, i) => (
                                        <Card key={i} className="glass-card">
                                            <CardContent className="py-4">
                                                <p className="text-sm mb-2">{note.content}</p>
                                                <div className="flex items-center justify-between">
                                                    <div className="flex flex-wrap gap-1">
                                                        {(note.tags || []).map((tag, ti) => (
                                                            <Badge key={ti} variant="outline" className="text-[10px] gap-1">
                                                                <Tag className="h-2.5 w-2.5" /> {tag}
                                                            </Badge>
                                                        ))}
                                                    </div>
                                                    <span className="text-[10px] text-muted-foreground">
                                                        {new Date(note.timestamp).toLocaleString()}
                                                    </span>
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}
                                </div>
                            )}
                        </TabsContent>

                        <TabsContent value="resume">
                            <Card className="glass-card">
                                <CardContent className="p-0 h-[500px]">
                                    {resumeUrl ? (
                                        <iframe src={resumeUrl} className="w-full h-full rounded-md" title="Candidate resume" />
                                    ) : (
                                        <div className="flex items-center justify-center h-full text-muted-foreground">
                                            <div className="text-center">
                                                <Download className="h-10 w-10 mx-auto mb-2 opacity-30" />
                                                No Resume Uploaded
                                            </div>
                                        </div>
                                    )}
                                </CardContent>
                            </Card>
                        </TabsContent>

                        <TabsContent value="history">
                            <Card className="glass-card">
                                <CardContent className="pt-6">
                                    <div className="space-y-4">
                                        {(application?.statusHistory || []).map((entry, i: number) => (
                                            <div key={i} className="flex gap-4">
                                                <div className="flex flex-col items-center">
                                                    <div className={`w-3 h-3 rounded-full ${getStatusColor(entry.status || '')} mt-1.5`} />
                                                    {i < ((application?.statusHistory?.length || 0) - 1) && <div className="w-0.5 flex-1 bg-border" />}
                                                </div>
                                                <div className="pb-4">
                                                    <div className="flex items-center gap-2">
                                                        <p className="font-semibold text-sm">
                                                            {entry.type === 'NOTE' ? '📝 Note Added' :
                                                                entry.type === 'RATING' ? `⭐ Rated ${entry.rating}/5` :
                                                                    entry.status}
                                                        </p>
                                                    </div>
                                                    <p className="text-xs text-muted-foreground mt-1">
                                                        {new Date(entry.timestamp).toLocaleString()}
                                                    </p>
                                                    {(entry.notes || entry.content) && (
                                                        <p className="text-sm text-muted-foreground mt-1 bg-muted/50 px-3 py-1.5 rounded-lg">
                                                            {entry.notes || entry.content}
                                                        </p>
                                                    )}
                                                    {entry.tags && entry.tags.length > 0 && (
                                                        <div className="flex gap-1 mt-1.5">
                                                            {entry.tags.map((tag, ti) => (
                                                                <Badge key={ti} variant="outline" className="text-[9px] h-4">{tag}</Badge>
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </CardContent>
                            </Card>
                        </TabsContent>

                        {/* AI Interviews Tab */}
                        <TabsContent value="ai-interviews">
                            <Card className="glass-card">
                                <CardHeader>
                                    <CardTitle className="text-base flex items-center gap-2">
                                        <Zap className="h-4 w-4 text-amber-500" /> AI Interview Results
                                    </CardTitle>
                                    <CardDescription>
                                        Performance in practice interviews on TechWell.
                                    </CardDescription>
                                </CardHeader>
                                <CardContent>
                                    {!application?.applicant?.id ? (
                                        <div className="text-center py-12 text-muted-foreground">
                                            <p>This is an external candidate. AI Interview history is not available.</p>
                                        </div>
                                    ) : (
                                        <AIInterviewList userId={application.applicant.id} />
                                    )}
                                </CardContent>
                            </Card>
                        </TabsContent>
                    </Tabs>

                    {/* Quick Actions */}
                    <Card className="glass-card">
                        <CardHeader className="pb-3">
                            <CardTitle className="text-base">Update Status</CardTitle>
                        </CardHeader>
                        <CardContent className="flex gap-2 flex-wrap">
                            <Button size="sm" variant="outline" onClick={() => handleStatusUpdate('SCREENED')}>Screen</Button>
                            <Button size="sm" variant="outline" onClick={() => handleStatusUpdate('SHORTLISTED')} className="border-purple-200 text-purple-700 hover:bg-purple-50">
                                Shortlist
                            </Button>
                            <Button size="sm" variant="outline" onClick={() => handleStatusUpdate('INTERVIEW_SCHEDULED')} className="border-blue-200 text-blue-700 hover:bg-blue-50">
                                Schedule Interview
                            </Button>
                            <Button size="sm" variant="outline" onClick={() => handleStatusUpdate('APPOINTED')} className="border-green-200 text-green-700 hover:bg-green-50">
                                <CheckCircle2 className="mr-1 h-3 w-3" /> Hire
                            </Button>
                            <Button size="sm" variant="outline" onClick={() => handleStatusUpdate('REJECTED')} className="border-red-200 text-red-700 hover:bg-red-50">
                                <XCircle className="mr-1 h-3 w-3" /> Reject
                            </Button>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { useParams, useRouter } from "next/navigation"
import api from "@/lib/api"
import { DragDropContext, Droppable, Draggable } from "@hello-pangea/dnd"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Loader2, Mail, Phone, Calendar, Star, MoreVertical, Download } from "lucide-react"

interface ColumnConfig {
    title: string
    color: string
}

const COLUMNS: Record<string, ColumnConfig> = {
    APPLIED: { title: "Applied", color: "bg-gray-100" },
    VIEWED: { title: "Viewed", color: "bg-blue-50" }, // Added Viewed
    SCREENED: { title: "Screened", color: "bg-indigo-50" },
    SHORTLISTED: { title: "Shortlisted", color: "bg-purple-50" },
    INTERVIEW_SCHEDULED: { title: "Interview", color: "bg-pink-50" },
    SELECTED: { title: "Selected", color: "bg-green-50" },
    APPOINTED: { title: "Hired", color: "bg-emerald-100 border-emerald-200" }, // Renamed Hired in UI
    REJECTED: { title: "Rejected", color: "bg-red-50" }
}

import type { DropResult } from "@hello-pangea/dnd"

export default function ATSPipelinePage() {
    const { id: jobId } = useParams()
    const router = useRouter()
    interface Job {
        id: string
        title: string
    }

    interface Application {
        id: string
        status: string
        source: string
        atsScore: number
        externalName?: string
        externalEmail?: string
        createdAt: string
        applicant?: {
            name: string
            email: string
            avatar?: string
        }
    }

    const [applications, setApplications] = useState<Application[]>([])
    const [job, setJob] = useState<Job | null>(null)
    const [isLoading, setIsLoading] = useState(true)

    useEffect(() => {
        fetchData()
    }, [jobId])

    const fetchData = async () => {
        try {
            const [jobRes, appsRes] = await Promise.all([
                api.get(`/jobs/${jobId}`),
                api.get(`/ats/applications/${jobId}`)
            ])
            setJob(jobRes.data)
            setApplications(appsRes.data)
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoading(false)
        }
    }

    const handleExport = async () => {
        try {
            const res = await api.get(`/ats/export/${jobId}`, { responseType: 'blob' })
            const url = window.URL.createObjectURL(new Blob([res.data]))
            const link = document.createElement('a')
            link.href = url
            link.setAttribute('download', `applicants-${jobId}.csv`)
            document.body.appendChild(link)
            link.click()
            link.remove()
        } catch (error) {
            console.error("Failed to export", error)
            alert("Failed to export data")
        }
    }

    const onDragEnd = async (result: DropResult) => {
        if (!result.destination) return

        const { draggableId, destination } = result
        const newStatus = destination.droppableId

        // Optimistic UI update
        const updatedApps = applications.map(app =>
            app.id === draggableId ? { ...app, status: newStatus } : app
        )
        setApplications(updatedApps)

        // API Call
        try {
            await api.patch(`/ats/status/${draggableId}`, { status: newStatus })
        } catch (error) {
            console.error("Failed to update status", error)
            fetchData() // Revert on error
        }
    }

    if (isLoading) return <div className="flex justify-center p-8"><Loader2 className="animate-spin" /></div>

    // Group apps by status
    const columns = Object.keys(COLUMNS).reduce((acc: Record<string, Application[]>, status) => {
        acc[status] = applications.filter(app => app.status === status)
        return acc
    }, {})

    return (
        <div className="container py-6 h-[calc(100vh-60px)] flex flex-col">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
                <div>
                    <h1 className="text-2xl font-bold">{job?.title} Pipeline</h1>
                    <div className="flex gap-2 text-sm text-muted-foreground mt-1">
                        <Badge variant="outline">{applications.length} Candidates</Badge>
                        <Badge variant="outline" className="bg-blue-50 text-blue-700">
                            {applications.filter(a => a.source === 'INTERNAL').length} Internal
                        </Badge>
                    </div>
                </div>
                <div className="flex flex-wrap gap-2">
                    <Button variant="outline" size="sm" onClick={() => handleExport()}>
                        <Download className="mr-2 h-4 w-4" /> Export
                    </Button>
                    <Button variant="ghost" size="sm" onClick={() => router.push(`/employer/jobs/edit/${jobId}`)}>Edit Job</Button>
                    <Button size="sm" onClick={() => router.push(`/employer/dashboard/ats/add-candidate`)}>Add Candidate</Button>
                </div>
            </div>

            <DragDropContext onDragEnd={onDragEnd}>
                <div className="flex-1 overflow-x-auto pb-4">
                    <div className="flex gap-4 min-w-[1200px] h-full">
                        {(Object.entries(COLUMNS) as [string, ColumnConfig][]).map(([status, config]) => (
                            <div key={status} className={`flex-1 min-w-[280px] rounded-lg p-3 flex flex-col ${config.color}`}>
                                <h3 className="font-semibold mb-3 flex justify-between items-center">
                                    {config.title}
                                    <Badge variant="secondary" className="bg-white/50">{columns[status]?.length || 0}</Badge>
                                </h3>

                                <Droppable droppableId={status}>
                                    {(provided) => (
                                        <div
                                            ref={provided.innerRef}
                                            {...provided.droppableProps}
                                            className="flex-1 overflow-y-auto space-y-3 min-h-[100px]"
                                        >
                                            {columns[status]?.map((app, index: number) => (
                                                <Draggable key={app.id} draggableId={app.id} index={index}>
                                                    {(provided) => (
                                                        <Card
                                                            ref={provided.innerRef}
                                                            {...provided.draggableProps}
                                                            {...provided.dragHandleProps}
                                                            className="shadow-sm hover:shadow-md cursor-grab active:cursor-grabbing border-none"
                                                            onClick={() => router.push(`/employer/dashboard/ats/candidate/${app.id}`)}
                                                        >
                                                            <CardContent className="p-3">
                                                                <div className="flex items-start justify-between mb-2">
                                                                    <div className="flex items-center gap-2">
                                                                        {app.source === 'INTERNAL' && (
                                                                            <Badge variant="default" className="bg-blue-600 text-[10px] h-5 px-1">TechWell</Badge>
                                                                        )}
                                                                        {app.atsScore > 0 && (
                                                                            <Badge variant="outline" className={`text-[10px] h-5 px-1 ${app.atsScore >= 80 ? 'text-green-600 border-green-200' : 'text-orange-500'}`}>
                                                                                {app.atsScore}% Match
                                                                            </Badge>
                                                                        )}
                                                                    </div>
                                                                </div>

                                                                <div className="flex items-center gap-3 mb-3">
                                                                    <Avatar className="h-8 w-8">
                                                                        <AvatarImage src={app.applicant?.avatar} />
                                                                        <AvatarFallback>{(app.applicant?.name || app.externalName || 'U')[0]}</AvatarFallback>
                                                                    </Avatar>
                                                                    <div>
                                                                        <p className="font-medium text-sm line-clamp-1">{app.applicant?.name || app.externalName}</p>
                                                                        <p className="text-xs text-muted-foreground line-clamp-1">{app.applicant?.email || app.externalEmail}</p>
                                                                    </div>
                                                                </div>

                                                                <div className="flex justify-between items-center mt-2 border-t pt-2">
                                                                    <div className="text-xs text-muted-foreground flex items-center gap-1">
                                                                        <Calendar className="w-3 h-3" />
                                                                        {new Date(app.createdAt).toLocaleDateString()}
                                                                    </div>
                                                                    <Button variant="ghost" size="icon" className="h-6 w-6">
                                                                        <MoreVertical className="w-3 h-3" />
                                                                    </Button>
                                                                </div>
                                                            </CardContent>
                                                        </Card>
                                                    )}
                                                </Draggable>
                                            ))}
                                            {provided.placeholder}
                                        </div>
                                    )}
                                </Droppable>
                            </div>
                        ))}
                    </div>
                </div>
            </DragDropContext>
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { useRouter, useSearchParams } from "next/navigation"
import api from "@/lib/api"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Calendar } from "@/components/ui/calendar"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { format } from "date-fns"
import { Calendar as CalendarIcon, Clock, Link as LinkIcon, User } from "lucide-react"
import { cn } from "@/lib/utils"

interface Application {
    applicant?: {
        name: string
    }
    externalName?: string
    job?: {
        title: string
    }
}

export default function ScheduleInterviewPage() {
    const router = useRouter()
    const searchParams = useSearchParams()
    const appId = searchParams.get('appId')

    const [application, setApplication] = useState<Application | null>(null)
    const [isLoading, setIsLoading] = useState(true)
    const [isSubmitting, setIsSubmitting] = useState(false)

    const [formData, setFormData] = useState({
        roundName: '',
        type: 'TECHNICAL',
        date: undefined as Date | undefined,
        time: '10:00',
        duration: '30',
        meetingLink: '',
        interviewerId: ''
    })

    useEffect(() => {
        if (appId) fetchApplication()
    }, [appId])

    const fetchApplication = async () => {
        try {
            const res = await api.get(`/ats/applications/detail/${appId}`)
            setApplication(res.data)
            // Default round name based on existing interviews count? 
            // For now simple default
            setFormData(prev => ({ ...prev, roundName: 'Technical Round 1' }))
        } catch (error) {
            console.error(error)
            alert("Failed to load application details")
        } finally {
            setIsLoading(false)
        }
    }

    const handleSubmit = async () => {
        if (!formData.date || !formData.time || !formData.roundName) {
            alert("Please fill all required fields")
            return
        }

        setIsSubmitting(true)
        try {
            // Combine Date and Time
            const scheduledAt = new Date(formData.date)
            const [hours, minutes] = formData.time.split(':')
            scheduledAt.setHours(parseInt(hours), parseInt(minutes))

            await api.post('/ats/interviews', {
                applicationId: appId,
                roundName: formData.roundName,
                type: formData.type,
                scheduledAt: scheduledAt.toISOString(),
                duration: formData.duration,
                meetingLink: formData.meetingLink
            })

            alert("Interview Scheduled Successfully!")
            router.push(`/employer/dashboard/ats/candidate/${appId}`)
        } catch {
            alert("Failed to schedule interview")
        } finally {
            setIsSubmitting(false)
        }
    }

    if (!appId) return <div className="p-8">Missing Application ID</div>
    if (isLoading) return <div className="p-8">Loading...</div>

    const candidateName = application?.applicant?.name || application?.externalName
    const jobTitle = application?.job?.title

    return (
        <div className="container py-8 max-w-2xl">
            <Card>
                <CardHeader>
                    <CardTitle>Schedule Interview</CardTitle>
                    <CardDescription>
                        For <strong>{candidateName}</strong> - {jobTitle}
                    </CardDescription>
                </CardHeader>
                <CardContent className="space-y-6">
                    <div className="space-y-2">
                        <Label>Round Name</Label>
                        <Input
                            value={formData.roundName}
                            onChange={e => setFormData({ ...formData, roundName: e.target.value })}
                            placeholder="e.g. Technical Round 1"
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label>Round Type</Label>
                            <Select
                                value={formData.type}
                                onValueChange={val => setFormData({ ...formData, type: val })}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="SCREENING">Screening</SelectItem>
                                    <SelectItem value="TECHNICAL">Technical</SelectItem>
                                    <SelectItem value="MANAGERIAL">Managerial</SelectItem>
                                    <SelectItem value="HR">HR</SelectItem>
                                    <SelectItem value="FINAL">Final</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label>Duration (Minutes)</Label>
                            <Select
                                value={formData.duration}
                                onValueChange={val => setFormData({ ...formData, duration: val })}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="15">15 mins</SelectItem>
                                    <SelectItem value="30">30 mins</SelectItem>
                                    <SelectItem value="45">45 mins</SelectItem>
                                    <SelectItem value="60">1 Hour</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2 flex flex-col">
                            <Label className="mb-2">Date</Label>
                            <Popover>
                                <PopoverTrigger asChild>
                                    <Button
                                        variant={"outline"}
                                        className={cn(
                                            "w-full justify-start text-left font-normal",
                                            !formData.date && "text-muted-foreground"
                                        )}
                                    >
                                        <CalendarIcon className="mr-2 h-4 w-4" />
                                        {formData.date ? format(formData.date, "PPP") : <span>Pick a date</span>}
                                    </Button>
                                </PopoverTrigger>
                                <PopoverContent className="w-auto p-0">
                                    <Calendar
                                        mode="single"
                                        selected={formData.date}
                                        onSelect={date => setFormData({ ...formData, date })}
                                        initialFocus
                                        disabled={(date) => date < new Date()}
                                    />
                                </PopoverContent>
                            </Popover>
                        </div>
                        <div className="space-y-2">
                            <Label>Time</Label>
                            <div className="relative">
                                <Clock className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                                <Input
                                    type="time"
                                    className="pl-9"
                                    value={formData.time}
                                    onChange={e => setFormData({ ...formData, time: e.target.value })}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label>Meeting Link (Google Meet / Zoom)</Label>
                        <div className="relative">
                            <LinkIcon className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                            <Input
                                className="pl-9"
                                placeholder="https://meet.google.com/..."
                                value={formData.meetingLink}
                                onChange={e => setFormData({ ...formData, meetingLink: e.target.value })}
                            />
                        </div>
                        <p className="text-xs text-muted-foreground">The candidate will receive this link via email.</p>
                    </div>

                    <div className="pt-4 flex justify-end gap-2">
                        <Button variant="outline" onClick={() => router.back()}>Cancel</Button>
                        <Button onClick={handleSubmit} disabled={isSubmitting}>
                            {isSubmitting ? 'Scheduling...' : 'Schedule Interview'}
                        </Button>
                    </div>
                </CardContent>
            </Card>
        </div>
    )
}

"use client"

import * as React from 'react'
import {
    FileCheck,
    Search,
    Filter,
    Loader2,
    User,
    BookOpen,
    Clock,
    CheckCircle2,
    XCircle,
    Eye,
    MessageSquare,
    Download
} from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Textarea } from '@/components/ui/textarea'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
    DialogFooter
} from '@/components/ui/dialog'
import {
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger
} from '@/components/ui/tabs'
import api from '@/lib/api'

interface Submission {
    id: string
    content: string | null
    fileUrl: string | null
    grade: number | null
    feedback: string | null
    status: string
    createdAt: string
    user: {
        id: string
        name: string
        email: string
        avatar: string | null
    }
    lesson: {
        id: string
        title: string
        module: {
            title: string
            course: {
                title: string
            }
        }
    }
}

export default function AssessmentsPage() {
    const [submissions, setSubmissions] = React.useState<Submission[]>([])
    const [loading, setLoading] = React.useState(true)
    const [searchQuery, setSearchQuery] = React.useState('')
    const [activeTab, setActiveTab] = React.useState('pending')

    const [selectedSubmission, setSelectedSubmission] = React.useState<Submission | null>(null)
    const [gradeValue, setGradeValue] = React.useState('')
    const [feedbackValue, setFeedbackValue] = React.useState('')
    const [grading, setGrading] = React.useState(false)

    React.useEffect(() => {
        fetchSubmissions()
    }, [])

    const fetchSubmissions = async () => {
        try {
            const res = await api.get('/trainer/assessments')
            setSubmissions(res.data || [])
        } catch (error) {
            console.error('Failed to fetch submissions:', error)
            // Fallback to empty for now
            setSubmissions([])
        } finally {
            setLoading(false)
        }
    }

    const handleGrade = async () => {
        if (!selectedSubmission || !gradeValue) return

        setGrading(true)
        try {
            await api.post('/trainer/assessments/grade', {
                submissionId: selectedSubmission.id,
                grade: parseInt(gradeValue),
                feedback: feedbackValue,
                status: 'GRADED'
            })
            setSelectedSubmission(null)
            setGradeValue('')
            setFeedbackValue('')
            fetchSubmissions()
        } catch (error) {
            console.error('Failed to grade submission:', error)
            alert('Failed to grade submission')
        } finally {
            setGrading(false)
        }
    }

    const filteredSubmissions = submissions.filter(s => {
        const matchesSearch =
            s.user.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.lesson.title.toLowerCase().includes(searchQuery.toLowerCase())

        if (activeTab === 'pending') return matchesSearch && s.status === 'PENDING'
        if (activeTab === 'graded') return matchesSearch && s.status === 'GRADED'
        return matchesSearch
    })

    const pendingCount = submissions.filter(s => s.status === 'PENDING').length
    const gradedCount = submissions.filter(s => s.status === 'GRADED').length

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'PENDING':
                return <Badge variant="secondary" className="bg-amber-100 text-amber-700">Pending Review</Badge>
            case 'GRADED':
                return <Badge className="bg-green-100 text-green-700">Graded</Badge>
            case 'REJECTED':
                return <Badge variant="destructive">Rejected</Badge>
            default:
                return <Badge variant="outline">{status}</Badge>
        }
    }

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header */}
            <div>
                <h1 className="text-2xl font-black text-slate-800">Assessment Center</h1>
                <p className="text-sm text-slate-500 mt-1">Review and grade student assignments</p>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-amber-100">
                            <Clock className="h-5 w-5 text-amber-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{pendingCount}</p>
                            <p className="text-xs text-slate-500 font-medium">Pending Review</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-green-100">
                            <CheckCircle2 className="h-5 w-5 text-green-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{gradedCount}</p>
                            <p className="text-xs text-slate-500 font-medium">Graded</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-primary/10">
                            <FileCheck className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{submissions.length}</p>
                            <p className="text-xs text-slate-500 font-medium">Total Submissions</p>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Tabs & Search */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <Tabs value={activeTab} onValueChange={setActiveTab}>
                    <TabsList>
                        <TabsTrigger value="pending">
                            Pending ({pendingCount})
                        </TabsTrigger>
                        <TabsTrigger value="graded">
                            Graded ({gradedCount})
                        </TabsTrigger>
                        <TabsTrigger value="all">All</TabsTrigger>
                    </TabsList>
                </Tabs>

                <div className="relative max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                    <Input
                        placeholder="Search by student or assignment..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="pl-10"
                    />
                </div>
            </div>

            {/* Submissions List */}
            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : filteredSubmissions.length === 0 ? (
                <Card className="border-dashed">
                    <CardContent className="flex flex-col items-center justify-center py-16">
                        <FileCheck className="h-16 w-16 text-slate-300 mb-4" />
                        <h3 className="text-lg font-bold text-slate-600">
                            {activeTab === 'pending' ? 'No pending submissions' : 'No submissions found'}
                        </h3>
                        <p className="text-sm text-slate-500 mt-1">
                            {activeTab === 'pending'
                                ? 'All caught up! No assignments waiting for review.'
                                : 'No submissions match your search criteria.'}
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-4">
                    {filteredSubmissions.map((submission) => (
                        <Card key={submission.id} className="border-none shadow-sm hover:shadow-md transition-all">
                            <CardContent className="p-6">
                                <div className="flex flex-col md:flex-row md:items-center gap-4">
                                    {/* Student Info */}
                                    <div className="flex items-center gap-3 min-w-[200px]">
                                        <div className="h-10 w-10 rounded-full bg-slate-200 flex items-center justify-center">
                                            {submission.user.avatar ? (
                                                <img src={submission.user.avatar} alt="" className="h-10 w-10 rounded-full object-cover" />
                                            ) : (
                                                <User className="h-5 w-5 text-slate-500" />
                                            )}
                                        </div>
                                        <div>
                                            <p className="font-bold text-slate-800">{submission.user.name}</p>
                                            <p className="text-xs text-slate-500">{submission.user.email}</p>
                                        </div>
                                    </div>

                                    {/* Assignment Info */}
                                    <div className="flex-1">
                                        <p className="font-medium text-slate-700">{submission.lesson.title}</p>
                                        <p className="text-xs text-slate-500 flex items-center gap-1">
                                            <BookOpen className="h-3 w-3" />
                                            {submission.lesson.module.course.title} • {submission.lesson.module.title}
                                        </p>
                                    </div>

                                    {/* Status & Grade */}
                                    <div className="flex items-center gap-4">
                                        {getStatusBadge(submission.status)}
                                        {submission.grade !== null && (
                                            <span className="text-lg font-bold text-primary">{submission.grade}%</span>
                                        )}
                                    </div>

                                    {/* Actions */}
                                    <div className="flex items-center gap-2">
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => {
                                                setSelectedSubmission(submission)
                                                setGradeValue(submission.grade?.toString() || '')
                                                setFeedbackValue(submission.feedback || '')
                                            }}
                                        >
                                            <Eye className="h-4 w-4 mr-1" />
                                            {submission.status === 'PENDING' ? 'Review' : 'View'}
                                        </Button>
                                        {submission.fileUrl && (
                                            <Button variant="ghost" size="icon" asChild>
                                                <a href={submission.fileUrl} target="_blank" rel="noopener noreferrer" title="Download attachment">
                                                    <Download className="h-4 w-4" />
                                                </a>
                                            </Button>
                                        )}
                                    </div>
                                </div>

                                {/* Submitted Date */}
                                <div className="mt-4 pt-4 border-t flex items-center justify-between text-xs text-slate-500">
                                    <span>Submitted {new Date(submission.createdAt).toLocaleString()}</span>
                                    {submission.feedback && (
                                        <span className="flex items-center gap-1">
                                            <MessageSquare className="h-3 w-3" />
                                            Feedback provided
                                        </span>
                                    )}
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}

            {/* Grade Dialog */}
            <Dialog open={!!selectedSubmission} onOpenChange={() => setSelectedSubmission(null)}>
                <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle>Review Submission</DialogTitle>
                        <DialogDescription>
                            {selectedSubmission?.lesson.title} - {selectedSubmission?.user.name}
                        </DialogDescription>
                    </DialogHeader>

                    {selectedSubmission && (
                        <div className="space-y-6 py-4">
                            {/* Submission Content */}
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Submission Content</label>
                                <div className="p-4 bg-slate-50 rounded-lg border min-h-[100px]">
                                    {selectedSubmission.content ? (
                                        <p className="text-sm whitespace-pre-wrap">{selectedSubmission.content}</p>
                                    ) : (
                                        <p className="text-sm text-slate-500 italic">No text content submitted</p>
                                    )}
                                </div>
                                {selectedSubmission.fileUrl && (
                                    <Button variant="outline" size="sm" asChild className="mt-2">
                                        <a href={selectedSubmission.fileUrl} target="_blank" rel="noopener noreferrer">
                                            <Download className="h-4 w-4 mr-2" />
                                            Download Attachment
                                        </a>
                                    </Button>
                                )}
                            </div>

                            {/* Grade Input */}
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Grade (0-100) *</label>
                                <Input
                                    type="number"
                                    min="0"
                                    max="100"
                                    placeholder="Enter grade..."
                                    value={gradeValue}
                                    onChange={(e) => setGradeValue(e.target.value)}
                                />
                            </div>

                            {/* Feedback */}
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Feedback</label>
                                <Textarea
                                    placeholder="Provide constructive feedback to the student..."
                                    value={feedbackValue}
                                    onChange={(e) => setFeedbackValue(e.target.value)}
                                    rows={4}
                                />
                            </div>
                        </div>
                    )}

                    <DialogFooter className="gap-2">
                        <Button variant="outline" onClick={() => setSelectedSubmission(null)}>
                            Cancel
                        </Button>
                        {selectedSubmission?.status === 'PENDING' && (
                            <Button
                                onClick={handleGrade}
                                disabled={grading || !gradeValue}
                            >
                                {grading && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                                Submit Grade
                            </Button>
                        )}
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import * as React from 'react'
import {
    Users,
    Search,
    Filter,
    Loader2,
    User,
    BookOpen,
    TrendingUp,
    TrendingDown,
    AlertTriangle,
    ArrowUpRight,
    BarChart3,
    Target,
    ChevronDown
} from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Progress } from '@/components/ui/progress'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription
} from '@/components/ui/dialog'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger
} from '@/components/ui/dropdown-menu'
import api from '@/lib/api'

interface Student {
    id: string
    name: string
    email: string
    avatar: string | null
    enrollments: {
        course: { id: string; title: string }
        progress: number
        completedAt: string | null
    }[]
}

interface Batch {
    id: string
    name: string
    course: { title: string }
}

interface StudentProgress {
    student: { name: string; email: string }
    course: { title: string }
    overallProgress: number
    modules: {
        title: string
        progress: number
        lessons: {
            title: string
            completed: boolean
            score: number | null
        }[]
    }[]
}

export default function InstructorStudentsPage() {
    const [students, setStudents] = React.useState<Student[]>([])
    const [batches, setBatches] = React.useState<Batch[]>([])
    const [loading, setLoading] = React.useState(true)
    const [searchQuery, setSearchQuery] = React.useState('')
    const [selectedBatch, setSelectedBatch] = React.useState<string>('')
    const [progressFilter, setProgressFilter] = React.useState<string>('all')

    const [selectedStudent, setSelectedStudent] = React.useState<Student | null>(null)
    const [selectedCourseId, setSelectedCourseId] = React.useState<string>('')
    const [studentProgress, setStudentProgress] = React.useState<StudentProgress | null>(null)
    const [loadingProgress, setLoadingProgress] = React.useState(false)

    React.useEffect(() => {
        fetchData()
    }, [selectedBatch])

    const fetchData = async () => {
        setLoading(true)
        try {
            const [studentsRes, batchesRes] = await Promise.all([
                api.get('/trainer/students', { params: { batchId: selectedBatch || undefined } }),
                api.get('/trainer/batches')
            ])
            setStudents(studentsRes.data || [])
            setBatches(batchesRes.data || [])
        } catch (error) {
            console.error('Failed to fetch data:', error)
        } finally {
            setLoading(false)
        }
    }

    const fetchStudentProgress = async (studentId: string, courseId: string) => {
        setLoadingProgress(true)
        try {
            const res = await api.get(`/trainer/students/${studentId}/progress`, {
                params: { courseId }
            })
            setStudentProgress(res.data)
        } catch (error) {
            console.error('Failed to fetch progress:', error)
            setStudentProgress(null)
        } finally {
            setLoadingProgress(false)
        }
    }

    const handleViewProgress = (student: Student, courseId: string) => {
        setSelectedStudent(student)
        setSelectedCourseId(courseId)
        fetchStudentProgress(student.id, courseId)
    }

    const getProgressColor = (progress: number) => {
        if (progress >= 80) return 'text-green-600 bg-green-100'
        if (progress >= 50) return 'text-amber-600 bg-amber-100'
        return 'text-red-600 bg-red-100'
    }

    const getProgressIcon = (progress: number) => {
        if (progress >= 80) return TrendingUp
        if (progress >= 50) return Target
        return TrendingDown
    }

    const filteredStudents = students.filter(s => {
        const matchesSearch = s.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            s.email.toLowerCase().includes(searchQuery.toLowerCase())

        if (progressFilter === 'all') return matchesSearch

        const avgProgress = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)

        if (progressFilter === 'at-risk') return matchesSearch && avgProgress < 30
        if (progressFilter === 'on-track') return matchesSearch && avgProgress >= 30 && avgProgress < 80
        if (progressFilter === 'top') return matchesSearch && avgProgress >= 80

        return matchesSearch
    })

    const atRiskCount = students.filter(s => {
        const avg = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)
        return avg < 30
    }).length

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header */}
            <div>
                <h1 className="text-2xl font-black text-slate-800">Student Progress</h1>
                <p className="text-sm text-slate-500 mt-1">Monitor and track student performance across your courses</p>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card className="border-none shadow-sm">
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-primary/10">
                            <Users className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">{students.length}</p>
                            <p className="text-xs text-slate-500 font-medium">Total Students</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm cursor-pointer hover:shadow-md transition-all"
                    onClick={() => setProgressFilter('top')}>
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-green-100">
                            <TrendingUp className="h-5 w-5 text-green-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">
                                {students.filter(s => {
                                    const avg = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)
                                    return avg >= 80
                                }).length}
                            </p>
                            <p className="text-xs text-slate-500 font-medium">Top Performers</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm cursor-pointer hover:shadow-md transition-all"
                    onClick={() => setProgressFilter('on-track')}>
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-amber-100">
                            <Target className="h-5 w-5 text-amber-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold">
                                {students.filter(s => {
                                    const avg = s.enrollments.reduce((acc, e) => acc + e.progress, 0) / (s.enrollments.length || 1)
                                    return avg >= 30 && avg < 80
                                }).length}
                            </p>
                            <p className="text-xs text-slate-500 font-medium">On Track</p>
                        </div>
                    </CardContent>
                </Card>
                <Card className="border-none shadow-sm cursor-pointer hover:shadow-md transition-all border-red-200"
                    onClick={() => setProgressFilter('at-risk')}>
                    <CardContent className="p-4 flex items-center gap-4">
                        <div className="p-3 rounded-xl bg-red-100">
                            <AlertTriangle className="h-5 w-5 text-red-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-red-600">{atRiskCount}</p>
                            <p className="text-xs text-slate-500 font-medium">At Risk</p>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Filters */}
            <div className="flex flex-col md:flex-row md:items-center gap-4">
                <div className="relative flex-1 max-w-md">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                    <Input
                        placeholder="Search students..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="pl-10"
                    />
                </div>

                <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                        <Button variant="outline" className="gap-2">
                            <Filter className="h-4 w-4" />
                            {selectedBatch ? batches.find(b => b.id === selectedBatch)?.name : 'All Batches'}
                            <ChevronDown className="h-4 w-4" />
                        </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent>
                        <DropdownMenuItem onClick={() => setSelectedBatch('')}>All Batches</DropdownMenuItem>
                        {batches.map(batch => (
                            <DropdownMenuItem key={batch.id} onClick={() => setSelectedBatch(batch.id)}>
                                {batch.name}
                            </DropdownMenuItem>
                        ))}
                    </DropdownMenuContent>
                </DropdownMenu>

                {progressFilter !== 'all' && (
                    <Button variant="ghost" size="sm" onClick={() => setProgressFilter('all')}>
                        Clear filter
                    </Button>
                )}
            </div>

            {/* Students List */}
            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : filteredStudents.length === 0 ? (
                <Card className="border-dashed">
                    <CardContent className="flex flex-col items-center justify-center py-16">
                        <Users className="h-16 w-16 text-slate-300 mb-4" />
                        <h3 className="text-lg font-bold text-slate-600">No students found</h3>
                        <p className="text-sm text-slate-500 mt-1">
                            {searchQuery ? 'Try adjusting your search' : 'No students enrolled yet'}
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-4">
                    {filteredStudents.map((student) => {
                        const avgProgress = student.enrollments.reduce((acc, e) => acc + e.progress, 0) / (student.enrollments.length || 1)
                        const ProgressIcon = getProgressIcon(avgProgress)

                        return (
                            <Card key={student.id} className="border-none shadow-sm hover:shadow-md transition-all">
                                <CardContent className="p-6">
                                    <div className="flex flex-col md:flex-row md:items-center gap-4">
                                        {/* Student Info */}
                                        <div className="flex items-center gap-4 min-w-[250px]">
                                            <div className="h-12 w-12 rounded-full bg-slate-200 flex items-center justify-center">
                                                {student.avatar ? (
                                                    <img src={student.avatar} alt="" className="h-12 w-12 rounded-full object-cover" />
                                                ) : (
                                                    <User className="h-6 w-6 text-slate-500" />
                                                )}
                                            </div>
                                            <div>
                                                <p className="font-bold text-slate-800">{student.name}</p>
                                                <p className="text-xs text-slate-500">{student.email}</p>
                                            </div>
                                        </div>

                                        {/* Progress Overview */}
                                        <div className="flex-1">
                                            <div className="flex items-center gap-4 mb-2">
                                                <div className={`flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold ${getProgressColor(avgProgress)}`}>
                                                    <ProgressIcon className="h-3 w-3" />
                                                    {Math.round(avgProgress)}% avg
                                                </div>
                                                <span className="text-xs text-slate-500">
                                                    {student.enrollments.length} course{student.enrollments.length !== 1 ? 's' : ''}
                                                </span>
                                            </div>
                                            <Progress value={avgProgress} className="h-2" />
                                        </div>

                                        {/* Courses */}
                                        <div className="flex flex-wrap gap-2">
                                            {student.enrollments.slice(0, 2).map((enrollment) => (
                                                <Button
                                                    key={enrollment.course.id}
                                                    variant="outline"
                                                    size="sm"
                                                    className="text-xs"
                                                    onClick={() => handleViewProgress(student, enrollment.course.id)}
                                                >
                                                    <BookOpen className="h-3 w-3 mr-1" />
                                                    {enrollment.course.title.substring(0, 20)}...
                                                    <Badge variant="secondary" className="ml-2 text-[10px]">
                                                        {enrollment.progress}%
                                                    </Badge>
                                                </Button>
                                            ))}
                                            {student.enrollments.length > 2 && (
                                                <Badge variant="outline">+{student.enrollments.length - 2} more</Badge>
                                            )}
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        )
                    })}
                </div>
            )}

            {/* Progress Detail Dialog */}
            <Dialog open={!!selectedStudent && !!selectedCourseId} onOpenChange={() => {
                setSelectedStudent(null)
                setSelectedCourseId('')
                setStudentProgress(null)
            }}>
                <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle>Student Progress Details</DialogTitle>
                        <DialogDescription>
                            {selectedStudent?.name} - {studentProgress?.course.title || 'Loading...'}
                        </DialogDescription>
                    </DialogHeader>

                    {loadingProgress ? (
                        <div className="flex items-center justify-center py-12">
                            <Loader2 className="h-8 w-8 animate-spin text-primary" />
                        </div>
                    ) : studentProgress ? (
                        <div className="space-y-6 py-4">
                            {/* Overall Progress */}
                            <div className="p-4 bg-slate-50 rounded-xl">
                                <div className="flex items-center justify-between mb-2">
                                    <span className="font-medium">Overall Progress</span>
                                    <span className="text-lg font-bold text-primary">{studentProgress.overallProgress}%</span>
                                </div>
                                <Progress value={studentProgress.overallProgress} className="h-3" />
                            </div>

                            {/* Module-wise Progress */}
                            <div className="space-y-4">
                                <h3 className="font-bold text-slate-800">Module Breakdown</h3>
                                {studentProgress.modules.map((module, idx) => (
                                    <Card key={idx} className="border">
                                        <CardHeader className="py-3 px-4">
                                            <div className="flex items-center justify-between">
                                                <CardTitle className="text-sm">{module.title}</CardTitle>
                                                <Badge variant={module.progress === 100 ? "default" : "secondary"}>
                                                    {module.progress}%
                                                </Badge>
                                            </div>
                                        </CardHeader>
                                        <CardContent className="px-4 pb-4 pt-0">
                                            <div className="space-y-2">
                                                {module.lessons.map((lesson, lidx) => (
                                                    <div key={lidx} className="flex items-center justify-between text-sm py-1 border-b last:border-0">
                                                        <span className={lesson.completed ? 'text-slate-800' : 'text-slate-500'}>
                                                            {lesson.title}
                                                        </span>
                                                        <div className="flex items-center gap-2">
                                                            {lesson.score !== null && (
                                                                <Badge variant="outline" className="text-xs">
                                                                    Score: {lesson.score}%
                                                                </Badge>
                                                            )}
                                                            {lesson.completed ? (
                                                                <Badge className="bg-green-100 text-green-700 text-xs">Done</Badge>
                                                            ) : (
                                                                <Badge variant="secondary" className="text-xs">Pending</Badge>
                                                            )}
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </CardContent>
                                    </Card>
                                ))}
                            </div>
                        </div>
                    ) : (
                        <div className="text-center py-12 text-slate-500">
                            <p>Unable to load progress details</p>
                        </div>
                    )}
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useRouter, useParams } from 'next/navigation'
import { useAuth } from '@/lib/auth-context'
import { interviewApi } from '@/lib/api'
import { Button } from '@/components/ui/button'
import { Card, CardContent } from '@/components/ui/card'
import {
    Video,
    VideoOff,
    Mic,
    MicOff,
    Phone,
    ChevronRight,
    MessageSquare,
    Clock,
    User,
    Bot,
    Loader2,
    CheckCircle2,
    ArrowLeft,
    Send,
    Briefcase,
    AlertTriangle
} from 'lucide-react'
import { useToast } from '@/components/ui/use-toast'

// Speech Recognition Types
interface ISpeechRecognitionEvent extends Event {
    resultIndex: number
    results: {
        [key: number]: {
            [key: number]: {
                transcript: string
            }
            length: number
            isFinal: boolean
        }
        length: number
    }
}

interface ISpeechRecognitionErrorEvent extends Event {
    error: string
}

interface ISpeechRecognition extends EventTarget {
    continuous: boolean
    interimResults: boolean
    onresult: (event: ISpeechRecognitionEvent) => void
    onerror: (event: ISpeechRecognitionErrorEvent) => void
    onend: () => void
    start: () => void
    stop: () => void
}

declare global {
    interface Window {
        SpeechRecognition: new () => ISpeechRecognition
        webkitSpeechRecognition: new () => ISpeechRecognition
    }
}

interface Message {
    id: string
    role: 'interviewer' | 'user'
    content: string
    timestamp: Date
}

interface Question {
    id: string
    question: string
    type: string
    avatarRole: string // 'Technical', 'HR', etc.
}

interface AvatarConfig {
    name: string
    role: string
    color: string
    icon: React.ElementType
}

const AVATARS: Record<string, AvatarConfig> = {
    'tech-1': { name: "Alex Chen", role: "Technical Lead", color: "from-blue-500/20 to-cyan-500/20", icon: Bot },
    'tech-2': { name: "Sarah Johnson", role: "Senior Engineer", color: "from-indigo-500/20 to-blue-500/20", icon: Bot },
    'hr-1': { name: "Emma Williams", role: "HR Manager", color: "from-purple-500/20 to-pink-500/20", icon: Briefcase },
    'hr-2': { name: "David Smith", role: "Talent Acquisition", color: "from-slate-500/20 to-gray-500/20", icon: Briefcase },
    // Fallbacks
    'Technical': { name: "AI Interviewer", role: "Technical", color: "from-blue-500/20 to-cyan-500/20", icon: Bot },
    'HR': { name: "AI Recruiter", role: "HR", color: "from-purple-500/20 to-pink-500/20", icon: Briefcase }
}

// Success Overlay Component
function SuccessOverlay({ onRedirect }: { onRedirect: () => void }) {
    React.useEffect(() => {
        const timer = setTimeout(onRedirect, 3000);
        return () => clearTimeout(timer);
    }, [onRedirect]);

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/80 backdrop-blur-sm animate-in fade-in duration-500">
            <div className="text-center space-y-6 p-8 bg-card border rounded-2xl shadow-2xl max-w-md w-full animate-in zoom-in-50 duration-500 delay-150">
                <div className="mx-auto h-24 w-24 bg-green-100 rounded-full flex items-center justify-center mb-4">
                    <CheckCircle2 className="h-12 w-12 text-green-600 animate-in zoom-in duration-300 delay-300" />
                </div>
                <div className="space-y-2">
                    <h2 className="text-3xl font-bold tracking-tight">Interview Completed!</h2>
                    <p className="text-muted-foreground">Great job! We are generating your performance report now.</p>
                </div>
                <div className="flex justify-center gap-2">
                    <div className="h-2 w-2 bg-primary rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="h-2 w-2 bg-primary rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="h-2 w-2 bg-primary rounded-full animate-bounce"></div>
                </div>
            </div>
        </div>
    );
}

export default function InterviewRoomPage() {
    const router = useRouter()
    const params = useParams()
    const { isAuthenticated, isLoading: authLoading } = useAuth()
    const { toast } = useToast()

    const videoRef = React.useRef<HTMLVideoElement>(null)
    const [stream, setStream] = React.useState<MediaStream | null>(null)
    const [isVideoOn, setIsVideoOn] = React.useState(true)
    const [isMicOn, setIsMicOn] = React.useState(true)

    // AI State
    const [currentQuestion, setCurrentQuestion] = React.useState<Question | null>(null)
    const [questionCount, setQuestionCount] = React.useState(0)

    const [messages, setMessages] = React.useState<Message[]>([])
    const [userResponse, setUserResponse] = React.useState('')
    const [codeResponse, setCodeResponse] = React.useState('') // New: Code Editor State
    const [isThinking, setIsThinking] = React.useState(false)
    const [isAIProcessing, setIsAIProcessing] = React.useState(false)

    // 2026 Features: Real-time Analysis
    const [wpm, setWpm] = React.useState(0)
    const [fillerCount, setFillerCount] = React.useState(0)
    const [speechStartTime, setSpeechStartTime] = React.useState<number | null>(null)
    const [tabSwitchCount, setTabSwitchCount] = React.useState(0)
    const [isTabActive, setIsTabActive] = React.useState(true)

    // Anti-Cheat: Tab Visibility
    React.useEffect(() => {
        const handleVisibilityChange = () => {
            if (document.hidden) {
                setTabSwitchCount(prev => prev + 1)
                setIsTabActive(false)
                toast({
                    variant: "destructive",
                    title: "Warning: Tab Switch Detected",
                    description: "Please stay on this tab during the interview. This event has been logged."
                })
            } else {
                setIsTabActive(true)
            }
        }
        document.addEventListener("visibilitychange", handleVisibilityChange)
        return () => document.removeEventListener("visibilitychange", handleVisibilityChange)
    }, [toast])

    // Real-time Speech Logic
    const analyzeSpeech = React.useCallback((transcript: string) => {
        if (!speechStartTime) return

        const words = transcript.trim().split(/\s+/).length
        const durationMin = (Date.now() - speechStartTime) / 60000
        const currentWpm = durationMin > 0 ? Math.round(words / durationMin) : 0
        setWpm(currentWpm)

        const fillers = (transcript.match(/\b(um|uh|like|you know|sort of)\b/gi) || []).length
        setFillerCount(fillers)
    }, [speechStartTime])

    interface Interview {
        id: string
        role: string
        company?: string
        technology?: string
        difficulty?: string
        duration?: number
        panelCount?: number
        selectedAvatars?: string[]
    }

    const [interview, setInterview] = React.useState<Interview | null>(null)
    const [timeLeft, setTimeLeft] = React.useState(0) // Seconds
    const [isCompleted, setIsCompleted] = React.useState(false)

    const [showSuccess, setShowSuccess] = React.useState(false)

    React.useEffect(() => {
        if (!authLoading && !isAuthenticated) {
            router.push('/login')
        }
    }, [authLoading, isAuthenticated, router])

    // Load Interview & Init Timer
    React.useEffect(() => {
        const fetchInterview = async () => {
            try {
                const res = await interviewApi.getById(params.id as string)
                setInterview(res.data.interview)
                // Initialize timer (default 30 mins if missing)
                if (res.data.interview.duration) {
                    setTimeLeft(res.data.interview.duration * 60)
                } else {
                    setTimeLeft(30 * 60)
                }
            } catch (error) {
                console.error('Failed to fetch interview:', error)
            }
        }
        if (params.id) {
            fetchInterview()
        }
    }, [params.id])

    // Countdown Timer
    React.useEffect(() => {
        if (!isCompleted && timeLeft > 0) {
            const timer = setInterval(() => {
                setTimeLeft(prev => {
                    if (prev <= 1) {
                        clearInterval(timer)
                        handleEndInterview() // Auto-end
                        return 0
                    }
                    return prev - 1
                })
            }, 1000)
            return () => clearInterval(timer)
        }
    }, [isCompleted, timeLeft])

    // Initialize camera stream
    React.useEffect(() => {
        const initCamera = async () => {
            try {
                const mediaStream = await navigator.mediaDevices.getUserMedia({
                    video: true,
                    audio: true
                })
                setStream(mediaStream)
                if (videoRef.current) {
                    videoRef.current.srcObject = mediaStream
                }
            } catch (error) {
                console.error('Failed to access camera:', error)
                toast({
                    variant: "destructive",
                    title: "Hardware Access Error",
                    description: "Could not access camera/microphone. Please check permissions."
                })
                setIsMicOn(false)
                setIsVideoOn(false)
            }
        }
        initCamera()

        return () => {
            if (stream) {
                stream.getTracks().forEach(track => track.stop())
            }
        }
    }, [])

    // Sync Mic State with Stream
    React.useEffect(() => {
        if (stream) {
            stream.getAudioTracks().forEach(track => {
                track.enabled = isMicOn
            })
        }
    }, [isMicOn, stream])

    // Initial Question Fetch
    React.useEffect(() => {
        const startInterview = async () => {
            if (messages.length === 0 && !isCompleted && !currentQuestion) {
                await fetchNextQuestion();
            }
        }
        startInterview();
    }, [messages.length, isCompleted])

    const handleEndInterview = async () => {
        try {
            await interviewApi.complete(params.id as string, { score: Math.floor(Math.random() * 20) + 80 })
        } catch (error) {
            console.error('Failed to complete interview:', error)
        }
        if (stream) {
            stream.getTracks().forEach(track => track.stop())
        }
        setShowSuccess(true)
    }

    // Timer
    React.useEffect(() => {
        if (!isCompleted && timeLeft > 0) {
            const timer = setInterval(() => {
                setTimeLeft(prev => {
                    if (prev <= 1) {
                        clearInterval(timer)
                        handleEndInterview() // Auto-end
                        return 0
                    }
                    return prev - 1
                })
            }, 1000)
            return () => clearInterval(timer)
        }
    }, [isCompleted, timeLeft])

    const fetchNextQuestion = async () => {
        try {
            setIsAIProcessing(true);
            const res = await interviewApi.nextQuestion(params.id as string);

            if (res.data.completed) {
                setIsCompleted(true);
                setMessages(prev => [...prev, {
                    id: Date.now().toString(),
                    role: 'interviewer',
                    content: "Thank you! The interview is complete. Generating your feedback report...",
                    timestamp: new Date()
                }]);
                // Redirect to report after short delay
                setTimeout(() => router.push(`/interviews/${params.id}/report`), 3000);
                return;
            }

            const questionData = res.data.question;

            setCurrentQuestion({
                id: questionData.id || 'temp',
                question: questionData.question,
                type: questionData.type,
                avatarRole: questionData.avatarRole || (questionData.avatarId?.includes('hr') ? 'HR' : 'Technical')
            });

            setQuestionCount(prev => prev + 1);

            // Add to chat
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'interviewer',
                content: questionData.question,
                timestamp: new Date()
            }]);

            // Speak the question
            speakText(questionData.question);
        } catch (error) {
            console.error("Failed to fetch next question:", error);
            toast({
                variant: "destructive",
                title: "Connection Error",
                description: "Failed to load the next question. Please check your connection."
            });
        } finally {
            setIsAIProcessing(false);
        }
    }

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60)
        const secs = seconds % 60
        return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`
    }

    const [isWaitingNext, setIsWaitingNext] = React.useState(false)
    const [nextQuestionTimer, setNextQuestionTimer] = React.useState(10)
    const [isRecording, setIsRecording] = React.useState(false)
    const recognitionRef = React.useRef<ISpeechRecognition | null>(null)
    const speechTimeoutRef = React.useRef<NodeJS.Timeout | null>(null)

    // Handle Speech Recognition
    React.useEffect(() => {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition
        if (SpeechRecognition) {
            recognitionRef.current = new SpeechRecognition()
            if (recognitionRef.current) {
                recognitionRef.current.continuous = true
                recognitionRef.current.interimResults = true

                recognitionRef.current.onresult = (event: ISpeechRecognitionEvent) => {
                    let transcript = ''
                    for (let i = event.resultIndex; i < event.results.length; i++) {
                        transcript += event.results[i][0].transcript
                    }
                    setUserResponse(transcript)
                    analyzeSpeech(transcript)
                }



                recognitionRef.current.onerror = (event: ISpeechRecognitionErrorEvent) => {
                    console.error('Speech recognition error:', event.error)
                    setIsRecording(false)
                }

                recognitionRef.current.onend = () => {
                    setIsRecording(false)
                }
            }
        }
    }, [])

    const toggleRecording = () => {
        if (isRecording) {
            recognitionRef.current?.stop()
        } else {
            setUserResponse('')
            recognitionRef.current?.start()
            setIsRecording(true)
            setSpeechStartTime(Date.now())
            setWpm(0)
            setFillerCount(0)
        }
    }

    const speakText = (text: string) => {
        if (typeof window !== 'undefined' && window.speechSynthesis) {
            // Cancel any ongoing speech
            window.speechSynthesis.cancel()

            const utterance = new SpeechSynthesisUtterance(text)
            utterance.rate = 0.95
            utterance.pitch = 1

            // Get voices and find a good one (prefer female for HR, male for Tech maybe)
            const voices = window.speechSynthesis.getVoices()
            const preferredVoice = voices.find(v => v.name.includes('Google') || v.name.includes('Premium'))
            if (preferredVoice) utterance.voice = preferredVoice

            utterance.onend = () => {
                // Start 10s timeout after speaking is done
                startResponseTimer()
                // Auto-start recording
                toggleRecording()
                toast({
                    description: "Listening...",
                    duration: 2000,
                })
            }

            window.speechSynthesis.speak(utterance)
        }
    }

    const startResponseTimer = () => {
        setNextQuestionTimer(60) // Give user 60 seconds to answer
        if (speechTimeoutRef.current) clearInterval(speechTimeoutRef.current)

        speechTimeoutRef.current = setInterval(() => {
            setNextQuestionTimer(prev => {
                if (prev <= 1) {
                    if (speechTimeoutRef.current) clearInterval(speechTimeoutRef.current)
                    handleAutoSubmit()
                    return 0
                }
                return prev - 1
            })
        }, 1000)
    }

    const handleAutoSubmit = () => {
        if (isRecording) recognitionRef.current?.stop()
        handleSendResponse(true)
    }

    // Re-attach stream when video toggles back on
    React.useEffect(() => {
        if (isVideoOn && videoRef.current && stream) {
            videoRef.current.srcObject = stream
        }
    }, [isVideoOn, stream])

    // Gap Timer
    React.useEffect(() => {
        if (isWaitingNext) {
            if (nextQuestionTimer <= 0) {
                setIsWaitingNext(false)
                fetchNextQuestion()
                return
            }
            const timer = setInterval(() => {
                setNextQuestionTimer(prev => prev - 1)
            }, 1000)
            return () => clearInterval(timer)
        }
    }, [isWaitingNext, nextQuestionTimer])

    // ... existing initialization ...

    const handleSendResponse = async (isAuto = false) => {
        if (!currentQuestion) return
        if (!userResponse.trim() && !isAuto) return // Don't allow manual empty submit

        const finalResponse = userResponse.trim() || "(No verbal response recorded)";

        if ((!userResponse.trim() || userResponse.trim().length < 5) && isAuto) {
            toast({
                variant: "destructive",
                title: "No audio detected",
                description: "We couldn't hear your answer clearly. Please check your microphone.",
            })
            // Optional: Don't submit if silent? For now we submit "No verbal response" as per original logic but warn the user.
        }

        // Add user message if there was a response or if it's auto-submit
        const userMessage: Message = {
            id: Date.now().toString(),
            role: 'user',
            content: finalResponse,
            timestamp: new Date()
        }
        setMessages(prev => [...prev, userMessage])
        setUserResponse('')
        setIsThinking(true)

        // Clear auto-submit timer
        if (speechTimeoutRef.current) clearInterval(speechTimeoutRef.current)
        if (isRecording) recognitionRef.current?.stop()

        // Submit to AI
        try {
            await interviewApi.submitResponse(params.id as string, {
                questionId: currentQuestion.id,
                answer: finalResponse,
                code: currentQuestion.type === 'CODING' ? codeResponse : undefined
            });

            // Always wait for next question (backend decides if it's the last one)
            setNextQuestionTimer(5) // Short gap before next question
            setIsWaitingNext(true)

        } catch (error) {
            console.error("Error submitting response:", error);
            // Even on error, try to move forward
            if (isAuto) {
                setNextQuestionTimer(5)
                setIsWaitingNext(true)
            }
        } finally {
            setIsThinking(false);
        }
    }



    if (authLoading || !isAuthenticated) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    const getActiveAvatar = () => {
        // 1. If question has specific avatar role/id, use it
        if (currentQuestion?.avatarRole && AVATARS[currentQuestion.avatarRole]) {
            return AVATARS[currentQuestion.avatarRole]
        }
        // 2. Use interview selected avatar
        const primaryAvatarId = interview?.selectedAvatars?.[0]
        if (primaryAvatarId && AVATARS[primaryAvatarId]) {
            return AVATARS[primaryAvatarId]
        }
        // 3. Fallback
        return AVATARS['tech-1'] || AVATARS['Technical']
    }

    const activeAvatar = getActiveAvatar()

    const AvatarIcon = activeAvatar.icon;

    return (
        <div className="min-h-screen bg-background">
            {showSuccess && <SuccessOverlay onRedirect={() => router.push(`/interviews/${params.id}/report`)} />}

            {/* Header Bar */}
            <div className="h-14 bg-muted/50 border-b flex items-center justify-between px-4 backdrop-blur-md sticky top-0 z-20">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="sm" onClick={() => router.push('/interviews')}>
                        <ArrowLeft className="h-4 w-4 mr-2" />
                        Exit
                    </Button>
                    <div className="h-6 w-px bg-border" />
                    <div className="flex flex-col">
                        <div className="flex items-center gap-2 text-sm">
                            <Bot className="h-4 w-4 text-primary" />
                            <span className="font-bold">{interview?.role || 'Interview'}</span>
                            {interview?.technology && (
                                <span className="bg-primary/10 text-primary text-[10px] px-2 py-0.5 rounded-full">
                                    {interview.technology}
                                </span>
                            )}
                        </div>
                        <p className="text-[10px] text-muted-foreground uppercase tracking-wider font-semibold">
                            {interview?.company || 'Mock Interview'} • {interview?.difficulty} Level
                        </p>
                    </div>
                </div>
                <div className="flex items-center gap-6">
                    <div className="flex items-center gap-2 text-sm bg-background/50 px-3 py-1 rounded-full border">
                        <Clock className="h-4 w-4 text-primary" />
                        <span className="font-mono font-bold">{formatTime(timeLeft)}</span>
                    </div>
                    <div className="flex items-center gap-2 text-sm">
                        <span className="text-muted-foreground">Progress:</span>
                        <div className="flex gap-1">
                            {[1, 2, 3, 4, 5].map(step => (
                                <div
                                    key={step}
                                    className={`h-1.5 w-6 rounded-full ${step <= questionCount ? 'bg-primary' : 'bg-muted'}`}
                                />
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex h-[calc(100vh-3.5rem)] overflow-hidden">
                {/* Left Sidebar: Panel visualization */}
                <div className="w-64 border-r bg-muted/30 flex flex-col p-4 gap-4 hidden md:flex">
                    <div className="space-y-1">
                        <h3 className="text-xs font-bold text-muted-foreground uppercase tracking-widest pl-2">Interviewer Panel</h3>
                        <p className="text-[10px] text-muted-foreground pl-2">{interview?.panelCount || 1} Experts Conducting</p>
                    </div>

                    <div className="space-y-2">
                        {/* List only avatars selected for this panel */}
                        {Object.entries(AVATARS)
                            .filter(([id]) => interview?.selectedAvatars?.includes(id))
                            .map(([id, avatar]) => {
                                const isActive = activeAvatar?.name === avatar.name;
                                return (
                                    <div
                                        key={id}
                                        className={`flex items-center gap-3 p-3 rounded-xl transition-all duration-300 border-2 ${isActive
                                            ? 'bg-primary/10 border-primary shadow-lg shadow-primary/10 scale-105'
                                            : 'bg-white/5 border-transparent opacity-60 grayscale hover:grayscale-0 hover:opacity-100 hover:bg-white/10'
                                            }`}
                                    >
                                        <div className={`p-2 rounded-lg bg-gradient-to-br ${avatar.color}`}>
                                            <avatar.icon className={`h-5 w-5 ${isActive ? 'text-primary animate-pulse' : 'text-muted-foreground'}`} />
                                        </div>
                                        <div className="flex-1 min-w-0 text-left">
                                            <div className="flex items-center gap-1.5">
                                                <p className={`text-sm font-bold truncate ${isActive ? 'text-foreground' : 'text-muted-foreground'}`}>{avatar.name}</p>
                                                {isActive && <div className="h-1.5 w-1.5 rounded-full bg-primary animate-ping" />}
                                            </div>
                                            <p className="text-[10px] text-muted-foreground uppercase font-bold tracking-wider truncate">{avatar.role}</p>
                                        </div>
                                        {isActive && (
                                            <div className="px-2 py-0.5 rounded-full bg-primary/20 text-primary text-[8px] font-black uppercase tracking-tighter">
                                                Active
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                    </div>

                    <div className="mt-auto p-4 bg-primary/5 rounded-2xl border border-primary/10">
                        <div className="flex items-center gap-2 mb-2">
                            <CheckCircle2 className="h-4 w-4 text-primary" />
                            <span className="text-xs font-bold">Live Mentoring</span>
                        </div>
                        <p className="text-[10px] text-muted-foreground leading-relaxed">
                            Interviewer is analyzing your STAR method utilization and technical depth in real-time.
                        </p>
                    </div>
                </div>

                {/* Video Section */}
                <div className="flex-1 p-4 flex flex-col gap-4 bg-muted/10 relative">
                    {/* CODING MODE LAYOUT */}
                    {currentQuestion?.type === 'CODING' ? (
                        <div className="flex-1 flex gap-4 h-full min-h-0">
                            {/* Left Side: Question & Avatar (Compact) */}
                            <div className="w-1/3 flex flex-col gap-4">
                                <Card className="flex-1 relative overflow-hidden border-2 border-primary/20 shadow-xl flex flex-col">
                                    <CardContent className={`h-full flex flex-col items-center justify-center p-6 bg-gradient-to-br ${activeAvatar.color}`}>
                                        <div className="relative mb-6">
                                            <div className="h-24 w-24 rounded-full bg-background/50 backdrop-blur-md flex items-center justify-center shadow-2xl">
                                                <AvatarIcon className="h-12 w-12 text-primary" />
                                            </div>
                                            {isAIProcessing && (
                                                <div className="absolute -bottom-1 -right-1 h-6 w-6 bg-primary rounded-full flex items-center justify-center animate-bounce">
                                                    <div className="h-2 w-2 bg-primary-foreground rounded-full animate-ping" />
                                                </div>
                                            )}
                                        </div>
                                        <div className="text-center space-y-2 z-10">
                                            <h2 className="font-bold text-lg leading-tight">{currentQuestion.question}</h2>
                                            <p className="text-xs text-muted-foreground/80">Code your solution in the editor.</p>
                                        </div>
                                    </CardContent>
                                </Card>
                            </div>

                            {/* Right Side: Code Editor */}
                            <div className="flex-1 flex flex-col bg-[#1e1e1e] rounded-xl border border-border/50 shadow-2xl overflow-hidden">
                                <div className="bg-[#2d2d2d] px-4 py-2 flex items-center justify-between border-b border-white/10 text-xs text-gray-400 font-mono">
                                    <div className="flex items-center gap-2">
                                        <span className="text-blue-400">JS</span>
                                        <span>solution.js</span>
                                    </div>
                                    <span>Auto-save enabled</span>
                                </div>
                                <textarea
                                    value={codeResponse}
                                    onChange={(e) => setCodeResponse(e.target.value)}
                                    className="flex-1 w-full bg-[#1e1e1e] text-[#d4d4d4] p-4 font-mono text-sm resize-none focus:outline-none leading-relaxed"
                                    spellCheck={false}
                                    placeholder="// Write your solution here..."
                                />
                            </div>
                        </div>
                    ) : (
                        /* STANDARD MODE LAYOUT */
                        <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 h-full min-h-0">
                            {/* AI Interviewer - Dynamic Avatar */}
                            <Card className={`relative overflow-hidden border-2 transition-all duration-500 flex flex-col ${isAIProcessing ? 'border-primary/50' : 'border-transparent shadow-xl'}`}>
                                <CardContent className={`h-full flex items-center justify-center p-0 bg-gradient-to-br ${activeAvatar.color}`}>
                                    <div className="text-center">
                                        <div className="h-32 w-32 rounded-full bg-background/50 backdrop-blur-md flex items-center justify-center mx-auto mb-6 shadow-2xl animate-in zoom-in duration-500">
                                            {activeAvatar && <AvatarIcon className="h-16 w-16 text-primary" />}
                                        </div>
                                        <h2 className="font-bold text-2xl tracking-tight">{activeAvatar.name}</h2>
                                    </div>
                                </CardContent>
                            </Card>
                            {/* ... (rest of standard layout) */}


                            {/* User Video */}
                            <Card className="relative overflow-hidden bg-muted/50 border-transparent shadow-lg">
                                <CardContent className="h-full flex items-center justify-center p-0">
                                    {isVideoOn && stream ? (
                                        <video
                                            ref={videoRef}
                                            autoPlay
                                            muted
                                            playsInline
                                            className="w-full h-full object-cover scale-x-[-1]"
                                        />
                                    ) : (
                                        <div className="text-center p-8">
                                            <div className="h-28 w-28 rounded-full bg-muted/50 flex items-center justify-center mx-auto mb-4 border-2 border-dashed border-muted">
                                                {isVideoOn ? <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" /> : <VideoOff className="h-8 w-8 text-muted-foreground" />}
                                            </div>
                                            <p className="font-bold">You</p>
                                            <p className="text-xs text-muted-foreground">{isVideoOn ? 'Camera loading...' : 'Camera is disabled'}</p>
                                        </div>
                                    )}

                                    {/* AI Coach Widget */}
                                    {isRecording && (
                                        <div className="absolute top-4 left-4 flex flex-col gap-2">
                                            <div className="bg-black/60 backdrop-blur-md px-3 py-2 rounded-xl text-white text-xs border border-white/10 shadow-xl">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <div className={`h-2 w-2 rounded-full ${wpm > 160 ? 'bg-red-500' : wpm < 100 ? 'bg-yellow-500' : 'bg-green-500'}`} />
                                                    <span className="font-bold uppercase tracking-wider">Live Coach</span>
                                                </div>
                                                <div className="space-y-1">
                                                    <div className="flex justify-between gap-4">
                                                        <span className="text-white/70">Pace:</span>
                                                        <span className={`font-mono font-bold ${wpm > 160 || wpm < 100 ? 'text-yellow-400' : 'text-green-400'}`}>
                                                            {wpm} WPM
                                                        </span>
                                                    </div>
                                                    <div className="flex justify-between gap-4">
                                                        <span className="text-white/70">Fillers:</span>
                                                        <span className={`font-mono font-bold ${fillerCount > 3 ? 'text-red-400' : 'text-green-400'}`}>
                                                            {fillerCount}
                                                        </span>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {/* Anti-Cheat Warning */}
                                    {!isTabActive && (
                                        <div className="absolute inset-0 bg-red-950/90 backdrop-blur-sm z-50 flex items-center justify-center p-8 text-center animate-in fade-in">
                                            <div>
                                                <AlertTriangle className="h-12 w-12 text-red-500 mx-auto mb-4" />
                                                <h3 className="text-xl font-bold text-white mb-2">Tab Switch Detected!</h3>
                                                <p className="text-red-200 text-sm">
                                                    Please return to the interview tab immediately.<br />
                                                    This incident has been flagged.
                                                </p>
                                            </div>
                                        </div>
                                    )}

                                    <div className="absolute bottom-4 left-4 flex items-center gap-3 bg-black/60 backdrop-blur-md px-4 py-2 rounded-2xl text-white">
                                        {isMicOn ? (
                                            <div className="flex items-center gap-2">
                                                <div className="flex gap-0.5 items-end h-3">
                                                    <div className="w-0.5 h-1 bg-green-400 animate-bounce" style={{ animationDelay: '0ms' }} />
                                                    <div className="w-0.5 h-2 bg-green-400 animate-bounce" style={{ animationDelay: '100ms' }} />
                                                    <div className="w-0.5 h-3 bg-green-400 animate-bounce" style={{ animationDelay: '200ms' }} />
                                                </div>
                                                <span className="text-[10px] font-bold uppercase tracking-wider">Audio Active</span>
                                            </div>
                                        ) : (
                                            <div className="flex items-center gap-2">
                                                <MicOff className="h-3 w-3 text-red-400" />
                                                <span className="text-[10px] font-bold uppercase tracking-wider text-red-400">Microphone Muted</span>
                                            </div>
                                        )}
                                    </div>
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* Controls */}
                    <div className="bg-background/80 backdrop-blur-md p-4 rounded-3xl border shadow-xl flex items-center justify-center gap-6 max-w-md mx-auto w-full">
                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant={isMicOn ? "outline" : "destructive"}
                                size="icon"
                                className={`h-12 w-12 rounded-2xl transition-all ${isRecording ? 'ring-2 ring-primary ring-offset-2' : ''}`}
                                onClick={() => setIsMicOn(!isMicOn)}
                            >
                                {isMicOn ? <Mic className="h-5 w-5" /> : <MicOff className="h-5 w-5" />}
                            </Button>
                            <span className="text-[10px] font-bold text-muted-foreground uppercase">{isMicOn ? (isRecording ? 'Listening...' : 'Mic On') : 'Mic Muted'}</span>
                        </div>

                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant={isVideoOn ? "outline" : "destructive"}
                                size="icon"
                                className="h-12 w-12 rounded-2xl transition-all"
                                onClick={() => setIsVideoOn(!isVideoOn)}
                            >
                                {isVideoOn ? <Video className="h-5 w-5" /> : <VideoOff className="h-5 w-5" />}
                            </Button>
                            <span className="text-[10px] font-bold text-muted-foreground uppercase">{isVideoOn ? 'Stop Video' : 'Start Video'}</span>
                        </div>

                        <div className="h-10 w-px bg-border mx-2" />

                        <div className="flex flex-col items-center gap-1">
                            <Button
                                variant="destructive"
                                size="icon"
                                className="h-12 w-12 rounded-2xl shadow-lg shadow-red-500/20 hover:scale-110 active:scale-95 transition-all"
                                onClick={handleEndInterview}
                            >
                                <Phone className="h-5 w-5 rotate-[135deg]" />
                            </Button>
                            <span className="text-[10px] font-bold text-red-600 uppercase">End Session</span>
                        </div>
                    </div>
                </div>

                {/* Chat Section */}
                <div className="w-96 border-l flex flex-col bg-background/50 backdrop-blur-xl shrink-0">
                    <div className="p-4 border-b flex items-center justify-between">
                        <div className="flex items-center gap-2">
                            <div className="p-1.5 bg-primary/10 rounded-lg">
                                <MessageSquare className="h-4 w-4 text-primary" />
                            </div>
                            <h3 className="font-bold text-sm">Session Log</h3>
                        </div>
                        <div className="bg-muted px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-tighter">Live</div>
                    </div>

                    {/* Messages Container */}
                    <div className="flex-1 overflow-y-auto p-4 space-y-6">
                        {messages.length === 0 && (
                            <div className="h-full flex flex-col items-center justify-center text-center opacity-40 grayscale">
                                <Bot className="h-12 w-12 mb-2" />
                                <p className="text-xs font-medium">Interviewer is connecting...</p>
                            </div>
                        )}
                        {messages.map((msg) => (
                            <div
                                key={msg.id}
                                className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}
                            >
                                <div className={`max-w-[85%] rounded-2xl px-4 py-3 relative ${msg.role === 'user'
                                    ? 'bg-primary text-primary-foreground rounded-tr-none shadow-lg shadow-primary/10'
                                    : 'bg-muted/50 border rounded-tl-none'
                                    }`}>
                                    <p className="text-sm leading-relaxed">{msg.content}</p>
                                    <div className={`mt-2 flex items-center justify-between gap-4 ${msg.role === 'user' ? 'text-primary-foreground/60' : 'text-muted-foreground'}`}>
                                        <p className="text-[9px] font-bold uppercase tracking-wider">
                                            {msg.role === 'user' ? 'You' : activeAvatar?.name}
                                        </p>
                                        <p className="text-[9px] font-mono">
                                            {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        ))}
                        {(isThinking || isAIProcessing) && (
                            <div className="flex justify-start">
                                <div className="bg-muted/30 border rounded-2xl rounded-tl-none px-4 py-3">
                                    <div className="flex items-center gap-3">
                                        <div className="flex gap-1">
                                            <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce [animation-delay:-0.3s]" />
                                            <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce [animation-delay:-0.15s]" />
                                            <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce" />
                                        </div>
                                        <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">
                                            {activeAvatar?.name} is speaking
                                        </span>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Input Area */}
                    {
                        !isCompleted ? (
                            <div className="p-4 border-t space-y-3 bg-background">
                                <div className="relative">
                                    <textarea
                                        value={userResponse}
                                        onChange={(e) => setUserResponse(e.target.value)}
                                        placeholder="Click to type your response..."
                                        className="w-full min-h-[100px] p-4 text-sm rounded-2xl border bg-muted/20 resize-none focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all placeholder:text-muted-foreground/50 font-medium"
                                        disabled={isAIProcessing || isThinking}
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter' && !e.shiftKey) {
                                                e.preventDefault()
                                                handleSendResponse()
                                            }
                                        }}
                                    />
                                    <div className="absolute bottom-3 right-3 text-[9px] font-bold text-muted-foreground uppercase opacity-50">
                                        Press Enter ↵
                                    </div>
                                </div>
                                <Button
                                    className="w-full h-11 rounded-xl font-bold uppercase tracking-widest shadow-lg shadow-primary/20 transition-all hover:scale-[1.02] active:scale-[0.98]"
                                    onClick={() => handleSendResponse(false)}
                                    disabled={!userResponse.trim() || isThinking || isAIProcessing}
                                >
                                    <Send className="h-4 w-4 mr-2" />
                                    Submit Answer
                                </Button>
                            </div>
                        ) : (
                            <div className="p-6 border-t text-center bg-green-500/5 space-y-4">
                                <div className="h-12 w-12 bg-green-500/20 rounded-full flex items-center justify-center mx-auto">
                                    <CheckCircle2 className="h-6 w-6 text-green-600" />
                                </div>
                                <div className="space-y-1">
                                    <p className="font-bold text-lg">Interview Concluded</p>
                                    <p className="text-xs text-muted-foreground">Detailed feedback and scoring ready</p>
                                </div>
                                <Button
                                    className="w-full rounded-full h-11 bg-green-600 hover:bg-green-700 font-bold"
                                    onClick={handleEndInterview}
                                >
                                    Generate Full Report
                                    <ChevronRight className="h-4 w-4 ml-2" />
                                </Button>
                            </div>
                        )
                    }
                </div>
            </div>
        </div>
    )
}

"use client"

import * as React from 'react'
import { useState, useRef, useEffect } from 'react'
import { useRouter, useParams } from 'next/navigation'
import { useAuth } from '@/lib/auth-context'
import { interviewApi } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import {
    ArrowLeft,
    ArrowRight,
    Check,
    Camera,
    Mic,
    Monitor,
    Wifi,
    Volume2,
    AlertCircle,
    Loader2,
    Play,
    CheckCircle2,
    XCircle,
    Lightbulb
} from 'lucide-react'

interface CheckItem {
    id: string
    label: string
    icon: React.ElementType
    status: 'pending' | 'checking' | 'success' | 'error'
    message?: string
}

export default function InterviewStartPage() {
    const router = useRouter()
    const params = useParams()
    const { isAuthenticated, isLoading: authLoading } = useAuth()

    const videoRef = useRef<HTMLVideoElement>(null)
    const [stream, setStream] = useState<MediaStream | null>(null)
    const [audioLevel, setAudioLevel] = useState(0)
    const [isReady, setIsReady] = useState(false)
    interface Interview {
        id: string
        role: string
        title?: string
    }
    const [interview, setInterview] = useState<Interview | null>(null)

    const [checks, setChecks] = useState<CheckItem[]>([
        { id: 'camera', label: 'Camera Access', icon: Camera, status: 'pending' },
        { id: 'microphone', label: 'Microphone Access', icon: Mic, status: 'pending' },
        { id: 'browser', label: 'Browser Compatibility', icon: Monitor, status: 'pending' },
        { id: 'connection', label: 'Internet Connection', icon: Wifi, status: 'pending' },
    ])

    useEffect(() => {
        if (!authLoading && !isAuthenticated) {
            router.push('/login')
        }
    }, [authLoading, isAuthenticated, router])

    // Fetch interview details
    useEffect(() => {
        const fetchInterview = async () => {
            try {
                const res = await interviewApi.getById(params.id as string)
                setInterview(res.data.interview)
            } catch (error) {
                console.error('Failed to fetch interview:', error)
            }
        }
        if (params.id) {
            fetchInterview()
        }
    }, [params.id])

    function updateCheck(id: string, update: Partial<CheckItem>) {
        setChecks(prev => prev.map(check =>
            check.id === id ? { ...check, ...update } : check
        ))
    }

    const requestMediaPermissions = async () => {
        updateCheck('camera', { status: 'checking' })
        updateCheck('microphone', { status: 'checking' })

        try {
            const mediaStream = await navigator.mediaDevices.getUserMedia({
                video: true,
                audio: true
            })

            setStream(mediaStream)

            // Attach video to preview
            if (videoRef.current) {
                videoRef.current.srcObject = mediaStream
            }

            updateCheck('camera', { status: 'success', message: 'Camera connected' })
            updateCheck('microphone', { status: 'success', message: 'Microphone connected' })

            // Setup audio level monitoring
            const audioContext = new AudioContext()
            const analyser = audioContext.createAnalyser()
            const microphone = audioContext.createMediaStreamSource(mediaStream)
            microphone.connect(analyser)
            analyser.fftSize = 256

            const dataArray = new Uint8Array(analyser.frequencyBinCount)

            const updateAudioLevel = () => {
                analyser.getByteFrequencyData(dataArray)
                const average = dataArray.reduce((a, b) => a + b) / dataArray.length
                setAudioLevel(Math.round((average / 255) * 100))
                requestAnimationFrame(updateAudioLevel)
            }
            updateAudioLevel()

            setIsReady(true)
        } catch (error) {
            console.error('Media permission error:', error)
            const err = error as Error

            if (err.name === 'NotAllowedError') {
                updateCheck('camera', { status: 'error', message: 'Permission denied - Please allow access' })
                updateCheck('microphone', { status: 'error', message: 'Permission denied - Please allow access' })
            } else {
                updateCheck('camera', { status: 'error', message: 'Camera not found' })
                updateCheck('microphone', { status: 'error', message: 'Microphone not found' })
            }
        }
    }

    const runSystemChecks = async () => {
        // Check browser compatibility
        updateCheck('browser', { status: 'checking' })
        await new Promise(r => setTimeout(r, 500))
        const isCompatible = !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia)
        updateCheck('browser', {
            status: isCompatible ? 'success' : 'error',
            message: isCompatible ? 'Chrome/Edge/Firefox detected' : 'Browser not supported'
        })

        // Check internet connection
        updateCheck('connection', { status: 'checking' })
        await new Promise(r => setTimeout(r, 500))
        const isOnline = navigator.onLine
        updateCheck('connection', {
            status: isOnline ? 'success' : 'error',
            message: isOnline ? 'Connection stable' : 'No internet connection'
        })

        // Request camera and microphone
        await requestMediaPermissions()
    }

    // Run system checks on mount
    useEffect(() => {
        let mounted = true
        if (mounted) {
            // runSystemChecks is async but calls setState synchronously at start
            // Defer to avoid cascading render lint
            setTimeout(() => void runSystemChecks(), 0)
        }
        return () => {
            mounted = false
            // Cleanup stream on unmount
            if (stream) {
                stream.getTracks().forEach(track => track.stop())
            }
        }
    }, [])

    const handleStartInterview = async () => {
        try {
            await interviewApi.start(params.id as string)
            router.push(`/interviews/${params.id}`)
        } catch (error) {
            console.error('Failed to start interview:', error)
        }
    }

    const getStatusIcon = (status: CheckItem['status']) => {
        switch (status) {
            case 'pending': return <div className="h-5 w-5 rounded-full border-2 border-muted" />
            case 'checking': return <Loader2 className="h-5 w-5 animate-spin text-primary" />
            case 'success': return <CheckCircle2 className="h-5 w-5 text-green-500" />
            case 'error': return <XCircle className="h-5 w-5 text-red-500" />
        }
    }

    const allChecksPassed = checks.every(c => c.status === 'success')

    if (authLoading || !isAuthenticated) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-background to-muted/30 py-8">
            <div className="container max-w-4xl">
                {/* Header */}
                <div className="mb-8">
                    <Button variant="ghost" onClick={() => router.push('/interviews')} className="mb-4">
                        <ArrowLeft className="h-4 w-4 mr-2" />
                        Back to Interviews
                    </Button>
                    <h1 className="text-3xl font-bold">Pre-Interview Setup</h1>
                    <p className="text-muted-foreground">Let&apos;s make sure everything is ready for your interview</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Camera Preview */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Camera className="h-5 w-5" />
                                Camera Preview
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="aspect-video bg-muted rounded-lg overflow-hidden relative">
                                <video
                                    ref={videoRef}
                                    autoPlay
                                    muted
                                    playsInline
                                    className="w-full h-full object-cover scale-x-[-1]"
                                />
                                {!stream && (
                                    <div className="absolute inset-0 flex items-center justify-center">
                                        <div className="text-center text-muted-foreground">
                                            <Camera className="h-12 w-12 mx-auto mb-2 opacity-50" />
                                            <p>Camera loading...</p>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </CardContent>
                    </Card>

                    {/* System Checks */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Monitor className="h-5 w-5" />
                                System Check
                            </CardTitle>
                            <CardDescription>
                                We&apos;re checking your setup for the best interview experience
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {checks.map(check => (
                                <div key={check.id} className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
                                    <div className="flex items-center gap-3">
                                        <check.icon className="h-5 w-5 text-muted-foreground" />
                                        <div>
                                            <p className="font-medium text-sm">{check.label}</p>
                                            {check.message && (
                                                <p className={`text-xs ${check.status === 'error' ? 'text-red-500' : 'text-muted-foreground'}`}>
                                                    {check.message}
                                                </p>
                                            )}
                                        </div>
                                    </div>
                                    {getStatusIcon(check.status)}
                                </div>
                            ))}

                            {/* Audio Level Indicator */}
                            {stream && (
                                <div className="p-3 bg-muted/50 rounded-lg">
                                    <div className="flex items-center gap-3 mb-2">
                                        <Volume2 className="h-5 w-5 text-muted-foreground" />
                                        <span className="font-medium text-sm">Microphone Level</span>
                                    </div>
                                    <div className="h-2 bg-muted rounded-full overflow-hidden">
                                        <div
                                            className="h-full bg-gradient-to-r from-green-500 to-green-400 transition-all duration-100"
                                            style={{ width: `${audioLevel}%` }}
                                        />
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-1">
                                        Speak to test your microphone
                                    </p>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>

                {/* Interview Tips */}
                <Card className="mt-6">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Lightbulb className="h-5 w-5 text-yellow-500" />
                            Tips for a Great Interview
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="p-4 bg-muted/50 rounded-lg">
                                <h4 className="font-medium mb-1">🎯 Be Specific</h4>
                                <p className="text-sm text-muted-foreground">Use the STAR method for behavioral questions</p>
                            </div>
                            <div className="p-4 bg-muted/50 rounded-lg">
                                <h4 className="font-medium mb-1">🗣️ Think Aloud</h4>
                                <p className="text-sm text-muted-foreground">Explain your thought process for technical questions</p>
                            </div>
                            <div className="p-4 bg-muted/50 rounded-lg">
                                <h4 className="font-medium mb-1">⏱️ Pace Yourself</h4>
                                <p className="text-sm text-muted-foreground">Take your time - quality over speed</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Start Button */}
                <div className="mt-8 text-center">
                    {allChecksPassed ? (
                        <Button size="lg" onClick={handleStartInterview} className="px-8">
                            <Play className="h-5 w-5 mr-2" />
                            I&apos;m Ready - Start Interview
                        </Button>
                    ) : (
                        <div className="space-y-2">
                            <Button size="lg" disabled className="px-8">
                                <AlertCircle className="h-5 w-5 mr-2" />
                                Complete System Check First
                            </Button>
                            <p className="text-sm text-muted-foreground">
                                Please allow camera and microphone access to continue
                            </p>
                            <Button variant="outline" onClick={requestMediaPermissions}>
                                Retry Permissions
                            </Button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

