import * as React from 'react'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { interviewApi } from '@/lib/api'
import { useAuth } from '@/lib/auth-context'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import {
    Video,
    Calendar,
    Clock,
    CheckCircle2,
    XCircle,
    PlayCircle,
    Loader2,
    Plus,
    Sparkles,
    FileText,
    Upload,
    Bot,
    Briefcase,
    Check,
    ArrowRight
} from 'lucide-react'
import { NewInterviewDialog } from '@/components/interviews/NewInterviewDialog'


interface Interview {
    id: string
    domain: string
    role: string
    company?: string
    difficulty: string
    status: string
    scheduledAt: string
    score?: number
}

const DOMAINS = [
    { value: 'TECHNOLOGY', label: 'Technology / Software' },
    { value: 'DATA_SCIENCE', label: 'Data Science & AI' },
    { value: 'PRODUCT', label: 'Product Management' },
    { value: 'DESIGN', label: 'UI/UX Design' },
    { value: 'BUSINESS', label: 'Business / Consulting' },
    { value: 'FINANCE', label: 'Finance & Banking' },
]

const DIFFICULTIES = [
    { value: 'BEGINNER', label: 'Beginner', desc: 'For freshers, 0-2 years experience' },
    { value: 'INTERMEDIATE', label: 'Intermediate', desc: 'For mid-level, 2-5 years experience' },
