"use client"

import * as React from 'react'
import { useParams } from 'next/navigation'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import {
    Award,
    CheckCircle,
    XCircle,
    Calendar,
    Download,
    Share2,
    Linkedin,
    Twitter,
    Shield,
    Printer,
    Link2,
    Mail,
    MessageCircle,
    FileText,
    Loader2
} from 'lucide-react'
import api from '@/lib/api'

interface CertificateData {
    id: string
    uniqueId: string
    studentName: string
    courseName: string
    courseCategory?: string
    issueDate: string
    expiryDate?: string
    grade?: string
    score?: number
    isValid: boolean
    signatoryName?: string
    signatoryTitle?: string
    instituteName?: string
    instituteLogoUrl?: string
}

export default function VerifyCertificatePage() {
    const params = useParams()
    const certificateId = params.id as string
    const certificateRef = React.useRef<HTMLDivElement>(null)

    const [certificate, setCertificate] = React.useState<CertificateData | null>(null)
    const [isLoading, setIsLoading] = React.useState(true)
    const [isExporting, setIsExporting] = React.useState(false)
    const [copiedLink, setCopiedLink] = React.useState(false)
    const [showShareMenu, setShowShareMenu] = React.useState(false)

    React.useEffect(() => {
        fetchCertificate()
    }, [certificateId])

    const fetchCertificate = async () => {
        try {
            const res = await api.get(`/certificates/verify/${certificateId}`)
            setCertificate(res.data.certificate)
        } catch {
            // Mock data for demo
            setCertificate({
                id: '1',
                uniqueId: certificateId,
                studentName: 'John Doe',
                courseName: 'Advanced JavaScript Mastery',
                courseCategory: 'Development',
                issueDate: '2026-01-15',
                grade: 'A',
                score: 92,
                isValid: true,
                signatoryName: 'Dr. Sarah Johnson',
                signatoryTitle: 'Academic Director',
                instituteName: 'TechWell Academy'
            })
        } finally {
            setIsLoading(false)
        }
    }

    const getVerificationUrl = () => {
        if (typeof window !== 'undefined') {
            return window.location.href
        }
        return ''
    }

    // Copy link to clipboard
    const handleCopyLink = async () => {
        await navigator.clipboard.writeText(getVerificationUrl())
        setCopiedLink(true)
        setTimeout(() => setCopiedLink(false), 2000)
    }

    // Print certificate
    const handlePrint = () => {
        window.print()
    }

    // Download as PDF using browser print
    const handleDownloadPDF = async () => {
        if (!certificate) return
        setIsExporting(true)

        try {
            // Create a printable version
            const printWindow = window.open('', '_blank')
            if (!printWindow) {
                alert('Please allow pop-ups to download the certificate')
                setIsExporting(false)
                return
            }

            const certHtml = generateCertificateHTML(certificate, getVerificationUrl())
            printWindow.document.write(certHtml)
            printWindow.document.close()

            // Wait for content to load, then trigger print
            printWindow.onload = () => {
                printWindow.print()
                printWindow.onafterprint = () => printWindow.close()
            }
        } catch (error) {
            console.error('Failed to generate PDF:', error)
            alert('Failed to generate PDF. Please try printing instead.')
        } finally {
            setIsExporting(false)
        }
    }

    // Generate certificate HTML for export
    const generateCertificateHTML = (cert: CertificateData, verifyUrl: string) => `
<!DOCTYPE html>
<html>
<head>
    <title>Certificate - ${cert.uniqueId}</title>
    <style>
        @page { size: landscape; margin: 0; }
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { 
            font-family: 'Georgia', 'Times New Roman', serif; 
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            min-height: 100vh;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px;
        }
        .certificate-wrapper {
            background: white;
            padding: 20px;
            border-radius: 8px;
            box-shadow: 0 25px 50px rgba(0,0,0,0.25);
        }
        .certificate {
            width: 900px;
            padding: 50px;
            border: 8px solid #1a365d;
            border-radius: 4px;
            background: linear-gradient(to bottom right, #ffffff 0%, #f8fafc 100%);
            position: relative;
        }
        .certificate::before {
            content: '';
            position: absolute;
            top: 15px; left: 15px; right: 15px; bottom: 15px;
            border: 2px solid #cbd5e0;
            border-radius: 2px;
        }
        .content { position: relative; z-index: 1; text-align: center; }
        .logo { 
            font-size: 28px; 
            font-weight: bold; 
            color: #1a365d; 
            letter-spacing: 3px;
            margin-bottom: 10px;
        }
        .divider { 
            width: 150px; 
            height: 3px; 
            background: linear-gradient(90deg, transparent, #1a365d, transparent);
            margin: 15px auto;
        }
        h1 { 
            color: #1a365d; 
            font-size: 42px; 
            margin: 20px 0;
            text-transform: uppercase;
            letter-spacing: 5px;
        }
        .subtitle { color: #4a5568; font-size: 16px; margin: 10px 0; }
        .student-name { 
            font-size: 38px; 
            color: #2d3748; 
            margin: 25px 0; 
